import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'Admin',
  MANAGER = 'Manager',
  WAITER = 'Waiter',
  CASHIER = 'Cashier',
  STORE_KEEPER = 'Store Keeper'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  stock: number;
  image: string;
  minStock: number;
}

export interface OrderItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
}

export interface Order {
  id: string;
  items: OrderItem[];
  total: number;
  discount: number;
  paymentMethod: 'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card';
  timestamp: Date;
  staffId: string;
  customerName?: string;
}

export interface Expense {
  id: string;
  title: string;
  amount: number;
  category: string;
  date: string;
}

export interface StaffMember {
  id: string;
  name: string;
  role: UserRole;
  phone: string;
  joinDate: string;
  status: 'Active' | 'On Leave' | 'Inactive';
}

export type View = 'DASHBOARD' | 'POS' | 'INVENTORY' | 'STAFF' | 'REPORTS' | 'FINANCE' | 'SETTINGS';

