import { GoogleGenAI } from "@google/genai";

export const getBusinessInsights = async (salesData: any, inventoryData: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Maamulaha ganacsiga "Koob Coffee" waxaan u baahanahay talo ku saabsan ganacsiga.
    Halkan waa xogta iibka ee hadda: ${JSON.stringify(salesData)}
    Halkan waa xogta kaydka (inventory): ${JSON.stringify(inventoryData)}

    Fadlan i sii 3 dhibcood oo muhiim ah oo ku saabsan sida aan u horumarin karno iibka ama aan u badbaadin karno kharashka. 
    U soo qor af-Soomaali fudud oo ganacsi ku dheehan yahay.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Raalli ahow, hadda ma awoodo inaan bixiyo faallooyinka AI. Fadlan mar kale isku day.";
  }
};

import React from 'react';
import { View, UserRole } from '../types';

interface SidebarProps {
  currentView: View;
  setView: (view: View) => void;
  userRole: UserRole;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, setView, userRole }) => {
  const menuItems = [
    { id: 'DASHBOARD' as View, icon: 'fa-gauge', label: 'Dashboard', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'POS' as View, icon: 'fa-cash-register', label: 'POS (Iibka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER, UserRole.WAITER] },
    { id: 'INVENTORY' as View, icon: 'fa-boxes-stacked', label: 'Inventory (Kaydka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.STORE_KEEPER] },
    { id: 'STAFF' as View, icon: 'fa-users-gear', label: 'Staff (Shaqaalaha)', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'REPORTS' as View, icon: 'fa-chart-line', label: 'Reports', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'FINANCE' as View, icon: 'fa-money-bill-trend-up', label: 'Finance', roles: [UserRole.ADMIN, UserRole.MANAGER] },
  ];

  const allowedItems = menuItems.filter(item => item.roles.includes(userRole));

  return (
    <div className="w-64 bg-[#3d2b1f] text-white flex flex-col min-h-screen sticky top-0">
