          <img src="https://picsum.photos/seed/user/40" alt="Avatar" className="w-10 h-10 rounded-full" />
          <div className="overflow-hidden">
            <p className="text-sm font-semibold truncate">Cali Maxamed</p>
            <p className="text-xs text-gray-400 capitalize">{userRole}</p>
