import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { getBusinessInsights } from '../services/geminiService';
import { Product, Order } from '../types';

interface DashboardProps {
  products: Product[];
  orders: Order[];
}

const Dashboard: React.FC<DashboardProps> = ({ products, orders }) => {
  const [insights, setInsights] = useState<string | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Stats calculation
  const stats = useMemo(() => {
    const today = new Date();
    today.setHours(0,0,0,0);

    const todayOrders = orders.filter(o => new Date(o.timestamp) >= today);
    const dailyRevenue = todayOrders.reduce((sum, o) => sum + o.total, 0);
    const lowStockCount = products.filter(p => p.stock <= p.minStock).length;

    return {
      revenue: `$${dailyRevenue.toFixed(2)}`,
      orders: todayOrders.length,
      customers: todayOrders.length, // approximation
      lowStock: lowStockCount
    };
  }, [orders, products]);

  const salesByDay = useMemo(() => {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const data = days.map(d => ({ name: d, sales: 0 }));

    orders.forEach(o => {
      const dayIndex = new Date(o.timestamp).getDay();
      data[dayIndex].sales += o.total;
    });

    return data;
  }, [orders]);

  const fetchInsights = useCallback(async () => {
    setLoadingInsights(true);
    try {
      const res = await getBusinessInsights(salesByDay, { lowStockCount: stats.lowStock });
      setInsights(res || "AI insight not available.");
    } catch (err) {
      setInsights("Ma awoodo inaan hadda helo falanqaynta.");
    } finally {
      setLoadingInsights(false);
    }
  }, [salesByDay, stats.lowStock]);

  useEffect(() => {
    fetchInsights();
  }, [fetchInsights]);

  return (
    <div className="p-8 space-y-8 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-gray-800">Soo dhawoow, Ahmed!</h2>
          <p className="text-gray-500">Guud mar kooban oo ganacsiga Koob Coffee ah.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Daily Revenue" value={stats.revenue} icon="fa-dollar-sign" color="bg-green-100 text-green-600" trend="Today" />
        <StatCard title="Total Orders" value={stats.orders} icon="fa-receipt" color="bg-blue-100 text-blue-600" trend="Today" />
        <StatCard title="Customers" value={stats.customers} icon="fa-users" color="bg-purple-100 text-purple-600" trend="Today" />
        <StatCard title="Low Stock" value={stats.lowStock} icon="fa-triangle-exclamation" color="bg-orange-100 text-orange-600" trend="Action required" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold mb-6">Revenue Trends (Weekly)</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesByDay}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="sales" fill="#c6a07d" radius={[6, 6, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-[#3d2b1f] text-white p-6 rounded-2xl shadow-xl flex flex-col relative overflow-hidden">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
              <i className="fas fa-wand-magic-sparkles text-sm"></i>
            </div>
            <h3 className="text-lg font-bold">AI Business Insights</h3>
          </div>
          <div className="flex-1 space-y-4 text-gray-200">
            {loadingInsights ? (
              <div className="space-y-3 animate-pulse">
                <div className="h-4 bg-white/10 rounded w-3/4"></div>
                <div className="h-4 bg-white/10 rounded w-full"></div>
                <div className="h-4 bg-white/10 rounded w-5/6"></div>
              </div>
            ) : (
              <div className="prose prose-sm prose-invert whitespace-pre-wrap text-sm leading-relaxed">
                {insights}
              </div>
            )}
          </div>
          <button onClick={fetchInsights} disabled={loadingInsights} className="mt-6 w-full py-2 bg-[#c6a07d] hover:bg-[#b08d6c] disabled:opacity-50 text-white rounded-lg text-sm font-semibold transition-colors">
            {loadingInsights ? 'Analyzing...' : 'Refresh AI'}
          </button>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color, trend }: any) => (
