  MANAGER = 'Manager',
  WAITER = 'Waiter',
  CASHIER = 'Cashier',
  STORE_KEEPER = 'Store Keeper'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  stock: number;
  image: string;
  minStock: number;
}

export interface OrderItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
}

export interface Order {
  id: string;
  items: OrderItem[];
  total: number;
  discount: number;
  paymentMethod: 'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card';
  timestamp: Date;
  staffId: string;
  customerName?: string;
}

export interface Expense {
  id: string;
  title: string;
  amount: number;
  category: string;
  date: string;
}

export interface StaffMember {
  id: string;
  name: string;
  role: UserRole;
  phone: string;
  joinDate: string;
  status: 'Active' | 'On Leave' | 'Inactive';
  pin: string; // Added PIN for individual login
}

