import React, { useState } from 'react';
import { StaffMember } from '../types';

interface LoginProps {
  staffMembers: StaffMember[];
  onLogin: (staff: StaffMember) => void;
}

const Login: React.FC<LoginProps> = ({ staffMembers, onLogin }) => {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);

  const handleNumberClick = (num: string) => {
    if (pin.length < 4) {
      const newPin = pin + num;
      setPin(newPin);
      setError(false);

      if (newPin.length === 4) {
        setTimeout(() => {
          const matchedStaff = staffMembers.find(s => s.pin === newPin);
          if (matchedStaff) {
            onLogin(matchedStaff);
          } else {
            setError(true);
            setPin('');
          }
        }, 300);
      }
    }
  };

  const handleDelete = () => {
    setPin(pin.slice(0, -1));
    setError(false);
  };

  return (
    <div className="fixed inset-0 bg-[#3d2b1f] flex items-center justify-center z-[100]">
      <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
        <div className="absolute top-[-10%] left-[-5%] w-96 h-96 bg-[#c6a07d] rounded-full blur-3xl"></div>
        <div className="absolute bottom-[-10%] right-[-5%] w-96 h-96 bg-[#c6a07d] rounded-full blur-3xl"></div>
      </div>

      <div className="w-full max-w-md p-8 flex flex-col items-center relative z-10">
        <div className="w-20 h-20 bg-[#c6a07d] rounded-3xl flex items-center justify-center shadow-2xl mb-6 transform rotate-3">
          <i className="fas fa-coffee text-white text-4xl"></i>
        </div>

        <h1 className="text-3xl font-playfair font-bold text-[#f5ebe0] mb-2">Koob Coffee</h1>
        <p className="text-[#c6a07d] mb-12 font-medium tracking-widest uppercase text-xs">Staff Login</p>

        <div className="flex gap-4 mb-12">
          {[0, 1, 2, 3].map((i) => (
            <div
              key={i}
              className={`w-4 h-4 rounded-full border-2 transition-all duration-300 ${
                error ? 'border-red-500 bg-red-500 animate-bounce' : 
                pin.length > i ? 'bg-[#c6a07d] border-[#c6a07d] scale-125' : 'border-gray-500'
              }`}
            ></div>
          ))}
        </div>

        <div className="grid grid-cols-3 gap-6 w-full max-w-[320px]">
          {['1', '2', '3', '4', '5', '6', '7', '8', '9'].map((num) => (
            <button
              key={num}
              onClick={() => handleNumberClick(num)}
              className="w-20 h-20 rounded-full bg-white/5 border border-white/10 text-white text-2xl font-bold hover:bg-white/10 active:scale-90 transition-all flex items-center justify-center"
            >
              {num}
            </button>
          ))}
          <div className="w-20 h-20"></div>
          <button
            onClick={() => handleNumberClick('0')}
            className="w-20 h-20 rounded-full bg-white/5 border border-white/10 text-white text-2xl font-bold hover:bg-white/10 active:scale-90 transition-all flex items-center justify-center"
          >
            0
          </button>
          <button
            onClick={handleDelete}
            className="w-20 h-20 rounded-full bg-white/5 text-gray-400 text-xl hover:text-white active:scale-90 transition-all flex items-center justify-center"
          >
            <i className="fas fa-backspace"></i>
          </button>
        </div>

        {error && (
          <p className="mt-8 text-red-400 font-semibold animate-pulse text-sm">PIN-ka waa khalad. Isku day mar kale.</p>
        )}
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { StaffMember, UserRole } from '../types';

interface StaffProps {
  staff: StaffMember[];
  onAddStaff: (s: StaffMember) => void;
  onUpdateStaff: (s: StaffMember) => void;
  currentUser: StaffMember;
}

const Staff: React.FC<StaffProps> = ({ staff, onAddStaff, onUpdateStaff, currentUser }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    role: UserRole.WAITER,
    phone: '',
    status: 'Active' as 'Active' | 'On Leave' | 'Inactive',
    pin: '1234'
  });

  const isAdmin = currentUser.role === UserRole.ADMIN;

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newMember: StaffMember = {
      id: `S-${Date.now()}`,
      name: formData.name,
      role: formData.role,
      phone: formData.phone,
      joinDate: new Date().toISOString().split('T')[0],
      status: formData.status,
      pin: formData.pin
    };
    onAddStaff(newMember);
    setIsAdding(false);
    resetForm();
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingStaff) {
      onUpdateStaff({
        ...editingStaff,
        name: formData.name,
        role: formData.role,
        phone: formData.phone,
        status: formData.status,
        pin: formData.pin
      });
      setEditingStaff(null);
      resetForm();
    }
  };

  const resetForm = () => {
    setFormData({ name: '', role: UserRole.WAITER, phone: '', status: 'Active', pin: '1234' });
  };

  const startEdit = (member: StaffMember) => {
    setEditingStaff(member);
    setFormData({
      name: member.name,
      role: member.role,
      phone: member.phone,
      status: member.status,
      pin: member.pin
    });
  };

  return (
    <div className="p-8 space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Staff Management</h2>
          <p className="text-gray-500">Diiwaanka shaqaalaha iyo doorarkooda.</p>
        </div>
        {isAdmin && (
          <button onClick={() => setIsAdding(true)} className="px-4 py-2 bg-[#c6a07d] text-white rounded-lg hover:bg-[#b08d6c]">
            <i className="fas fa-user-plus mr-2"></i> Ku dar Shaqaale
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {staff.map(member => (
          <div key={member.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-all flex flex-col items-center text-center relative group">
            {isAdmin && (
              <button 
                onClick={() => startEdit(member)}
                className="absolute top-4 right-4 p-2 bg-gray-50 rounded-full text-gray-400 hover:text-[#c6a07d] opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <i className="fas fa-edit"></i>
              </button>
            )}

            <div className="relative mb-4">
              <img src={`https://i.pravatar.cc/150?u=${member.id}`} alt={member.name} className="w-24 h-24 rounded-full border-4 border-gray-50 shadow-sm" />
              <div className={`absolute bottom-0 right-0 w-6 h-6 rounded-full border-4 border-white ${member.status === 'Active' ? 'bg-green-500' : 'bg-orange-500'}`}></div>
            </div>

            <h3 className="text-lg font-bold text-gray-800">{member.name}</h3>
            <span className="text-xs font-semibold text-[#c6a07d] uppercase tracking-wider mb-3 px-3 py-1 bg-[#c6a07d]/10 rounded-full">
              {member.role}
            </span>

            <div className="w-full space-y-2 mb-2">
              <div className="flex justify-between text-sm text-gray-500">
                <span>Phone:</span>
                <span className="font-medium text-gray-700">{member.phone}</span>
              </div>
              <div className="flex justify-between text-sm text-gray-500">
                <span>PIN:</span>
                <span className="font-mono text-gray-700">****</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Add/Edit Modal */}
      {(isAdding || editingStaff) && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl p-8 animate-scaleIn">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold">{editingStaff ? 'Bedel Shaqaalaha' : 'Diiwaangeli Shaqaale'}</h3>
                <button onClick={() => { setIsAdding(false); setEditingStaff(null); resetForm(); }} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times"></i></button>
             </div>
             <form onSubmit={editingStaff ? handleEditSubmit : handleAddSubmit} className="space-y-4">
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Magaca</label>
                   <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Doorka (Role)</label>
                   <select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as UserRole})} className="w-full px-4 py-2 border rounded-xl">
                      {Object.values(UserRole).map(role => <option key={role} value={role}>{role}</option>)}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefoonka</label>
                   <input required value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Login PIN (4 Lambar)</label>
                   <input required maxLength={4} value={formData.pin} onChange={e => setFormData({...formData, pin: e.target.value})} className="w-full px-4 py-2 border rounded-xl font-mono" />
                </div>
                <button type="submit" className="w-full bg-[#c6a07d] text-white py-3 rounded-xl font-bold hover:bg-[#b08d6c]">
                   {editingStaff ? 'Cusboonaysii' : 'Keydi Shaqaalaha'}
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Staff;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import Inventory from './components/Inventory';
import Staff from './components/Staff';
import Finance from './components/Finance';
import Settings from './components/Settings';
import Login from './components/Login';
import { View, UserRole, Product, StaffMember, Order, Expense } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  // Persistence for data
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('koob_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [staff, setStaff] = useState<StaffMember[]>(() => {
    const saved = localStorage.getItem('koob_staff');
    return saved ? JSON.parse(saved) : INITIAL_STAFF;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('koob_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('koob_expenses');
    return saved ? JSON.parse(saved) : MOCK_EXPENSES;
  });

  // LocalStorage syncing
  useEffect(() => localStorage.setItem('koob_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('koob_staff', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('koob_orders', JSON.stringify(orders)), [orders]);
  useEffect(() => localStorage.setItem('koob_expenses', JSON.stringify(expenses)), [expenses]);

  // Handlers
  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const handleCompleteOrder = (order: Order) => {
    setOrders(prev => [order, ...prev]);
    setProducts(prev => prev.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) return { ...p, stock: p.stock - itemInOrder.quantity };
      return p;
    }));
  };

  const handleAddProduct = (newProduct: Product) => setProducts(prev => [newProduct, ...prev]);
  const handleAddStaff = (newMember: StaffMember) => setStaff(prev => [newMember, ...prev]);
  const handleUpdateStaff = (updatedMember: StaffMember) => {
    setStaff(prev => prev.map(s => s.id === updatedMember.id ? updatedMember : s));
    // If updating currently logged in user, refresh their context
    if (currentUser && currentUser.id === updatedMember.id) {
      setCurrentUser(updatedMember);
    }
  };
  const handleAddExpense = (newExpense: Expense) => setExpenses(prev => [newExpense, ...prev]);

  const renderView = () => {
    if (!currentUser) return null;

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} />;
      case 'POS': return <POS products={products} onCompleteOrder={handleCompleteOrder} />;
      case 'INVENTORY': return <Inventory products={products} onAddProduct={handleAddProduct} />;
      case 'STAFF': return <Staff staff={staff} onAddStaff={handleAddStaff} onUpdateStaff={handleUpdateStaff} currentUser={currentUser} />;
      case 'FINANCE': return <Finance orders={orders} expenses={expenses} onAddExpense={handleAddExpense} />;
      case 'SETTINGS': return (
        <div className="p-8">
           <h2 className="text-2xl font-bold mb-4">Settings</h2>
           <p className="text-gray-500">Global system configuration and API settings go here.</p>
        </div>
      );
      case 'REPORTS': 
        return (
          <div className="p-8">
            <h2 className="text-2xl font-bold mb-6">Order Reports</h2>
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
               <table className="w-full text-left">
                  <thead className="bg-gray-50 text-xs font-bold uppercase text-gray-500">
                    <tr>
                      <th className="px-6 py-4">ID</th>
                      <th className="px-6 py-4">Items</th>
                      <th className="px-6 py-4">Total</th>
                      <th className="px-6 py-4">Processed By</th>
                      <th className="px-6 py-4">Date</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {orders.map(o => {
                      const staffName = staff.find(s => s.id === o.staffId)?.name || 'Unknown';
                      return (
                        <tr key={o.id} className="hover:bg-gray-50">
                          <td className="px-6 py-4 font-mono text-xs">{o.id}</td>
                          <td className="px-6 py-4 text-sm">{o.items.map(i => `${i.quantity}x ${i.name}`).join(', ')}</td>
                          <td className="px-6 py-4 font-bold">${o.total.toFixed(2)}</td>
                          <td className="px-6 py-4 text-sm">{staffName}</td>
                          <td className="px-6 py-4 text-xs text-gray-400">{new Date(o.timestamp).toLocaleString()}</td>
                        </tr>
                      );
                    })}
                  </tbody>
               </table>
            </div>
          </div>
        );
      default: return <Dashboard products={products} orders={orders} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50">
      <Sidebar currentView={currentView} setView={setCurrentView} userRole={currentUser.role} currentUser={currentUser} />

      <main className="flex-1 overflow-y-auto">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">
                {currentView.replace('_', ' ')}
             </h2>
          </div>
          <div className="flex items-center gap-6">
            <button 
              onClick={handleLogout}
              className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2"
            >
              <i className="fas fa-sign-out-alt"></i> Logout
            </button>
            <div className="h-8 w-[1px] bg-gray-200"></div>
            <div className="flex items-center gap-2">
               <div className="text-right hidden sm:block">
                  <p className="text-sm font-bold text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] text-[#c6a07d] uppercase font-bold tracking-widest">{currentUser.role}</p>
               </div>
               <div className="w-10 h-10 bg-[#3d2b1f] rounded-xl flex items-center justify-center text-white shadow-lg">
                  <i className="fas fa-user-check"></i>
               </div>
            </div>
          </div>
        </header>

        {renderView()}
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scaleIn { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}} />
    </div>
  );
};

export default App;

import React from 'react';
import { View, UserRole, StaffMember } from '../types';

interface SidebarProps {
  currentView: View;
  setView: (view: View) => void;
  userRole: UserRole;
  currentUser: StaffMember;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, setView, userRole, currentUser }) => {
