    { id: 'DASHBOARD' as View, icon: 'fa-gauge', label: 'Dashboard', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'POS' as View, icon: 'fa-cash-register', label: 'POS (Iibka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER, UserRole.WAITER] },
    { id: 'INVENTORY' as View, icon: 'fa-boxes-stacked', label: 'Inventory (Kaydka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.STORE_KEEPER] },
    { id: 'STAFF' as View, icon: 'fa-users-gear', label: 'Staff (Shaqaalaha)', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'REPORTS' as View, icon: 'fa-chart-line', label: 'Reports', roles: [UserRole.ADMIN, UserRole.MANAGER] },
