  const allowedItems = menuItems.filter(item => item.roles.includes(userRole));

  return (
    <div className="w-64 bg-[#3d2b1f] text-white flex flex-col min-h-screen sticky top-0">
      <div className="p-6 flex items-center gap-3 border-b border-[#5a402e]">
        <div className="w-10 h-10 bg-[#c6a07d] rounded-full flex items-center justify-center shadow-inner">
          <i className="fas fa-coffee text-xl"></i>
        </div>
        <h1 className="text-xl font-playfair tracking-wide uppercase font-bold text-[#f5ebe0]">Koob Coffee</h1>
      </div>

      <nav className="flex-1 mt-6 px-4 space-y-1">
        {allowedItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setView(item.id)}
            className={`w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all duration-300 ${
              currentView === item.id 
                ? 'bg-[#c6a07d] text-white shadow-lg' 
                : 'text-gray-400 hover:bg-[#5a402e] hover:text-white'
            }`}
