import React, { useState, useMemo } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole } from '../types';
import { CATEGORIES } from '../constants';

interface POSProps {
  products: Product[];
  onCompleteOrder: (order: Order) => void;
  currentUser: StaffMember;
}

const POS: React.FC<POSProps> = ({ products, onCompleteOrder, currentUser }) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card'>('Cash');

  const isWaiter = currentUser.role === UserRole.WAITER;
  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);

  const filteredProducts = useMemo(() => {
    return products.filter(p => 
      (activeCategory === 'All' || p.category === activeCategory) &&
      p.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [activeCategory, search, products]);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) {
      alert("Waa ka dhammaatay (Out of stock)!");
      return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) {
          alert(`Ma hayno wax ka badan ${product.stock} oo ah ${product.name}`);
          return prev;
        }
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    const product = products.find(p => p.id === id);
    setCart(prev => prev.map(item => {
      if (item.productId === id) {
        const newQty = Math.max(0, item.quantity + delta);
        if (product && newQty > product.stock) {
           alert(`Kaliya ${product.stock} ayaa haray.`);
           return item;
        }
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const grandTotal = total;

  const handlePrintReceipt = () => {
    if (cart.length === 0) return;
    // Mocking print functionality
    alert(`Rasiidka waa la daabacayaa...\nTotal: $${grandTotal.toFixed(2)}\nItems: ${cart.length}`);
  };

  const handleCompleteSale = () => {
    if (!canProcessPayment) {
      alert("Kaliya Cashier-ka ayaa bixin kara biilka!");
      return;
    }

    const newOrder: Order = {
      id: `ORD-${Date.now()}`,
      items: [...cart],
      total: grandTotal,
      discount: 0,
      paymentMethod,
      timestamp: new Date(),
      staffId: currentUser.id,
    };

    onCompleteOrder(newOrder);
    setCart([]);
    setShowCheckout(false);
    alert("Iibka waa la dhammaystiray!");
  };

  return (
    <div className="flex h-[calc(100vh-2rem)] gap-6 p-4 overflow-hidden">
      <div className="flex-1 flex flex-col gap-6">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div className="relative w-72">
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" 
              placeholder="Raadi cabitaan ama cunto..." 
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-[#c6a07d] transition-all"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto pb-1 max-w-lg no-scrollbar">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`px-4 py-2 rounded-xl text-sm font-medium whitespace-nowrap transition-all ${
                  activeCategory === cat ? 'bg-[#c6a07d] text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-2 grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              disabled={product.stock <= 0}
              className={`bg-white p-3 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-all group relative overflow-hidden text-left ${product.stock <= 0 ? 'opacity-60 grayscale cursor-not-allowed' : ''}`}
            >
              <img src={product.image} alt={product.name} className="w-full h-32 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 truncate">{product.name}</h4>
              <p className="text-sm text-gray-500 mb-2">{product.category}</p>
              <div className="flex justify-between items-center mt-auto">
                <span className="text-[#c6a07d] font-bold">${product.price.toFixed(2)}</span>
                <span className={`text-xs px-2 py-1 rounded-md font-bold ${product.stock <= 0 ? 'bg-red-100 text-red-600' : 'bg-gray-100 text-gray-500'}`}>
                  {product.stock <= 0 ? 'Dhammaaday' : `Stock: ${product.stock}`}
                </span>
              </div>
              {product.stock > 0 && (
                <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <div className="w-8 h-8 bg-[#c6a07d] text-white rounded-full flex items-center justify-center shadow-lg">
                    <i className="fas fa-plus"></i>
                  </div>
                </div>
              )}
            </button>
          ))}
        </div>
      </div>

      <div className="w-96 bg-white rounded-3xl shadow-xl border border-gray-100 flex flex-col overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <div className="flex flex-col">
            <h3 className="text-xl font-bold">Dalabka Hadda</h3>
            <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{currentUser.name} ({currentUser.role})</span>
          </div>
          <button onClick={() => setCart([])} className="text-gray-400 hover:text-red-500 transition-colors">
            <i className="fas fa-trash-alt"></i>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-400 gap-4">
              <i className="fas fa-shopping-basket text-5xl"></i>
              <p>Dambiishu waa maran tahay</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.productId} className="flex items-center gap-4 bg-gray-50 p-3 rounded-2xl group">
                <div className="flex-1">
                  <h4 className="font-semibold text-gray-800">{item.name}</h4>
                  <p className="text-sm text-[#c6a07d] font-bold">${(item.price * item.quantity).toFixed(2)}</p>
                </div>
                <div className="flex items-center gap-3 bg-white px-3 py-1 rounded-xl shadow-sm border border-gray-100">
                  <button onClick={() => updateQuantity(item.productId, -1)} className="text-[#c6a07d] hover:text-[#b08d6c] font-bold">-</button>
                  <span className="font-bold text-sm min-w-[1rem] text-center">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.productId, 1)} className="text-[#c6a07d] hover:text-[#b08d6c] font-bold">+</button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-gray-50 space-y-4">
          <div className="flex justify-between items-center pt-3 border-t border-gray-200">
            <span className="text-xl font-bold">Total</span>
            <span className="text-2xl font-bold text-[#3d2b1f]">${grandTotal.toFixed(2)}</span>
          </div>

          <div className="flex flex-col gap-2">
            <button 
              disabled={cart.length === 0}
              onClick={handlePrintReceipt}
              className="w-full bg-white border-2 border-gray-200 hover:border-[#c6a07d] hover:text-[#c6a07d] text-gray-600 py-3 rounded-2xl font-bold text-sm shadow-sm transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <i className="fas fa-print"></i> Daabac Rasiidka
            </button>

            {canProcessPayment ? (
              <button 
                disabled={cart.length === 0}
                onClick={() => setShowCheckout(true)}
                className="w-full bg-[#c6a07d] disabled:bg-gray-300 disabled:cursor-not-allowed hover:bg-[#b08d6c] text-white py-4 rounded-2xl font-bold text-lg shadow-lg shadow-[#c6a07d]/30 transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                <i className="fas fa-wallet"></i> Bixi Biilka
              </button>
            ) : (
              <div className="w-full bg-gray-100 text-gray-400 py-4 rounded-2xl font-bold text-center text-sm flex items-center justify-center gap-2 cursor-not-allowed">
                <i className="fas fa-lock text-xs"></i> Kaliya Cashier
              </div>
            )}
          </div>
        </div>
      </div>

      {showCheckout && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-scaleIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-bold">Habka Lacag Bixinta</h3>
              <button onClick={() => setShowCheckout(false)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4 mb-8">
              {(['Cash', 'EVC Plus', 'E-Dahab', 'Card'] as const).map(method => (
                <button
                  key={method}
                  onClick={() => setPaymentMethod(method)}
                  className={`flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all ${
                    paymentMethod === method ? 'border-[#c6a07d] bg-[#c6a07d]/10' : 'border-gray-100 bg-gray-50'
                  }`}
                >
                  <i className={`fas ${method === 'Cash' ? 'fa-wallet' : method === 'Card' ? 'fa-credit-card' : 'fa-mobile-screen-button'} text-xl ${paymentMethod === method ? 'text-[#c6a07d]' : 'text-gray-400'}`}></i>
                  <span className={`text-sm font-semibold ${paymentMethod === method ? 'text-[#c6a07d]' : 'text-gray-600'}`}>{method}</span>
                </button>
              ))}
            </div>

            <button onClick={handleCompleteSale} className="w-full bg-[#3d2b1f] hover:bg-black text-white py-4 rounded-2xl font-bold text-lg transition-all shadow-xl">
              Dhammeystir Iibka (${grandTotal.toFixed(2)})
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

export enum UserRole {
  ADMIN = 'Admin',
  MANAGER = 'Manager',
  WAITER = 'Waiter',
  CASHIER = 'Cashier',
  STORE_KEEPER = 'Store Keeper'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  stock: number;
  image: string;
  minStock: number;
}

export interface OrderItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
}

export interface Order {
  id: string;
  items: OrderItem[];
  total: number;
  discount: number;
  paymentMethod: 'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card';
  timestamp: Date;
  staffId: string;
  customerName?: string;
}

export interface PendingOrder {
  id: string;
  items: OrderItem[];
  total: number;
  waiterId: string;
  waiterName: string;
  timestamp: Date;
  tableNumber?: string;
}

export interface Expense {
  id: string;
  title: string;
  amount: number;
  category: string;
  date: string;
}

export interface StaffMember {
  id: string;
  name: string;
  role: UserRole;
  phone: string;
  joinDate: string;
  status: 'Active' | 'On Leave' | 'Inactive';
  pin: string;
}

export type View = 'DASHBOARD' | 'POS' | 'INVENTORY' | 'STAFF' | 'REPORTS' | 'FINANCE' | 'SETTINGS';

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import Inventory from './components/Inventory';
import Staff from './components/Staff';
import Finance from './components/Finance';
import Settings from './components/Settings';
import Login from './components/Login';
import { View, UserRole, Product, StaffMember, Order, Expense, PendingOrder } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  // Persistence for data
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('koob_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [staff, setStaff] = useState<StaffMember[]>(() => {
    const saved = localStorage.getItem('koob_staff');
    return saved ? JSON.parse(saved) : INITIAL_STAFF;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('koob_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>(() => {
    const saved = localStorage.getItem('koob_pending_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('koob_expenses');
    return saved ? JSON.parse(saved) : MOCK_EXPENSES;
  });

  // LocalStorage syncing
  useEffect(() => localStorage.setItem('koob_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('koob_staff', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('koob_orders', JSON.stringify(orders)), [orders]);
  useEffect(() => localStorage.setItem('koob_pending_orders', JSON.stringify(pendingOrders)), [pendingOrders]);
  useEffect(() => localStorage.setItem('koob_expenses', JSON.stringify(expenses)), [expenses]);

  // Handlers
  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const handleCompleteOrder = (order: Order, pendingOrderId?: string) => {
    setOrders(prev => [order, ...prev]);
    // Deduct stock
    setProducts(prev => prev.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) return { ...p, stock: p.stock - itemInOrder.quantity };
      return p;
    }));
    // Remove from pending if applicable
    if (pendingOrderId) {
      setPendingOrders(prev => prev.filter(po => po.id !== pendingOrderId));
    }
  };

  const handleAddPendingOrder = (po: PendingOrder) => {
    setPendingOrders(prev => [po, ...prev]);
  };

  // Management Handlers
  const handleAddProduct = (newProduct: Product) => setProducts(prev => [newProduct, ...prev]);
  const handleUpdateProduct = (updated: Product) => setProducts(prev => prev.map(p => p.id === updated.id ? updated : p));
  const handleDeleteProduct = (id: string) => {
    if(confirm("Ma hubtaa inaad tirto alaabtan?")) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleAddStaff = (newMember: StaffMember) => setStaff(prev => [newMember, ...prev]);
  const handleUpdateStaff = (updatedMember: StaffMember) => {
    setStaff(prev => prev.map(s => s.id === updatedMember.id ? updatedMember : s));
    if (currentUser && currentUser.id === updatedMember.id) {
      setCurrentUser(updatedMember);
    }
  };
  const handleDeleteStaff = (id: string) => {
    if(id === currentUser?.id) {
      alert("Ma tiri kartid naftaada!");
      return;
    }
    if(confirm("Ma hubtaa inaad tirto shaqaalahan?")) {
      setStaff(prev => prev.filter(s => s.id !== id));
    }
  };

  const handleAddExpense = (newExpense: Expense) => setExpenses(prev => [newExpense, ...prev]);

  const renderView = () => {
    if (!currentUser) return null;

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} />;
      case 'POS': return (
        <POS 
          products={products} 
          onCompleteOrder={handleCompleteOrder} 
          onAddPendingOrder={handleAddPendingOrder}
          pendingOrders={pendingOrders}
          currentUser={currentUser} 
        />
      );
      case 'INVENTORY': return (
        <Inventory 
          products={products} 
          onAddProduct={handleAddProduct} 
          onUpdateProduct={handleUpdateProduct}
          onDeleteProduct={handleDeleteProduct}
          currentUser={currentUser}
        />
      );
      case 'STAFF': return (
        <Staff 
          staff={staff} 
          onAddStaff={handleAddStaff} 
          onUpdateStaff={handleUpdateStaff} 
          onDeleteStaff={handleDeleteStaff}
          currentUser={currentUser} 
        />
      );
      case 'FINANCE': return <Finance orders={orders} expenses={expenses} onAddExpense={handleAddExpense} />;
      case 'SETTINGS': return (
        <div className="p-8">
           <h2 className="text-2xl font-bold mb-4">Settings</h2>
           <p className="text-gray-500">System adjustments and backup settings.</p>
           <div className="mt-8 p-6 bg-white rounded-3xl border border-gray-100 max-w-md">
              <h3 className="font-bold mb-4">Database Tools</h3>
              <button 
                onClick={() => { localStorage.clear(); window.location.reload(); }}
                className="px-4 py-2 bg-red-100 text-red-600 rounded-xl text-sm font-bold hover:bg-red-200"
              >
                Reset System Data (Warning)
              </button>
           </div>
        </div>
      );
      case 'REPORTS': 
        return (
          <div className="p-8">
            <h2 className="text-2xl font-bold mb-6">Order Reports</h2>
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
               <table className="w-full text-left">
                  <thead className="bg-gray-50 text-xs font-bold uppercase text-gray-500">
                    <tr>
                      <th className="px-6 py-4">ID</th>
                      <th className="px-6 py-4">Items</th>
                      <th className="px-6 py-4">Total</th>
                      <th className="px-6 py-4">Processed By</th>
                      <th className="px-6 py-4">Date</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {orders.map(o => {
                      const staffName = staff.find(s => s.id === o.staffId)?.name || 'Unknown';
                      return (
                        <tr key={o.id} className="hover:bg-gray-50">
                          <td className="px-6 py-4 font-mono text-xs">{o.id}</td>
                          <td className="px-6 py-4 text-sm">{o.items.map(i => `${i.quantity}x ${i.name}`).join(', ')}</td>
                          <td className="px-6 py-4 font-bold">${o.total.toFixed(2)}</td>
                          <td className="px-6 py-4 text-sm">{staffName}</td>
                          <td className="px-6 py-4 text-xs text-gray-400">{new Date(o.timestamp).toLocaleString()}</td>
                        </tr>
                      );
                    })}
                  </tbody>
               </table>
            </div>
          </div>
        );
      default: return <Dashboard products={products} orders={orders} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50">
      <Sidebar currentView={currentView} setView={setCurrentView} userRole={currentUser.role} currentUser={currentUser} />

      <main className="flex-1 overflow-y-auto">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">
                {currentView.replace('_', ' ')}
             </h2>
          </div>
          <div className="flex items-center gap-6">
            <button 
              onClick={handleLogout}
              className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2"
            >
              <i className="fas fa-sign-out-alt"></i> Logout
            </button>
            <div className="h-8 w-[1px] bg-gray-200"></div>
            <div className="flex items-center gap-2">
               <div className="text-right hidden sm:block">
                  <p className="text-sm font-bold text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] text-[#c6a07d] uppercase font-bold tracking-widest">{currentUser.role}</p>
               </div>
               <div className="w-10 h-10 bg-[#3d2b1f] rounded-xl flex items-center justify-center text-white shadow-lg">
                  <i className="fas fa-user-check"></i>
               </div>
            </div>
          </div>
        </header>

        {renderView()}
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scaleIn { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole, PendingOrder } from '../types';
import { CATEGORIES } from '../constants';

interface POSProps {
  products: Product[];
  onCompleteOrder: (order: Order, pendingOrderId?: string) => void;
  onAddPendingOrder: (po: PendingOrder) => void;
  pendingOrders: PendingOrder[];
  currentUser: StaffMember;
}

const POS: React.FC<POSProps> = ({ products, onCompleteOrder, onAddPendingOrder, pendingOrders, currentUser }) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card'>('Cash');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);
  const isWaiterOnly = currentUser.role === UserRole.WAITER;

  const filteredProducts = useMemo(() => {
    return products.filter(p => 
      (activeCategory === 'All' || p.category === activeCategory) &&
      p.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [activeCategory, search, products]);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) {
      alert("Waa ka dhammaatay!");
      return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) {
          alert(`Kaliya ${product.stock} ayaa haray.`);
          return prev;
        }
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.productId === id) {
        const product = products.find(p => p.id === id);
        const newQty = Math.max(0, item.quantity + delta);
        if (product && newQty > product.stock) return item;
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const handleSendToCashier = () => {
    if (cart.length === 0) return;

    const po: PendingOrder = {
      id: `PEND-${Date.now()}`,
      items: [...cart],
      total: total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };

    onAddPendingOrder(po);
    setCart([]);
    alert("Dalabka waa loo diray Cashier-ka!");
  };

  const loadPendingOrder = (po: PendingOrder) => {
    setCart(po.items);
    setActivePendingId(po.id);
  };

  const handleCompleteSale = () => {
    const newOrder: Order = {
      id: `ORD-${Date.now()}`,
      items: [...cart],
      total: total,
      discount: 0,
      paymentMethod,
      timestamp: new Date(),
      staffId: currentUser.id,
    };

    onCompleteOrder(newOrder, activePendingId || undefined);
    setCart([]);
    setActivePendingId(null);
    setShowCheckout(false);
    alert("Iibka waa la dhammaystiray!");
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {/* Left Sidebar for Pending Orders (Cashier/Admin Only) */}
      {canProcessPayment && (
        <div className="w-72 bg-gray-50 border-r border-gray-200 flex flex-col">
          <div className="p-4 border-b bg-white">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <i className="fas fa-clock text-orange-400"></i> Dalabyada Sugaya
            </h3>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {pendingOrders.length === 0 ? (
              <div className="text-center py-10 text-gray-400">
                <i className="fas fa-inbox text-3xl mb-2 block"></i>
                <p className="text-xs">Ma jiraan dalabyo sugaya</p>
              </div>
            ) : (
              pendingOrders.map(po => (
                <button 
                  key={po.id}
                  onClick={() => loadPendingOrder(po)}
                  className={`w-full text-left p-4 rounded-2xl border transition-all ${
                    activePendingId === po.id ? 'bg-[#3d2b1f] border-[#3d2b1f] text-white shadow-lg' : 'bg-white border-gray-100 hover:border-[#c6a07d]'
                  }`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-[10px] font-bold uppercase tracking-widest opacity-60">#{po.id.slice(-4)}</span>
                    <span className="text-[10px] font-bold">{new Date(po.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                  </div>
                  <p className="font-bold truncate text-sm">{po.waiterName}</p>
                  <div className="flex justify-between items-center mt-2">
                    <span className="text-xs">{po.items.length} items</span>
                    <span className={`font-bold ${activePendingId === po.id ? 'text-[#c6a07d]' : 'text-[#3d2b1f]'}`}>${po.total.toFixed(2)}</span>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Main Product Selection Area */}
      <div className="flex-1 flex flex-col p-6 gap-6 overflow-hidden">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div className="relative w-72">
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" 
              placeholder="Raadi alaab..." 
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-[#c6a07d]"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-md">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`px-4 py-2 rounded-xl text-xs font-bold whitespace-nowrap transition-all ${
                  activeCategory === cat ? 'bg-[#c6a07d] text-white' : 'bg-gray-100 text-gray-600'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4 pr-2">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              disabled={product.stock <= 0}
              className={`bg-white p-3 rounded-2xl border border-gray-100 hover:shadow-md transition-all group relative text-left flex flex-col h-full ${product.stock <= 0 ? 'opacity-50 grayscale' : ''}`}
            >
              <img src={product.image} className="w-full h-24 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 text-sm truncate">{product.name}</h4>
              <p className="text-xs text-gray-500 mb-2">{product.category}</p>
              <div className="mt-auto flex justify-between items-center pt-2">
                <span className="text-[#c6a07d] font-bold text-sm">${product.price.toFixed(2)}</span>
                <span className="text-[10px] text-gray-400">Stock: {product.stock}</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Right Cart Summary */}
      <div className="w-96 bg-white border-l border-gray-100 flex flex-col shadow-2xl">
        <div className="p-6 border-b border-gray-100">
          <div className="flex justify-between items-center mb-1">
             <h3 className="text-xl font-bold">Dalabka Hadda</h3>
             <button onClick={() => { setCart([]); setActivePendingId(null); }} className="text-gray-400 hover:text-red-500"><i className="fas fa-trash-alt"></i></button>
          </div>
          <p className="text-[10px] font-bold text-[#c6a07d] uppercase tracking-widest">{currentUser.role} View</p>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-300">
              <i className="fas fa-shopping-basket text-4xl mb-4"></i>
              <p className="text-sm">Kudar alaab dambiisha</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-2xl">
                <div className="flex-1">
                  <h4 className="font-bold text-gray-800 text-sm truncate">{item.name}</h4>
                  <p className="text-xs text-[#c6a07d] font-bold">${(item.price * item.quantity).toFixed(2)}</p>
                </div>
                <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl border border-gray-100 shadow-sm">
                   <button onClick={() => updateQuantity(item.productId, -1)} className="w-6 h-6 flex items-center justify-center text-[#c6a07d] hover:bg-gray-50 rounded-lg">-</button>
                   <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                   <button onClick={() => updateQuantity(item.productId, 1)} className="w-6 h-6 flex items-center justify-center text-[#c6a07d] hover:bg-gray-50 rounded-lg">+</button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-gray-50 space-y-4">
          <div className="flex justify-between items-center pt-2 border-t border-gray-200">
            <span className="font-bold text-gray-500">Total</span>
            <span className="text-2xl font-bold text-[#3d2b1f]">${total.toFixed(2)}</span>
          </div>

          <div className="flex flex-col gap-2">
            {/* Waiter Primary Action */}
            <button 
              disabled={cart.length === 0}
              onClick={handleSendToCashier}
              className="w-full bg-white border-2 border-gray-200 hover:border-[#c6a07d] hover:text-[#c6a07d] text-gray-700 py-3 rounded-2xl font-bold text-sm transition-all flex items-center justify-center gap-2"
            >
              <i className="fas fa-print"></i> Diri & Daabac
            </button>

            {/* Cashier Primary Action */}
            {canProcessPayment ? (
              <button 
                disabled={cart.length === 0}
                onClick={() => setShowCheckout(true)}
                className="w-full bg-[#c6a07d] disabled:opacity-50 text-white py-4 rounded-2xl font-bold text-lg shadow-lg transition-all active:scale-95"
              >
                {activePendingId ? 'Bixi Biilka (Final)' : 'Iib Toos ah'}
              </button>
            ) : (
              <div className="text-center py-2 text-[10px] text-gray-400 font-bold uppercase tracking-wider">
                <i className="fas fa-lock mr-1"></i> Kaliya Cashier baa bixin kara
              </div>
            )}
          </div>
        </div>
      </div>

      {showCheckout && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 animate-scaleIn shadow-2xl">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold">Habka Lacag Bixinta</h3>
                <button onClick={() => setShowCheckout(false)} className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center"><i className="fas fa-times"></i></button>
              </div>

              <div className="grid grid-cols-2 gap-4 mb-8">
                 {(['Cash', 'EVC Plus', 'E-Dahab', 'Card'] as const).map(method => (
                   <button 
                    key={method}
                    onClick={() => setPaymentMethod(method)}
                    className={`flex flex-col items-center gap-2 p-4 rounded-3xl border-2 transition-all ${paymentMethod === method ? 'border-[#c6a07d] bg-[#c6a07d]/10' : 'bg-gray-50 border-gray-50'}`}
                   >
                     <i className={`fas ${method === 'Cash' ? 'fa-wallet' : method === 'Card' ? 'fa-credit-card' : 'fa-mobile-screen-button'} text-xl ${paymentMethod === method ? 'text-[#c6a07d]' : 'text-gray-400'}`}></i>
                     <span className="text-xs font-bold">{method}</span>
                   </button>
                 ))}
              </div>

              <button onClick={handleCompleteSale} className="w-full bg-[#3d2b1f] text-white py-5 rounded-3xl font-bold text-xl hover:bg-black transition-all shadow-xl">
                 Dhammaystir (${total.toFixed(2)})
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default POS;

