import React, { useState } from 'react';
import { Product, StaffMember, UserRole } from '../types';
import { CATEGORIES } from '../constants';

interface InventoryProps {
  products: Product[];
  onAddProduct: (p: Product) => void;
  onUpdateProduct: (p: Product) => void;
  onDeleteProduct: (id: string) => void;
  currentUser: StaffMember;
}

const Inventory: React.FC<InventoryProps> = ({ products, onAddProduct, onUpdateProduct, onDeleteProduct, currentUser }) => {
  const [search, setSearch] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    category: 'Coffee',
    price: '',
    stock: '',
    minStock: ''
  });

  const canManage = [UserRole.ADMIN, UserRole.MANAGER].includes(currentUser.role);
  const filtered = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      name: formData.name,
      category: formData.category,
      price: parseFloat(formData.price),
      stock: parseInt(formData.stock),
      minStock: parseInt(formData.minStock),
    };

    if (editingProduct) {
      onUpdateProduct({ ...editingProduct, ...payload });
      setEditingProduct(null);
    } else {
      const newProduct: Product = {
        id: `P-${Date.now()}`,
        ...payload,
        image: 'https://picsum.photos/seed/' + Date.now() + '/200/200'
      };
      onAddProduct(newProduct);
      setIsAdding(false);
    }
    resetForm();
  };

  const resetForm = () => {
    setFormData({ name: '', category: 'Coffee', price: '', stock: '', minStock: '' });
  };

  const startEdit = (p: Product) => {
    setEditingProduct(p);
    setFormData({
      name: p.name,
      category: p.category,
      price: p.price.toString(),
      stock: p.stock.toString(),
      minStock: p.minStock.toString()
    });
  };

  return (
    <div className="p-8 space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Inventory Management</h2>
          <p className="text-gray-500">Maamul alaabta iyo xogta kaydka.</p>
        </div>
        {canManage && (
          <div className="flex gap-3">
             <button onClick={() => setIsAdding(true)} className="px-4 py-2 bg-[#c6a07d] text-white rounded-lg hover:bg-[#b08d6c] transition-colors">
                <i className="fas fa-plus mr-2"></i> Ku dar Alaab
             </button>
          </div>
        )}
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex items-center gap-4">
           <div className="relative flex-1">
              <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
              <input 
                type="text" 
                placeholder="Raadi alaab..." 
                className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-[#c6a07d]"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
           </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50 text-gray-500 text-xs uppercase tracking-wider">
                <th className="px-6 py-4 font-semibold">Alaabta</th>
                <th className="px-6 py-4 font-semibold">Qaybta</th>
                <th className="px-6 py-4 font-semibold">Qiimaha</th>
                <th className="px-6 py-4 font-semibold">Stock</th>
                <th className="px-6 py-4 font-semibold">Status</th>
                {canManage && <th className="px-6 py-4 font-semibold text-right">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filtered.map(product => {
                const isLow = product.stock <= product.minStock;
                return (
                  <tr key={product.id} className="hover:bg-gray-50 transition-colors group">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <img src={product.image} className="w-10 h-10 rounded-lg object-cover" alt="" />
                        <span className="font-semibold text-gray-800">{product.name}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-500">{product.category}</td>
                    <td className="px-6 py-4 font-medium text-gray-800">${product.price.toFixed(2)}</td>
                    <td className="px-6 py-4">
                      <span className={`font-bold ${isLow ? 'text-red-500' : 'text-gray-800'}`}>{product.stock}</span>
                      <span className="text-xs text-gray-400 ml-1">/{product.minStock} min</span>
                    </td>
                    <td className="px-6 py-4">
                      {isLow ? (
                        <span className="px-3 py-1 bg-red-100 text-red-600 rounded-full text-xs font-bold w-fit">Low Stock</span>
                      ) : (
                        <span className="px-3 py-1 bg-green-100 text-green-600 rounded-full text-xs font-bold w-fit">In Stock</span>
                      )}
                    </td>
                    {canManage && (
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                           <button onClick={() => startEdit(product)} className="w-8 h-8 flex items-center justify-center bg-gray-100 rounded-lg text-gray-500 hover:text-[#c6a07d]"><i className="fas fa-edit text-xs"></i></button>
                           <button onClick={() => onDeleteProduct(product.id)} className="w-8 h-8 flex items-center justify-center bg-red-50 rounded-lg text-red-400 hover:text-red-600"><i className="fas fa-trash text-xs"></i></button>
                        </div>
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {(isAdding || editingProduct) && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl p-8 animate-scaleIn">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold">{editingProduct ? 'Bedel Alaabta' : 'Ku dar Alaab Cusub'}</h3>
                <button onClick={() => { setIsAdding(false); setEditingProduct(null); resetForm(); }} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times"></i></button>
             </div>
             <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Magaca</label>
                   <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Qaybta (Category)</label>
                   <select value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full px-4 py-2 border rounded-xl">
                      {CATEGORIES.filter(c => c !== 'All').map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Qiimaha ($)</label>
                      <input type="number" step="0.01" required value={formData.price} onChange={e => setFormData({...formData, price: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                   </div>
                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Stock Hadda</label>
                      <input type="number" required value={formData.stock} onChange={e => setFormData({...formData, stock: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                   </div>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Heerka Digniinta (Min Stock)</label>
                   <input type="number" required value={formData.minStock} onChange={e => setFormData({...formData, minStock: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                </div>
                <button type="submit" className="w-full bg-[#c6a07d] text-white py-3 rounded-xl font-bold hover:bg-[#b08d6c] transition-all">
                  {editingProduct ? 'Cusboonaysii Alaabta' : 'Keydi Alaabta'}
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState } from 'react';
import { StaffMember, UserRole } from '../types';

interface StaffProps {
  staff: StaffMember[];
  onAddStaff: (s: StaffMember) => void;
  onUpdateStaff: (s: StaffMember) => void;
  onDeleteStaff: (id: string) => void;
  currentUser: StaffMember;
}

const Staff: React.FC<StaffProps> = ({ staff, onAddStaff, onUpdateStaff, onDeleteStaff, currentUser }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    role: UserRole.WAITER,
    phone: '',
    status: 'Active' as 'Active' | 'On Leave' | 'Inactive',
    pin: '1234'
  });

  const canManage = [UserRole.ADMIN, UserRole.MANAGER].includes(currentUser.role);

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newMember: StaffMember = {
      id: `S-${Date.now()}`,
      name: formData.name,
      role: formData.role,
      phone: formData.phone,
      joinDate: new Date().toISOString().split('T')[0],
      status: formData.status,
      pin: formData.pin
    };
    onAddStaff(newMember);
    setIsAdding(false);
    resetForm();
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingStaff) {
      onUpdateStaff({
        ...editingStaff,
        name: formData.name,
        role: formData.role,
        phone: formData.phone,
        status: formData.status,
        pin: formData.pin
      });
      setEditingStaff(null);
      resetForm();
    }
  };

  const resetForm = () => {
    setFormData({ name: '', role: UserRole.WAITER, phone: '', status: 'Active', pin: '1234' });
  };

  const startEdit = (member: StaffMember) => {
    setEditingStaff(member);
    setFormData({
      name: member.name,
      role: member.role,
      phone: member.phone,
      status: member.status,
      pin: member.pin
    });
  };

  return (
    <div className="p-8 space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Staff Management</h2>
          <p className="text-gray-500">Diiwaanka iyo maamulka shaqaalaha Koob Coffee.</p>
        </div>
        {canManage && (
          <button onClick={() => setIsAdding(true)} className="px-4 py-2 bg-[#c6a07d] text-white rounded-lg hover:bg-[#b08d6c]">
            <i className="fas fa-user-plus mr-2"></i> Ku dar Shaqaale
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {staff.map(member => (
          <div key={member.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-all flex flex-col items-center text-center relative group">
            {canManage && (
              <div className="absolute top-4 right-4 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => startEdit(member)}
                  className="p-2 bg-gray-50 rounded-lg text-gray-400 hover:text-[#c6a07d]"
                >
                  <i className="fas fa-edit text-xs"></i>
                </button>
                <button 
                  onClick={() => onDeleteStaff(member.id)}
                  className="p-2 bg-red-50 rounded-lg text-red-300 hover:text-red-500"
                >
                  <i className="fas fa-trash text-xs"></i>
                </button>
              </div>
            )}

            <div className="relative mb-4">
              <img src={`https://i.pravatar.cc/150?u=${member.id}`} alt={member.name} className="w-24 h-24 rounded-full border-4 border-gray-50 shadow-sm" />
              <div className={`absolute bottom-0 right-0 w-6 h-6 rounded-full border-4 border-white ${member.status === 'Active' ? 'bg-green-500' : 'bg-orange-500'}`}></div>
            </div>

            <h3 className="text-lg font-bold text-gray-800">{member.name}</h3>
            <span className="text-xs font-semibold text-[#c6a07d] uppercase tracking-wider mb-3 px-3 py-1 bg-[#c6a07d]/10 rounded-full">
              {member.role}
            </span>

            <div className="w-full space-y-2 mb-2">
              <div className="flex justify-between text-sm text-gray-500">
                <span>Phone:</span>
                <span className="font-medium text-gray-700">{member.phone}</span>
              </div>
              <div className="flex justify-between text-sm text-gray-500">
                <span>PIN:</span>
                <span className="font-mono text-gray-700">{canManage ? member.pin : '****'}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {(isAdding || editingStaff) && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl p-8 animate-scaleIn">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold">{editingStaff ? 'Bedel Shaqaalaha' : 'Diiwaangeli Shaqaale'}</h3>
                <button onClick={() => { setIsAdding(false); setEditingStaff(null); resetForm(); }} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times"></i></button>
             </div>
             <form onSubmit={editingStaff ? handleEditSubmit : handleAddSubmit} className="space-y-4">
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Magaca</label>
                   <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Doorka (Role)</label>
                   <select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as UserRole})} className="w-full px-4 py-2 border rounded-xl">
                      {Object.values(UserRole).map(role => <option key={role} value={role}>{role}</option>)}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefoonka</label>
                   <input required value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full px-4 py-2 border rounded-xl" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Login PIN (4 Lambar)</label>
                   <input required maxLength={4} value={formData.pin} onChange={e => setFormData({...formData, pin: e.target.value})} className="w-full px-4 py-2 border rounded-xl font-mono" />
                </div>
                <button type="submit" className="w-full bg-[#c6a07d] text-white py-3 rounded-xl font-bold hover:bg-[#b08d6c]">
                   {editingStaff ? 'Cusboonaysii' : 'Keydi Shaqaalaha'}
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Staff;

import React, { useState, useMemo } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole, PendingOrder } from '../types';
import { CATEGORIES } from '../constants';

interface POSProps {
  products: Product[];
  onCompleteOrder: (order: Order, pendingOrderId?: string) => void;
  onAddPendingOrder: (po: PendingOrder) => void;
  pendingOrders: PendingOrder[];
  currentUser: StaffMember;
}

const POS: React.FC<POSProps> = ({ products, onCompleteOrder, onAddPendingOrder, pendingOrders, currentUser }) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card'>('Cash');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);
  const isWaiterOnly = currentUser.role === UserRole.WAITER;

  const filteredProducts = useMemo(() => {
    return products.filter(p => 
      (activeCategory === 'All' || p.category === activeCategory) &&
      p.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [activeCategory, search, products]);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) {
      alert("Waa ka dhammaatay!");
      return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) {
          alert(`Kaliya ${product.stock} ayaa haray.`);
          return prev;
        }
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.productId === id) {
        const product = products.find(p => p.id === id);
        const newQty = Math.max(0, item.quantity + delta);
        if (product && newQty > product.stock) return item;
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const handlePrintAndSend = () => {
    if (cart.length === 0) return;

    // Create pending order
    const po: PendingOrder = {
      id: `PEND-${Date.now()}`,
      items: [...cart],
      total: total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };

    onAddPendingOrder(po);
    setCart([]);
    alert("Rasiidka waa la daabacay & Dalabka waa loo diray Cashier-ka!");
  };

  const loadPendingOrder = (po: PendingOrder) => {
    setCart(po.items);
    setActivePendingId(po.id);
  };

  const handleCompleteSale = () => {
    const newOrder: Order = {
      id: `ORD-${Date.now()}`,
      items: [...cart],
      total: total,
      discount: 0,
      paymentMethod,
      timestamp: new Date(),
      staffId: currentUser.id,
    };

    onCompleteOrder(newOrder, activePendingId || undefined);
    setCart([]);
    setActivePendingId(null);
    setShowCheckout(false);
    alert("Iibka waa la dhammaystiray!");
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {/* Pending Orders - Hidden for Waiters */}
      {canProcessPayment && (
        <div className="w-72 bg-gray-50 border-r border-gray-200 flex flex-col">
          <div className="p-4 border-b bg-white">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <i className="fas fa-clock text-orange-400"></i> Dalabyada Sugaya
            </h3>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {pendingOrders.length === 0 ? (
              <div className="text-center py-10 text-gray-400">
                <i className="fas fa-inbox text-3xl mb-2 block"></i>
                <p className="text-xs">Ma jiraan dalabyo sugaya</p>
              </div>
            ) : (
              pendingOrders.map(po => (
                <button 
                  key={po.id}
                  onClick={() => loadPendingOrder(po)}
                  className={`w-full text-left p-4 rounded-2xl border transition-all ${
                    activePendingId === po.id ? 'bg-[#3d2b1f] border-[#3d2b1f] text-white shadow-lg' : 'bg-white border-gray-100 hover:border-[#c6a07d]'
                  }`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-[10px] font-bold uppercase tracking-widest opacity-60">#{po.id.slice(-4)}</span>
                    <span className="text-[10px] font-bold">{new Date(po.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                  </div>
                  <p className="font-bold truncate text-sm">{po.waiterName}</p>
                  <div className="flex justify-between items-center mt-2">
                    <span className="text-xs">{po.items.length} items</span>
                    <span className={`font-bold ${activePendingId === po.id ? 'text-[#c6a07d]' : 'text-[#3d2b1f]'}`}>${po.total.toFixed(2)}</span>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Main Product Area */}
      <div className="flex-1 flex flex-col p-6 gap-6 overflow-hidden">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div className="relative w-72">
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" 
              placeholder="Raadi alaab..." 
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-[#c6a07d]"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-md">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`px-4 py-2 rounded-xl text-xs font-bold whitespace-nowrap transition-all ${
                  activeCategory === cat ? 'bg-[#c6a07d] text-white' : 'bg-gray-100 text-gray-600'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4 pr-2">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              disabled={product.stock <= 0}
              className={`bg-white p-3 rounded-2xl border border-gray-100 hover:shadow-md transition-all group relative text-left flex flex-col h-full ${product.stock <= 0 ? 'opacity-50 grayscale' : ''}`}
            >
              <img src={product.image} className="w-full h-24 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 text-sm truncate">{product.name}</h4>
              <p className="text-xs text-gray-500 mb-2">{product.category}</p>
              <div className="mt-auto flex justify-between items-center pt-2">
                <span className="text-[#c6a07d] font-bold text-sm">${product.price.toFixed(2)}</span>
                <span className="text-[10px] text-gray-400">Stock: {product.stock}</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Cart Summary */}
      <div className="w-96 bg-white border-l border-gray-100 flex flex-col shadow-2xl">
        <div className="p-6 border-b border-gray-100">
          <div className="flex justify-between items-center mb-1">
             <h3 className="text-xl font-bold">Dalabka Hadda</h3>
             <button onClick={() => { setCart([]); setActivePendingId(null); }} className="text-gray-400 hover:text-red-500"><i className="fas fa-trash-alt"></i></button>
          </div>
          <p className="text-[10px] font-bold text-[#c6a07d] uppercase tracking-widest">{currentUser.role} View</p>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-300">
              <i className="fas fa-shopping-basket text-4xl mb-4"></i>
              <p className="text-sm">Kudar alaab dambiisha</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-2xl">
                <div className="flex-1">
                  <h4 className="font-bold text-gray-800 text-sm truncate">{item.name}</h4>
                  <p className="text-xs text-[#c6a07d] font-bold">${(item.price * item.quantity).toFixed(2)}</p>
                </div>
                <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl border border-gray-100 shadow-sm">
                   <button onClick={() => updateQuantity(item.productId, -1)} className="w-6 h-6 flex items-center justify-center text-[#c6a07d] hover:bg-gray-50 rounded-lg">-</button>
                   <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                   <button onClick={() => updateQuantity(item.productId, 1)} className="w-6 h-6 flex items-center justify-center text-[#c6a07d] hover:bg-gray-50 rounded-lg">+</button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-gray-50 space-y-4">
          <div className="flex justify-between items-center pt-2 border-t border-gray-200">
            <span className="font-bold text-gray-500">Total</span>
            <span className="text-2xl font-bold text-[#3d2b1f]">${total.toFixed(2)}</span>
          </div>

          <div className="flex flex-col gap-2">
            {/* Common Action: Print Receipt */}
            <button 
              disabled={cart.length === 0}
              onClick={handlePrintAndSend}
              className="w-full bg-white border-2 border-gray-200 hover:border-[#c6a07d] hover:text-[#c6a07d] text-gray-700 py-3 rounded-2xl font-bold text-sm transition-all flex items-center justify-center gap-2 shadow-sm"
            >
              <i className="fas fa-print"></i> Daabac & Diri
            </button>

            {/* Restricted Action: Payment (Cashier/Manager/Admin Only) */}
            {canProcessPayment ? (
              <button 
                disabled={cart.length === 0}
                onClick={() => setShowCheckout(true)}
                className="w-full bg-[#c6a07d] disabled:opacity-50 text-white py-4 rounded-2xl font-bold text-lg shadow-lg hover:bg-[#b08d6c] transition-all"
              >
                <i className="fas fa-wallet mr-2"></i> Bixi Biilka
              </button>
            ) : (
              <div className="bg-gray-100 text-gray-400 py-4 rounded-2xl font-bold text-center text-xs flex items-center justify-center gap-2">
                <i className="fas fa-lock"></i> KALIYA CASHIER BAA BIXIN KARA
              </div>
            )}
          </div>
        </div>
      </div>

      {showCheckout && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 animate-scaleIn shadow-2xl">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold">Habka Lacag Bixinta</h3>
                <button onClick={() => setShowCheckout(false)} className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center"><i className="fas fa-times"></i></button>
              </div>

              <div className="grid grid-cols-2 gap-4 mb-8">
                 {(['Cash', 'EVC Plus', 'E-Dahab', 'Card'] as const).map(method => (
                   <button 
                    key={method}
                    onClick={() => setPaymentMethod(method)}
                    className={`flex flex-col items-center gap-2 p-4 rounded-3xl border-2 transition-all ${paymentMethod === method ? 'border-[#c6a07d] bg-[#c6a07d]/10' : 'bg-gray-50 border-gray-50'}`}
                   >
                     <i className={`fas ${method === 'Cash' ? 'fa-wallet' : method === 'Card' ? 'fa-credit-card' : 'fa-mobile-screen-button'} text-xl ${paymentMethod === method ? 'text-[#c6a07d]' : 'text-gray-400'}`}></i>
                     <span className="text-xs font-bold">{method}</span>
                   </button>
                 ))}
              </div>

              <button onClick={handleCompleteSale} className="w-full bg-[#3d2b1f] text-white py-5 rounded-3xl font-bold text-xl hover:bg-black transition-all shadow-xl">
                 Dhammaystir (${total.toFixed(2)})
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

