  );
};

export default Settings;

import React, { useState, useMemo, useEffect } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole, PendingOrder } from '../types';
import { CATEGORIES } from '../constants';

interface POSProps {
  products: Product[];
  onCompleteOrder: (order: Order, pendingOrderId?: string) => void;
  onAddPendingOrder: (po: PendingOrder) => void;
  pendingOrders: PendingOrder[];
  currentUser: StaffMember;
  taxRate: number;
  globalTaxEnabled: boolean;
}

const Logo = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-12 h-12 fill-[#3d2b1f]"}>
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const POS: React.FC<POSProps> = ({ products, onCompleteOrder, onAddPendingOrder, pendingOrders, currentUser, taxRate, globalTaxEnabled }) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [showReceipt, setShowReceipt] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card'>('Cash');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);
  const [applyTax, setApplyTax] = useState(globalTaxEnabled);

  // Sync with global default when it changes, but only if cart is empty
  useEffect(() => {
    if (cart.length === 0) {
      setApplyTax(globalTaxEnabled);
    }
  }, [globalTaxEnabled, cart.length]);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);

  const filteredProducts = useMemo(() => {
    return products.filter(p => 
      (activeCategory === 'All' || p.category === activeCategory) &&
      p.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [activeCategory, search, products]);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) {
      alert("Waa ka dhammaatay!");
      return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) {
          alert(`Kaliya ${product.stock} ayaa haray.`);
          return prev;
        }
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.productId === id) {
        const product = products.find(p => p.id === id);
        const newQty = Math.max(0, item.quantity + delta);
        if (product && newQty > product.stock) return item;
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const taxAmount = applyTax ? (subtotal * (taxRate / 100)) : 0;
  const total = subtotal + taxAmount;

  const handlePrintAndSend = () => {
    if (cart.length === 0) return;
    setShowReceipt(true);
  };

  const finalizeSend = () => {
    const po: PendingOrder = {
      id: `PEND-${Date.now()}`,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total: total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };

    onAddPendingOrder(po);
    setCart([]);
    setShowReceipt(false);
    alert("Dalabka waa loo diray Cashier-ka!");
  };

  const loadPendingOrder = (po: PendingOrder) => {
    setCart(po.items);
    setActivePendingId(po.id);
    // Inherit the tax state of the pending order (if tax > 0, assume it was enabled)
    setApplyTax(po.tax > 0);
  };

  const handleCompleteSale = () => {
    const newOrder: Order = {
      id: `ORD-${Date.now()}`,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total: total,
      discount: 0,
      paymentMethod,
      timestamp: new Date(),
      staffId: currentUser.id,
    };

    onCompleteOrder(newOrder, activePendingId || undefined);
    setCart([]);
    setActivePendingId(null);
    setShowCheckout(false);
    alert("Iibka waa la dhammaystiray!");
  };

  const triggerPrint = () => {
    window.print();
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {/* Pending Orders - Hidden for Waiters */}
      {canProcessPayment && (
        <div className="w-72 bg-gray-50 border-r border-gray-200 flex flex-col no-print">
          <div className="p-4 border-b bg-white">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <i className="fas fa-clock text-orange-400"></i> Dalabyada Sugaya
            </h3>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {pendingOrders.length === 0 ? (
              <div className="text-center py-10 text-gray-400">
                <i className="fas fa-inbox text-3xl mb-2 block"></i>
                <p className="text-xs">Ma jiraan dalabyo sugaya</p>
              </div>
            ) : (
              pendingOrders.map(po => (
                <button 
                  key={po.id}
                  onClick={() => loadPendingOrder(po)}
                  className={`w-full text-left p-4 rounded-2xl border transition-all ${
                    activePendingId === po.id ? 'bg-[#3d2b1f] border-[#3d2b1f] text-white shadow-lg' : 'bg-white border-gray-100 hover:border-[#c6a07d]'
                  }`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-[10px] font-bold uppercase tracking-widest opacity-60">#{po.id.slice(-4)}</span>
                    <span className="text-[10px] font-bold">{new Date(po.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                  </div>
                  <p className="font-bold truncate text-sm">{po.waiterName}</p>
                  <div className="flex justify-between items-center mt-2">
                    <span className="text-xs">{po.items.length} items</span>
                    <span className={`font-bold ${activePendingId === po.id ? 'text-[#c6a07d]' : 'text-[#3d2b1f]'}`}>${po.total.toFixed(2)}</span>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Main Product Area */}
      <div className="flex-1 flex flex-col p-6 gap-6 overflow-hidden no-print">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div className="relative w-72">
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" 
              placeholder="Raadi alaab..." 
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-[#c6a07d]"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-md">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`px-4 py-2 rounded-xl text-xs font-bold whitespace-nowrap transition-all ${
                  activeCategory === cat ? 'bg-[#c6a07d] text-white' : 'bg-gray-100 text-gray-600'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4 pr-2">
          {filteredProducts.map(product => (
            <button
              key={product.id}
              onClick={() => addToCart(product)}
              disabled={product.stock <= 0}
              className={`bg-white p-3 rounded-2xl border border-gray-100 hover:shadow-md transition-all group relative text-left flex flex-col h-full ${product.stock <= 0 ? 'opacity-50 grayscale' : ''}`}
            >
              <img src={product.image} className="w-full h-24 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 text-sm truncate">{product.name}</h4>
              <p className="text-xs text-gray-500 mb-2">{product.category}</p>
              <div className="mt-auto flex justify-between items-center pt-2">
                <span className="text-[#c6a07d] font-bold text-sm">${product.price.toFixed(2)}</span>
                <span className="text-[10px] text-gray-400">Stock: {product.stock}</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Cart Summary */}
      <div className="w-96 bg-white border-l border-gray-100 flex flex-col shadow-2xl no-print">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-bold">Dalabka Hadda</h3>
            <p className="text-[10px] font-bold text-[#c6a07d] uppercase tracking-widest">{currentUser.role} View</p>
          </div>
          <button onClick={() => { setCart([]); setActivePendingId(null); }} className="text-gray-400 hover:text-red-500"><i className="fas fa-trash-alt"></i></button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-300">
              <i className="fas fa-shopping-basket text-4xl mb-4"></i>
              <p className="text-sm">Kudar alaab dambiisha</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-2xl">
                <div className="flex-1">
                  <h4 className="font-bold text-gray-800 text-sm truncate">{item.name}</h4>
                  <p className="text-xs text-[#c6a07d] font-bold">${(item.price * item.quantity).toFixed(2)}</p>
                </div>
                <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl border border-gray-100 shadow-sm">
                   <button onClick={() => updateQuantity(item.productId, -1)} className="w-6 h-6 flex items-center justify-center text-[#c6a07d] hover:bg-gray-50 rounded-lg">-</button>
                   <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                   <button onClick={() => updateQuantity(item.productId, 1)} className="w-6 h-6 flex items-center justify-center text-[#c6a07d] hover:bg-gray-50 rounded-lg">+</button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-gray-50 space-y-4">
          <div className="space-y-2 pt-2 border-t border-gray-200">
            <div className="flex justify-between items-center text-gray-500 text-sm">
              <span>Subtotal</span>
              <span>${subtotal.toFixed(2)}</span>
            </div>

            {/* Per-Order Tax Toggle UI */}
            <div className="flex justify-between items-center group cursor-pointer" onClick={() => setApplyTax(!applyTax)}>
              <span className={`text-sm flex items-center gap-2 transition-colors ${applyTax ? 'text-gray-700 font-semibold' : 'text-gray-400'}`}>
                <i className={`fas ${applyTax ? 'fa-check-circle text-[#c6a07d]' : 'fa-circle text-gray-300'}`}></i>
                Apply VAT ({taxRate}%)
              </span>
              <span className={`text-sm transition-colors ${applyTax ? 'text-gray-700 font-bold' : 'text-gray-400'}`}>
                ${taxAmount.toFixed(2)}
              </span>
            </div>

            <div className="flex justify-between items-center pt-2 border-t border-gray-200">
              <span className="font-bold text-gray-700">Grand Total</span>
              <span className="text-2xl font-bold text-[#3d2b1f]">${total.toFixed(2)}</span>
            </div>
          </div>

          <div className="flex flex-col gap-2">
            <button 
              disabled={cart.length === 0}
              onClick={handlePrintAndSend}
              className="w-full bg-white border-2 border-gray-200 hover:border-[#c6a07d] hover:text-[#c6a07d] text-gray-700 py-3 rounded-2xl font-bold text-sm transition-all flex items-center justify-center gap-2 shadow-sm"
            >
              <i className="fas fa-print"></i> Daabac Rasiidka
            </button>

            {canProcessPayment ? (
              <button 
                disabled={cart.length === 0}
                onClick={() => setShowCheckout(true)}
                className="w-full bg-[#c6a07d] disabled:opacity-50 text-white py-4 rounded-2xl font-bold text-lg shadow-lg hover:bg-[#b08d6c] transition-all"
              >
                <i className="fas fa-wallet mr-2"></i> Bixi Biilka
              </button>
            ) : (
              <div className="bg-gray-100 text-gray-400 py-4 rounded-2xl font-bold text-center text-xs flex items-center justify-center gap-2">
                <i className="fas fa-lock"></i> KALIYA CASHIER BAA BIXIN KARA
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Receipt Modal */}
      {showReceipt && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4 no-print">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 animate-scaleIn shadow-2xl flex flex-col">
            <div id="printable-receipt" className="bg-white p-4 font-mono text-sm text-gray-800">
               <div className="flex flex-col items-center mb-4">
                  <Logo className="w-16 h-16 fill-[#3d2b1f] mb-2" />
                  <h2 className="text-xl font-bold uppercase font-playfair tracking-wider">Koob Coffee</h2>
                  <p className="text-[10px] text-gray-500">Mogadishu, Somalia</p>
                  <p className="text-[10px] text-gray-500">Tel: +252 61 XXX XXXX</p>
               </div>

               <div className="border-t border-dashed border-gray-300 py-3 space-y-1 text-[10px]">
                  <div className="flex justify-between"><span>Date:</span> <span>{new Date().toLocaleDateString()}</span></div>
                  <div className="flex justify-between"><span>Time:</span> <span>{new Date().toLocaleTimeString()}</span></div>
                  <div className="flex justify-between"><span>Staff:</span> <span>{currentUser.name}</span></div>
                  <div className="flex justify-between"><span>Order:</span> <span>#{Date.now().toString().slice(-6)}</span></div>
               </div>

               <div className="border-t border-b border-dashed border-gray-300 py-3 my-3">
                  <div className="flex font-bold text-[10px] mb-2">
                     <span className="flex-1">Item</span>
                     <span className="w-8 text-center">Qty</span>
                     <span className="w-16 text-right">Price</span>
                  </div>
                  {cart.map((item, idx) => (
                    <div key={idx} className="flex text-[10px]">
                       <span className="flex-1 truncate">{item.name}</span>
                       <span className="w-8 text-center">{item.quantity}</span>
                       <span className="w-16 text-right">${(item.price * item.quantity).toFixed(2)}</span>
                    </div>
                  ))}
               </div>

               <div className="space-y-1 text-[10px]">
                  <div className="flex justify-between"><span>Subtotal:</span> <span>${subtotal.toFixed(2)}</span></div>
                  {applyTax && (
                    <div className="flex justify-between"><span>VAT ({taxRate}%):</span> <span>${taxAmount.toFixed(2)}</span></div>
                  )}
                  <div className="flex justify-between font-bold text-[11px] pt-1 border-t border-dotted border-gray-200">
                     <span>TOTAL:</span> <span>${total.toFixed(2)}</span>
                  </div>
               </div>

               <div className="text-center mt-8 space-y-1 border-t border-dashed border-gray-300 pt-4">
                  <p className="text-[10px] italic">Mahadsanid, Soo dhawoow mar kale!</p>
                  <div className="flex justify-center gap-1 mt-2">
                    {[...Array(20)].map((_, i) => <div key={i} className="w-2 h-0.5 bg-gray-200"></div>)}
                  </div>
               </div>
            </div>

            <div className="mt-6 flex gap-3">
               <button onClick={() => setShowReceipt(false)} className="flex-1 py-3 bg-gray-100 text-gray-600 rounded-xl font-bold text-sm">Cancel</button>
               <button onClick={triggerPrint} className="flex-1 py-3 bg-[#c6a07d] text-white rounded-xl font-bold text-sm flex items-center justify-center gap-2">
                  <i className="fas fa-print"></i> Print
               </button>
            </div>
            {currentUser.role === UserRole.WAITER && (
              <button onClick={finalizeSend} className="mt-3 w-full py-4 bg-[#3d2b1f] text-white rounded-xl font-bold shadow-lg">
                Dhammeystir & Diri
              </button>
            )}
          </div>
        </div>
      )}

      {showCheckout && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 no-print">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 animate-scaleIn shadow-2xl">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold">Habka Lacag Bixinta</h3>
                <button onClick={() => setShowCheckout(false)} className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center"><i className="fas fa-times"></i></button>
              </div>

              <div className="grid grid-cols-2 gap-4 mb-8">
                 {(['Cash', 'EVC Plus', 'E-Dahab', 'Card'] as const).map(method => (
                   <button 
                    key={method}
                    onClick={() => setPaymentMethod(method)}
                    className={`flex flex-col items-center gap-2 p-4 rounded-3xl border-2 transition-all ${paymentMethod === method ? 'border-[#c6a07d] bg-[#c6a07d]/10' : 'bg-gray-50 border-gray-50'}`}
                   >
                     <i className={`fas ${method === 'Cash' ? 'fa-wallet' : method === 'Card' ? 'fa-credit-card' : 'fa-mobile-screen-button'} text-xl ${paymentMethod === method ? 'text-[#c6a07d]' : 'text-gray-400'}`}></i>
                     <span className="text-xs font-bold">{method}</span>
                   </button>
                 ))}
              </div>

              <button onClick={handleCompleteSale} className="w-full bg-[#3d2b1f] text-white py-5 rounded-3xl font-bold text-xl hover:bg-black transition-all shadow-xl">
                 Dhammaystir (${total.toFixed(2)})
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState } from 'react';
import { Product, StaffMember, UserRole } from '../types';
import { CATEGORIES } from '../constants';

interface InventoryProps {
  products: Product[];
  onAddProduct: (p: Product) => void;
  onUpdateProduct: (p: Product) => void;
  onDeleteProduct: (id: string) => void;
  currentUser: StaffMember;
}

const Inventory: React.FC<InventoryProps> = ({ products, onAddProduct, onUpdateProduct, onDeleteProduct, currentUser }) => {
  const [search, setSearch] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    category: 'Coffee',
    price: '',
    stock: '',
    minStock: ''
  });

  const canManage = [UserRole.ADMIN, UserRole.MANAGER].includes(currentUser.role);
  const filtered = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      name: formData.name,
      category: formData.category,
      price: parseFloat(formData.price),
      stock: parseInt(formData.stock),
      minStock: parseInt(formData.minStock),
    };

    if (editingProduct) {
      onUpdateProduct({ ...editingProduct, ...payload });
      setEditingProduct(null);
    } else {
      const newProduct: Product = {
        id: `P-${Date.now()}`,
        ...payload,
        image: 'https://picsum.photos/seed/' + Date.now() + '/200/200'
      };
      onAddProduct(newProduct);
      setIsAdding(false);
    }
    resetForm();
  };

  const resetForm = () => {
    setFormData({ name: '', category: 'Coffee', price: '', stock: '', minStock: '' });
  };

  const startEdit = (p: Product) => {
    setEditingProduct(p);
    setFormData({
      name: p.name,
      category: p.category,
      price: p.price.toString(),
      stock: p.stock.toString(),
      minStock: p.minStock.toString()
    });
  };

  return (
    <div className="p-8 space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-gray-800">Inventory Management</h2>
          <p className="text-gray-500">Halkan ka maamul, ka bedel, ama ka tirtir alaabta kaydka.</p>
        </div>
        {canManage && (
          <div className="flex gap-3">
             <button onClick={() => setIsAdding(true)} className="px-6 py-3 bg-[#3d2b1f] text-white rounded-2xl hover:bg-black transition-all shadow-lg flex items-center gap-2 font-bold">
                <i className="fas fa-plus"></i> Ku dar Alaab Cusub
             </button>
          </div>
        )}
      </div>

      <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex items-center gap-4 bg-gray-50/50">
           <div className="relative flex-1">
              <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
              <input 
                type="text" 
                placeholder="Raadi alaabta magaceeda..." 
                className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-2xl focus:ring-2 focus:ring-[#c6a07d] focus:border-transparent transition-all"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
           </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-white text-gray-400 text-[10px] uppercase tracking-[0.2em] font-black border-b border-gray-100">
                <th className="px-8 py-5">Alaabta / Item</th>
                <th className="px-6 py-5">Category</th>
                <th className="px-6 py-5">Price</th>
                <th className="px-6 py-5">Stock Level</th>
                <th className="px-6 py-5">Status</th>
                {canManage && <th className="px-8 py-5 text-right">Maamulka</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {filtered.map(product => {
                const isLow = product.stock <= product.minStock;
                return (
                  <tr key={product.id} className="hover:bg-gray-50/80 transition-colors group">
                    <td className="px-8 py-5">
                      <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-2xl overflow-hidden shadow-sm border border-gray-100">
                          <img src={product.image} className="w-full h-full object-cover" alt="" />
                        </div>
                        <span className="font-bold text-gray-800">{product.name}</span>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <span className="px-3 py-1 bg-gray-100 text-gray-600 rounded-lg text-xs font-bold">{product.category}</span>
                    </td>
                    <td className="px-6 py-5 font-black text-[#3d2b1f]">${product.price.toFixed(2)}</td>
                    <td className="px-6 py-5">
                      <div className="flex flex-col">
                        <span className={`font-black text-lg ${isLow ? 'text-red-500' : 'text-gray-800'}`}>{product.stock}</span>
                        <span className="text-[10px] text-gray-400 font-bold uppercase">Min: {product.minStock}</span>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      {isLow ? (
                        <div className="flex items-center gap-2 text-red-500">
                          <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></span>
                          <span className="text-xs font-black uppercase">Low Stock</span>
                        </div>
                      ) : (
                        <div className="flex items-center gap-2 text-green-500">
                          <span className="w-2 h-2 rounded-full bg-green-500"></span>
                          <span className="text-xs font-black uppercase">In Stock</span>
                        </div>
                      )}
                    </td>
                    {canManage && (
                      <td className="px-8 py-5 text-right">
                        <div className="flex items-center justify-end gap-3">
                           <button 
                            onClick={() => startEdit(product)} 
                            title="Bedel alaabta"
                            className="w-10 h-10 flex items-center justify-center bg-blue-50 rounded-xl text-blue-600 hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                           >
                             <i className="fas fa-edit text-sm"></i>
                           </button>
                           <button 
                            onClick={() => onDeleteProduct(product.id)} 
                            title="Tir alaabta"
                            className="w-10 h-10 flex items-center justify-center bg-red-50 rounded-xl text-red-500 hover:bg-red-500 hover:text-white transition-all shadow-sm"
                           >
                             <i className="fas fa-trash-alt text-sm"></i>
                           </button>
                        </div>
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filtered.length === 0 && (
            <div className="py-20 flex flex-col items-center justify-center text-gray-400">
              <i className="fas fa-search text-4xl mb-4 opacity-20"></i>
              <p className="font-bold">Wax alaab ah lama helin.</p>
            </div>
          )}
        </div>
      </div>

      {(isAdding || editingProduct) && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-10 animate-scaleIn shadow-2xl">
             <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-2xl font-black text-gray-800">{editingProduct ? 'Bedel Macluumaadka' : 'Diiwaangeli Alaab'}</h3>
                  <p className="text-sm text-gray-500">{editingProduct ? 'Cusboonaysii xogta alaabtan halkan.' : 'Buuxi foomka si aad ugu darto alaab cusub.'}</p>
                </div>
                <button onClick={() => { setIsAdding(false); setEditingProduct(null); resetForm(); }} className="w-12 h-12 bg-gray-100 rounded-2xl flex items-center justify-center text-gray-400 hover:text-gray-800 transition-all">
                  <i className="fas fa-times text-xl"></i>
                </button>
             </div>

             <form onSubmit={handleSubmit} className="space-y-6">
                <div className="space-y-2">
                   <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Magaca Alaabta (Item Name)</label>
                   <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-[#c6a07d] font-bold" placeholder="Tusaale: Iced Latte" />
                </div>

                <div className="space-y-2">
                   <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Qaybta (Category)</label>
                   <select value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-[#c6a07d] font-bold">
                      {CATEGORIES.filter(c => c !== 'All').map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                </div>

                <div className="grid grid-cols-2 gap-6">
                   <div className="space-y-2">
                      <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Qiimaha ($)</label>
                      <input type="number" step="0.01" required value={formData.price} onChange={e => setFormData({...formData, price: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-[#c6a07d] font-bold text-center" />
                   </div>
                   <div className="space-y-2">
                      <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Tirada Kaydka (Stock)</label>
                      <input type="number" required value={formData.stock} onChange={e => setFormData({...formData, stock: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-[#c6a07d] font-bold text-center" />
                   </div>
                </div>

                <div className="space-y-2">
                   <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Xadka Digniinta (Minimum Stock Level)</label>
                   <input type="number" required value={formData.minStock} onChange={e => setFormData({...formData, minStock: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-[#c6a07d] font-bold text-center" />
                   <p className="text-[10px] text-gray-400 italic mt-1">Nidaamku wuxuu ku siin doonaa digniin haddii tiradu halkan hoos ugu dhacdo.</p>
                </div>

                <button type="submit" className="w-full bg-[#3d2b1f] text-white py-5 rounded-2xl font-black text-lg hover:bg-black transition-all shadow-xl mt-4">
                  {editingProduct ? 'Cusboonaysii Alaabta' : 'Keydi Alaabta Cusub'}
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

