            <div className="w-12 h-12 bg-purple-100 text-purple-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-palette text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Branding & System</h3>
              <p className="text-sm text-gray-500">Muuqaalka iyo magaca ganacsiga.</p>
            </div>
          </div>

          <form onSubmit={handleUpdateBranding} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2 space-y-2">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Magaca Ganacsiga (Shop Name)</label>
              <input 
                value={tempConfig.name} 
                onChange={e => setTempConfig({...tempConfig, name: e.target.value})}
