import React, { useState } from 'react';
import { StaffMember, SystemConfig } from '../types';

interface LoginProps {
  staffMembers: StaffMember[];
  onLogin: (staff: StaffMember) => void;
  config: SystemConfig;
}

const DefaultLogo = () => (
  <svg viewBox="0 0 100 100" className="w-16 h-16 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Login: React.FC<LoginProps> = ({ staffMembers, onLogin, config }) => {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);

  const handleNumberClick = (num: string) => {
    if (pin.length < 4) {
      const newPin = pin + num;
      setPin(newPin);
      setError(false);

      if (newPin.length === 4) {
        setTimeout(() => {
          const matchedStaff = staffMembers.find(s => s.pin === newPin);
          if (matchedStaff) {
            onLogin(matchedStaff);
          } else {
            setError(true);
            setPin('');
          }
        }, 300);
      }
    }
  };

  const handleDelete = () => {
    setPin(pin.slice(0, -1));
    setError(false);
  };

  return (
    <div className="fixed inset-0 flex items-center justify-center z-[100] bg-brand-primary overflow-hidden">
      {/* Dynamic Background Image */}
      <div 
        className="absolute inset-0 opacity-40 bg-cover bg-center"
        style={{ backgroundImage: `url(${config.loginBgUrl})` }}
      ></div>
      <div className="absolute inset-0 bg-gradient-to-t from-brand-primary via-brand-primary/80 to-transparent"></div>

      <div className="w-full max-w-md p-8 flex flex-col items-center relative z-10 animate-fadeIn">
        <div className="w-28 h-28 bg-white rounded-[2.5rem] flex items-center justify-center shadow-2xl mb-8 transform rotate-3 border-4 border-brand-secondary/20 overflow-hidden">
          {config.logoUrl ? (
            <img src={config.logoUrl} className="w-full h-full object-cover" alt="Logo" />
          ) : (
            <DefaultLogo />
          )}
        </div>

        <h1 className="text-4xl font-playfair font-black text-white mb-2 text-center drop-shadow-lg uppercase tracking-tight">{config.name}</h1>
        <p className="text-brand-secondary mb-12 font-black tracking-[0.3em] uppercase text-[10px] bg-white/5 px-4 py-1.5 rounded-full border border-white/10">Staff Access Point</p>

        <div className="flex gap-6 mb-12">
          {[0, 1, 2, 3].map((i) => (
            <div
              key={i}
              className={`w-4 h-4 rounded-full border-2 transition-all duration-300 shadow-lg ${
                error ? 'border-red-500 bg-red-500 animate-bounce' : 
                pin.length > i ? 'bg-brand-secondary border-brand-secondary scale-150' : 'border-white/30 bg-black/20'
              }`}
            ></div>
          ))}
        </div>

        <div className="grid grid-cols-3 gap-6 w-full max-w-[340px]">
          {['1', '2', '3', '4', '5', '6', '7', '8', '9'].map((num) => (
            <button
              key={num}
              onClick={() => handleNumberClick(num)}
              className="w-20 h-20 rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 text-white text-3xl font-black hover:bg-white/20 active:scale-90 transition-all flex items-center justify-center shadow-lg"
            >
              {num}
            </button>
          ))}
          <div className="w-20 h-20"></div>
          <button
            onClick={() => handleNumberClick('0')}
            className="w-20 h-20 rounded-3xl bg-white/10 backdrop-blur-md border border-white/20 text-white text-3xl font-black hover:bg-white/20 active:scale-90 transition-all flex items-center justify-center shadow-lg"
          >
            0
          </button>
          <button
            onClick={handleDelete}
            className="w-20 h-20 rounded-3xl bg-white/5 text-white/50 text-2xl hover:text-white active:scale-90 transition-all flex items-center justify-center"
          >
            <i className="fas fa-backspace"></i>
          </button>
        </div>

        {error && (
          <div className="mt-8 px-6 py-2 bg-red-500/20 backdrop-blur-sm border border-red-500/50 rounded-full text-red-200 font-bold text-xs animate-pulse">
            PIN-ka waa khalad. Mar kale isku day.
          </div>
        )}
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useMemo, useEffect } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole, PendingOrder, SystemConfig } from '../types';
import { CATEGORIES } from '../constants';

interface POSProps {
  products: Product[];
  onCompleteOrder: (order: Order, pendingOrderId?: string) => void;
  onAddPendingOrder: (po: PendingOrder) => void;
  pendingOrders: PendingOrder[];
  currentUser: StaffMember;
  taxRate: number;
  globalTaxEnabled: boolean;
  config: SystemConfig;
}

const DefaultLogoSVG = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-12 h-12 fill-brand-primary"}>
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const POS: React.FC<POSProps> = ({ products, onCompleteOrder, onAddPendingOrder, pendingOrders, currentUser, taxRate, globalTaxEnabled, config }) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [showReceipt, setShowReceipt] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'EVC Plus' | 'E-Dahab' | 'Card'>('Cash');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);
  const [applyTax, setApplyTax] = useState(globalTaxEnabled);

  useEffect(() => {
    if (cart.length === 0) setApplyTax(globalTaxEnabled);
  }, [globalTaxEnabled, cart.length]);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);
  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const taxAmount = applyTax ? (subtotal * (taxRate / 100)) : 0;
  const total = subtotal + taxAmount;

  const filteredProducts = useMemo(() => 
    products.filter(p => (activeCategory === 'All' || p.category === activeCategory) && p.name.toLowerCase().includes(search.toLowerCase())),
    [activeCategory, search, products]
  );

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return alert("Waa ka dhammaatay!");
    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return (alert("Stock limit!"), prev);
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const handleCompleteSale = () => {
    onCompleteOrder({
      id: `ORD-${Date.now()}`,
      items: [...cart], subtotal, tax: taxAmount, total, discount: 0, paymentMethod, timestamp: new Date(), staffId: currentUser.id,
    }, activePendingId || undefined);
    setCart([]); setActivePendingId(null); setShowCheckout(false); alert("Waa la dhammeeyay!");
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {canProcessPayment && (
        <div className="w-72 bg-gray-50 border-r border-gray-200 flex flex-col no-print">
          <div className="p-4 border-b bg-white">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <i className="fas fa-clock text-brand-secondary"></i> Dalabyada Sugaya
            </h3>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {pendingOrders.map(po => (
              <button 
                key={po.id} onClick={() => {setCart(po.items); setActivePendingId(po.id); setApplyTax(po.tax > 0);}}
                className={`w-full text-left p-4 rounded-2xl border transition-all ${activePendingId === po.id ? 'bg-brand-primary border-brand-primary text-white shadow-lg' : 'bg-white border-gray-100 hover:border-brand-secondary'}`}
              >
                <div className="flex justify-between items-start mb-1 text-[10px] font-bold">
                  <span className="opacity-60">#{po.id.slice(-4)}</span>
                  <span>{new Date(po.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                </div>
                <p className="font-bold truncate text-sm">{po.waiterName}</p>
                <div className="flex justify-between items-center mt-2">
                  <span className="text-xs">{po.items.length} items</span>
                  <span className={`font-bold ${activePendingId === po.id ? 'text-brand-secondary' : 'text-brand-primary'}`}>{config.currencySymbol}{po.total.toFixed(2)}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="flex-1 flex flex-col p-6 gap-6 overflow-hidden no-print">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <input 
            type="text" placeholder="Raadi alaab..." 
            className="w-72 pl-4 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-brand-secondary"
            value={search} onChange={(e) => setSearch(e.target.value)}
          />
          <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-md">
            {CATEGORIES.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${activeCategory === cat ? 'bg-brand-secondary text-white shadow-md' : 'bg-gray-100 text-gray-600'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredProducts.map(product => (
            <button key={product.id} onClick={() => addToCart(product)} disabled={product.stock <= 0} className="bg-white p-3 rounded-2xl border border-gray-100 hover:shadow-xl transition-all flex flex-col text-left group">
              <img src={product.image} className="w-full h-28 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 text-sm truncate">{product.name}</h4>
              <div className="mt-auto flex justify-between items-center pt-2">
                <span className="text-brand-secondary font-black text-sm">{config.currencySymbol}{product.price.toFixed(2)}</span>
                <span className="text-[10px] text-gray-400 font-bold">Qty: {product.stock}</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="w-96 bg-white border-l border-gray-100 flex flex-col shadow-2xl no-print">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
          <div><h3 className="text-xl font-black text-brand-primary">Dambiisha</h3><p className="text-[9px] font-bold text-brand-secondary uppercase tracking-[0.2em]">Transaction Panel</p></div>
          <button onClick={() => { setCart([]); setActivePendingId(null); }} className="text-gray-400 hover:text-red-500 transition-colors"><i className="fas fa-trash-alt"></i></button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.map(item => (
            <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-2xl border border-transparent hover:border-brand-secondary/20 transition-all">
              <div className="flex-1"><h4 className="font-bold text-gray-800 text-sm truncate">{item.name}</h4><p className="text-xs text-brand-secondary font-black">{config.currencySymbol}{(item.price * item.quantity).toFixed(2)}</p></div>
              <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                 <button onClick={() => {setCart(prev => prev.map(i => i.productId === item.productId ? {...i, quantity: Math.max(0, i.quantity - 1)} : i).filter(i => i.quantity > 0))}} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">-</button>
                 <span className="text-xs font-black w-4 text-center">{item.quantity}</span>
                 <button onClick={() => addToCart(products.find(p => p.id === item.productId)!)} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">+</button>
              </div>
            </div>
          ))}
        </div>

        <div className="p-6 bg-gray-100/50 space-y-4 rounded-t-[2.5rem] shadow-[0_-10px_30px_-15px_rgba(0,0,0,0.1)]">
          <div className="space-y-2 text-sm font-medium">
            <div className="flex justify-between text-gray-500"><span>Subtotal</span><span>{config.currencySymbol}{subtotal.toFixed(2)}</span></div>
            <div className="flex justify-between items-center group cursor-pointer" onClick={() => setApplyTax(!applyTax)}>
              <span className={`flex items-center gap-2 ${applyTax ? 'text-brand-primary' : 'text-gray-400'}`}><i className={`fas ${applyTax ? 'fa-check-circle text-brand-secondary' : 'fa-circle text-gray-200'}`}></i> VAT ({taxRate}%)</span>
              <span className={applyTax ? 'font-bold' : 'text-gray-400'}>{config.currencySymbol}{taxAmount.toFixed(2)}</span>
            </div>
            <div className="flex justify-between pt-2 border-t border-gray-200"><span className="font-black text-lg text-brand-primary">Total</span><span className="text-2xl font-black text-brand-primary">{config.currencySymbol}{total.toFixed(2)}</span></div>
          </div>
          <button onClick={() => setShowReceipt(true)} className="w-full bg-white border-2 border-brand-secondary/20 text-brand-primary py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-sm hover:border-brand-secondary transition-all"><i className="fas fa-print mr-2"></i> Daabac Receipt</button>
          {canProcessPayment ? (
            <button onClick={() => setShowCheckout(true)} disabled={cart.length === 0} className="w-full bg-brand-primary text-white py-5 rounded-3xl font-black text-xl shadow-xl hover:opacity-95 transition-all">Bixi Bill-ka</button>
          ) : (
            <button onClick={() => {const po: PendingOrder = {id: `PEND-${Date.now()}`, items: [...cart], subtotal, tax: taxAmount, total, waiterId: currentUser.id, waiterName: currentUser.name, timestamp: new Date()}; onAddPendingOrder(po); setCart([]); alert("Waa loo diray!");}} className="w-full bg-brand-secondary text-white py-4 rounded-2xl font-black uppercase text-xs tracking-[0.2em] shadow-lg">Diri Dalabka</button>
          )}
        </div>
      </div>

      {/* DYNAMIC RECEIPT MODAL */}
      {showReceipt && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 no-print">
          <div className="bg-white w-full max-w-[320px] rounded-3xl p-6 shadow-2xl animate-scaleIn">
            <div id="printable-receipt" className="font-mono text-[10px] text-gray-800 uppercase">
              <div className="flex flex-col items-center mb-6 text-center">
                 <div className="w-16 h-16 mb-2">
                   {config.logoUrl ? <img src={config.logoUrl} className="w-full h-full object-contain" /> : <DefaultLogoSVG />}
                 </div>
                 <h2 className="text-lg font-black tracking-tighter leading-none mb-1">{config.name}</h2>
                 <p className="text-[8px] opacity-70">{config.address}</p>
                 <p className="text-[8px] opacity-70">TEL: {config.phone}</p>
              </div>
              <div className="border-t border-dashed border-gray-300 py-3 space-y-1">
                 <div className="flex justify-between"><span>Date:</span><span>{new Date().toLocaleDateString()}</span></div>
                 <div className="flex justify-between"><span>Staff:</span><span>{currentUser.name}</span></div>
                 <div className="flex justify-between"><span>Order:</span><span>#{Date.now().toString().slice(-6)}</span></div>
              </div>
              <div className="border-t border-b border-dashed border-gray-300 py-3 my-2 space-y-1">
                 <div className="flex font-black border-b border-gray-100 pb-1 mb-1">
                   <span className="flex-1">Item</span><span className="w-6 text-center">Qty</span><span className="w-12 text-right">Amt</span>
                 </div>
                 {cart.map((i, idx) => (
                   <div key={idx} className="flex">
                     <span className="flex-1 truncate">{i.name}</span><span className="w-6 text-center">{i.quantity}</span><span className="w-12 text-right">{(i.price * i.quantity).toFixed(2)}</span>
                   </div>
                 ))}
              </div>
              <div className="space-y-1 font-black">
                 <div className="flex justify-between"><span>Subtotal:</span><span>{config.currencySymbol}{subtotal.toFixed(2)}</span></div>
                 {applyTax && <div className="flex justify-between"><span>Tax ({taxRate}%):</span><span>{config.currencySymbol}{taxAmount.toFixed(2)}</span></div>}
                 <div className="flex justify-between text-sm pt-2 border-t border-dotted border-gray-300"><span>TOTAL:</span><span>{config.currencySymbol}{total.toFixed(2)}</span></div>
              </div>
              <div className="text-center mt-8 space-y-2">
                 <p className="text-[8px] italic opacity-60">Mahadsanid, Soo dhawoow!</p>
                 <div className="flex justify-center gap-1 opacity-20">{[...Array(15)].map((_, i) => <div key={i} className="w-1 h-0.5 bg-black"></div>)}</div>
              </div>
            </div>
            <div className="mt-8 flex gap-3">
              <button onClick={() => setShowReceipt(false)} className="flex-1 py-3 bg-gray-100 text-gray-500 rounded-xl font-bold text-xs uppercase">Xir</button>
              <button onClick={() => window.print()} className="flex-1 py-3 bg-brand-primary text-white rounded-xl font-bold text-xs uppercase"><i className="fas fa-print mr-2"></i> Print</button>
            </div>
          </div>
        </div>
      )}

      {showCheckout && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 animate-scaleIn">
              <h3 className="text-3xl font-black text-brand-primary mb-8 text-center uppercase tracking-tight">Payment Method</h3>
              <div className="grid grid-cols-2 gap-4 mb-8">
                 {(['Cash', 'EVC Plus', 'E-Dahab', 'Card'] as const).map(m => (
                   <button key={m} onClick={() => setPaymentMethod(m)} className={`flex flex-col items-center gap-3 p-6 rounded-3xl border-2 transition-all ${paymentMethod === m ? 'border-brand-secondary bg-brand-secondary/5 text-brand-primary' : 'bg-gray-50 border-gray-50 text-gray-400'}`}>
                     <i className={`fas ${m === 'Cash' ? 'fa-money-bill-wave' : m === 'Card' ? 'fa-credit-card' : 'fa-mobile-alt'} text-2xl`}></i>
                     <span className="text-[10px] font-black uppercase tracking-widest">{m}</span>
                   </button>
                 ))}
              </div>
              <button onClick={handleCompleteSale} className="w-full bg-brand-primary text-white py-6 rounded-3xl font-black text-2xl shadow-2xl active:scale-95 transition-all">PAY {config.currencySymbol}{total.toFixed(2)}</button>
              <button onClick={() => setShowCheckout(false)} className="w-full mt-4 text-gray-400 font-bold text-sm uppercase">Ka Noqo (Cancel)</button>
           </div>
        </div>
      )}
    </div>
  );
};

