            <form onSubmit={handleUpdateTax} className={`space-y-6 transition-opacity duration-300 ${isTaxEnabled ? 'opacity-100' : 'opacity-40 pointer-events-none'}`}>
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">VAT Percentage (%)</label>
                <div className="relative">
                  <input
                    type="number" step="0.1" value={tempTax}
                    onChange={(e) => setTempTax(e.target.value)}
                    className="w-full pl-6 pr-12 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-lg"
                  />
                  <span className="absolute right-6 top-1/2 -translate-y-1/2 font-bold text-gray-400">%</span>
                </div>
              </div>
              <button type="submit" className="w-full py-4 bg-brand-secondary text-white rounded-2xl font-bold shadow-lg">Cusboonaysii VAT</button>
            </form>
          </div>

          {/* SYSTEM MAINTENANCE */}
          <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8">
            <div className="flex items-center gap-4 mb-8">
              <div className="w-12 h-12 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center">
                <i className="fas fa-database text-xl"></i>
              </div>
              <div>
                <h3 className="font-bold text-lg text-gray-800">System Maintenance</h3>
                <p className="text-sm text-gray-500">Nadiifinta xogta guud.</p>
              </div>
            </div>
            <div className="p-4 bg-red-50 rounded-2xl border border-red-100">
               <p className="text-xs text-red-600 font-medium mb-3">DIGNIIN: Tallaabadani waxay tirtiri doontaa dhammaan xogta (Orders & Products).</p>
               <button onClick={onResetData} className="w-full py-3 bg-white text-red-600 border border-red-200 rounded-xl font-bold text-sm hover:bg-red-600 hover:text-white transition-all">
                Reset Order & Product Data
              </button>
            </div>
          </div>
        </div>
      </div>

      {message && (
        <div className={`fixed bottom-8 right-8 p-4 rounded-2xl shadow-xl animate-fadeIn z-[200] ${message.type === 'success' ? 'bg-green-600 text-white' : 'bg-red-600 text-white'}`}>
          <i className="fas fa-check-circle mr-2"></i>
          {message.text}
        </div>
      )}
