  globalTaxEnabled: boolean;
  config: SystemConfig;
}

const DefaultLogoSVG = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-12 h-12 fill-brand-primary"}>
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const POS: React.FC<POSProps> = ({ products, onCompleteOrder, onAddPendingOrder, pendingOrders, currentUser, taxRate, globalTaxEnabled, config }) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [showReceipt, setShowReceipt] = useState(false);
  const [paymentStep, setPaymentStep] = useState<'Category' | 'Method'>('Category');
  const [paymentType, setPaymentType] = useState<'CashMobile' | 'Credit' | null>(null);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Cash');
  const [customerName, setCustomerName] = useState('');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);
  const [applyTax, setApplyTax] = useState(globalTaxEnabled);

  useEffect(() => {
    if (cart.length === 0) {
      setApplyTax(globalTaxEnabled);
      setCustomerName('');
      setPaymentStep('Category');
      setPaymentType(null);
    }
  }, [globalTaxEnabled, cart.length]);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);
  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const taxAmount = applyTax ? (subtotal * (taxRate / 100)) : 0;
  const total = subtotal + taxAmount;

  const filteredProducts = useMemo(() => 
    products.filter(p => (activeCategory === 'All' || p.category === activeCategory) && p.name.toLowerCase().includes(search.toLowerCase())),
    [activeCategory, search, products]
  );

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return alert("Waa ka dhammaatay!");
    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return (alert("Stock limit!"), prev);
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const handleSelectCategory = (category: 'CashMobile' | 'Credit') => {
    setPaymentType(category);
    if (category === 'Credit') {
      setPaymentMethod('Credit');
    }
    setPaymentStep('Method');
  };

  const handleCompleteSale = () => {
    if (paymentMethod === 'Credit' && !customerName) {
      alert("Fadlan geli magaca macmiilka si loogu diwaangeliyo Amaahda (Buugga).");
      return;
    }

    onCompleteOrder({
      id: `ORD-${Date.now()}`,
      items: [...cart], 
      subtotal, 
      tax: taxAmount, 
      total, 
      discount: 0, 
      paymentMethod, 
      timestamp: new Date(), 
      staffId: currentUser.id,
      customerName: customerName || undefined
    }, activePendingId || undefined);

    setCart([]); 
    setActivePendingId(null); 
    setShowCheckout(false); 
    setCustomerName('');
    setPaymentStep('Category');
    setPaymentType(null);
    alert("Lacag bixinta waa la diwaangeliyay!");
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {canProcessPayment && (
        <div className="w-72 bg-gray-50 border-r border-gray-200 flex flex-col no-print">
          <div className="p-4 border-b bg-white">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <i className="fas fa-clock text-brand-secondary"></i> Dalabyada Sugaya
            </h3>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {pendingOrders.map(po => (
              <button 
                key={po.id} onClick={() => {setCart(po.items); setActivePendingId(po.id); setApplyTax(po.tax > 0);}}
                className={`w-full text-left p-4 rounded-2xl border transition-all ${activePendingId === po.id ? 'bg-brand-primary border-brand-primary text-white shadow-lg' : 'bg-white border-gray-100 hover:border-brand-secondary'}`}
              >
                <div className="flex justify-between items-start mb-1 text-[10px] font-bold">
                  <span className="opacity-60">#{po.id.slice(-4)}</span>
                  <span>{new Date(po.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                </div>
                <p className="font-bold truncate text-sm">{po.waiterName}</p>
                <div className="flex justify-between items-center mt-2">
                  <span className="text-xs">{po.items.length} items</span>
                  <span className={`font-bold ${activePendingId === po.id ? 'text-brand-secondary' : 'text-brand-primary'}`}>{config.currencySymbol}{po.total.toFixed(2)}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="flex-1 flex flex-col p-6 gap-6 overflow-hidden no-print">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div className="relative w-72">
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" placeholder="Raadi alaab..." 
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-brand-secondary"
              value={search} onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-md">
            {CATEGORIES.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap ${activeCategory === cat ? 'bg-brand-secondary text-white shadow-md' : 'bg-gray-100 text-gray-600'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredProducts.map(product => (
            <button key={product.id} onClick={() => addToCart(product)} disabled={product.stock <= 0} className="bg-white p-3 rounded-2xl border border-gray-100 hover:shadow-xl transition-all flex flex-col text-left group">
              <img src={product.image} className="w-full h-28 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 text-sm truncate">{product.name}</h4>
              <div className="mt-auto flex justify-between items-center pt-2">
                <span className="text-brand-secondary font-black text-sm">{config.currencySymbol}{product.price.toFixed(2)}</span>
                <span className="text-[10px] text-gray-400 font-bold">Qty: {product.stock}</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="w-96 bg-white border-l border-gray-100 flex flex-col shadow-2xl no-print">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
          <div><h3 className="text-xl font-black text-brand-primary">Dambiisha</h3><p className="text-[9px] font-bold text-brand-secondary uppercase tracking-[0.2em]">Transaction Panel</p></div>
          <button onClick={() => { setCart([]); setActivePendingId(null); }} className="text-gray-400 hover:text-red-500 transition-colors"><i className="fas fa-trash-alt"></i></button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.map(item => (
            <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-2xl border border-transparent hover:border-brand-secondary/20 transition-all">
              <div className="flex-1"><h4 className="font-bold text-gray-800 text-sm truncate">{item.name}</h4><p className="text-xs text-brand-secondary font-black">{config.currencySymbol}{(item.price * item.quantity).toFixed(2)}</p></div>
              <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                 <button onClick={() => {setCart(prev => prev.map(i => i.productId === item.productId ? {...i, quantity: Math.max(0, i.quantity - 1)} : i).filter(i => i.quantity > 0))}} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">-</button>
                 <span className="text-xs font-black w-4 text-center">{item.quantity}</span>
                 <button onClick={() => addToCart(products.find(p => p.id === item.productId)!)} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">+</button>
              </div>
            </div>
          ))}
        </div>

        <div className="p-6 bg-gray-100/50 space-y-4 rounded-t-[2.5rem] shadow-[0_-10px_30px_-15px_rgba(0,0,0,0.1)]">
          <div className="space-y-2 text-sm font-medium">
            <div className="flex justify-between text-gray-500"><span>Subtotal</span><span>{config.currencySymbol}{subtotal.toFixed(2)}</span></div>
            <div className="flex justify-between items-center group cursor-pointer" onClick={() => setApplyTax(!applyTax)}>
              <span className={`flex items-center gap-2 ${applyTax ? 'text-brand-primary' : 'text-gray-400'}`}><i className={`fas ${applyTax ? 'fa-check-circle text-brand-secondary' : 'fa-circle text-gray-200'}`}></i> VAT ({taxRate}%)</span>
              <span className={applyTax ? 'font-bold' : 'text-gray-400'}>{config.currencySymbol}{taxAmount.toFixed(2)}</span>
            </div>
            <div className="flex justify-between pt-2 border-t border-gray-200"><span className="font-black text-lg text-brand-primary">Total</span><span className="text-2xl font-black text-brand-primary">{config.currencySymbol}{total.toFixed(2)}</span></div>
          </div>
          <button onClick={() => setShowReceipt(true)} className="w-full bg-white border-2 border-brand-secondary/20 text-brand-primary py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-sm hover:border-brand-secondary transition-all"><i className="fas fa-print mr-2"></i> Daabac Receipt</button>
          {canProcessPayment ? (
            <button onClick={() => setShowCheckout(true)} disabled={cart.length === 0} className="w-full bg-brand-primary text-white py-5 rounded-3xl font-black text-xl shadow-xl hover:opacity-95 transition-all">Bixi Bill-ka</button>
          ) : (
            <button onClick={() => {const po: PendingOrder = {id: `PEND-${Date.now()}`, items: [...cart], subtotal, tax: taxAmount, total, waiterId: currentUser.id, waiterName: currentUser.name, timestamp: new Date()}; onAddPendingOrder(po); setCart([]); alert("Waa loo diray!");}} className="w-full bg-brand-secondary text-white py-4 rounded-2xl font-black uppercase text-xs tracking-[0.2em] shadow-lg">Diri Dalabka</button>
          )}
        </div>
      </div>

      {/* DYNAMIC RECEIPT MODAL */}
      {showReceipt && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 no-print">
          <div className="bg-white w-full max-w-[320px] rounded-3xl p-6 shadow-2xl animate-scaleIn">
            <div id="printable-receipt" className="font-mono text-[10px] text-gray-800 uppercase">
              <div className="flex flex-col items-center mb-6 text-center">
                 <div className="w-16 h-16 mb-2">
                   {config.logoUrl ? <img src={config.logoUrl} className="w-full h-full object-contain" /> : <DefaultLogoSVG />}
                 </div>
                 <h2 className="text-lg font-black tracking-tighter leading-none mb-1">{config.name}</h2>
                 <p className="text-[8px] opacity-70 italic mb-1">{config.description}</p>
                 <p className="text-[8px] opacity-70">{config.address}</p>
                 <p className="text-[8px] opacity-70">TEL: {config.phone}</p>
              </div>
              <div className="border-t border-dashed border-gray-300 py-3 space-y-1">
                 <div className="flex justify-between"><span>Date:</span><span>{new Date().toLocaleDateString()}</span></div>
                 <div className="flex justify-between"><span>Staff:</span><span>{currentUser.name}</span></div>
                 <div className="flex justify-between"><span>Order:</span><span>#{Date.now().toString().slice(-6)}</span></div>
                 {customerName && <div className="flex justify-between font-black"><span>Customer:</span><span>{customerName}</span></div>}
              </div>
              <div className="border-t border-b border-dashed border-gray-300 py-3 my-2 space-y-1">
                 <div className="flex font-black border-b border-gray-100 pb-1 mb-1">
                   <span className="flex-1">Item</span><span className="w-6 text-center">Qty</span><span className="w-12 text-right">Amt</span>
                 </div>
                 {cart.map((i, idx) => (
                   <div key={idx} className="flex">
                     <span className="flex-1 truncate">{i.name}</span><span className="w-6 text-center">{i.quantity}</span><span className="w-12 text-right">{(i.price * i.quantity).toFixed(2)}</span>
                   </div>
                 ))}
              </div>
              <div className="space-y-1 font-black">
                 <div className="flex justify-between"><span>Subtotal:</span><span>{config.currencySymbol}{subtotal.toFixed(2)}</span></div>
                 {applyTax && <div className="flex justify-between"><span>Tax ({taxRate}%):</span><span>{config.currencySymbol}{taxAmount.toFixed(2)}</span></div>}
                 <div className="flex justify-between text-sm pt-2 border-t border-dotted border-gray-300"><span>TOTAL:</span><span>{config.currencySymbol}{total.toFixed(2)}</span></div>
                 <div className="flex justify-between pt-1 opacity-70 italic"><span>Method:</span><span>{paymentMethod}</span></div>
              </div>

              {/* Account Numbers on Receipt */}
              <div className="mt-4 p-2 bg-gray-50 border border-dashed border-gray-200 rounded text-center">
                <p className="text-[7px] font-bold text-gray-500 mb-1 uppercase">Merchant / Payment Accounts</p>
                <p className="text-[9px] font-black">{config.accountNumbers}</p>
              </div>

              <div className="text-center mt-6 space-y-2">
                 <p className="text-[8px] italic opacity-60">Mahadsanid, Soo dhawoow!</p>
                 <div className="flex justify-center gap-1 opacity-20">{[...Array(15)].map((_, i) => <div key={i} className="w-1 h-0.5 bg-black"></div>)}</div>
              </div>
            </div>
            <div className="mt-8 flex gap-3">
              <button onClick={() => setShowReceipt(false)} className="flex-1 py-3 bg-gray-100 text-gray-500 rounded-xl font-bold text-xs uppercase">Xir</button>
              <button onClick={() => window.print()} className="flex-1 py-3 bg-brand-primary text-white rounded-xl font-bold text-xs uppercase"><i className="fas fa-print mr-2"></i> Print</button>
            </div>
          </div>
        </div>
      )}

      {/* CHECKOUT MODAL - REWORKED FOR 2-STEP SOMALI PAYMENT FLOW */}
      {showCheckout && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-xl rounded-[2.5rem] p-8 md:p-12 animate-scaleIn shadow-2xl relative">

              {/* Header */}
              <div className="flex justify-between items-start mb-8">
                 <div className="text-left">
                    <h3 className="text-3xl font-black text-brand-primary uppercase tracking-tight">
                      {paymentStep === 'Category' ? 'Nooca Lacag bixinta' : 'Xulo Adeegga'}
                    </h3>
                    <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">Wadarta: {config.currencySymbol}{total.toFixed(2)}</p>
                 </div>
                 <button onClick={() => setShowCheckout(false)} className="w-10 h-10 bg-gray-100 rounded-xl flex items-center justify-center text-gray-400 hover:text-red-500 transition-all">
                    <i className="fas fa-times"></i>
                 </button>
              </div>

              {/* Step 1: Payment Category Selection */}
              {paymentStep === 'Category' && (
                <div className="grid grid-cols-1 gap-6 animate-fadeIn">
                  <button 
                    onClick={() => handleSelectCategory('CashMobile')}
                    className="flex items-center gap-6 p-8 bg-gray-50 rounded-[2rem] border-4 border-transparent hover:border-brand-secondary hover:bg-white transition-all group"
                  >
                    <div className="w-20 h-20 bg-green-500 rounded-3xl flex items-center justify-center text-white text-3xl shadow-xl group-hover:scale-110 transition-transform">
                      <i className="fas fa-money-bill-transfer"></i>
                    </div>
                    <div className="text-left">
                      <h4 className="text-2xl font-black text-gray-800">Cadaan / Mobile</h4>
                      <p className="text-sm text-gray-400 font-bold uppercase tracking-widest">EVC, Dahab, Merchant Code</p>
                    </div>
                    <i className="fas fa-chevron-right ml-auto text-gray-300"></i>
                  </button>

                  <button 
                    onClick={() => handleSelectCategory('Credit')}
                    className="flex items-center gap-6 p-8 bg-gray-50 rounded-[2rem] border-4 border-transparent hover:border-red-500 hover:bg-white transition-all group"
                  >
                    <div className="w-20 h-20 bg-red-500 rounded-3xl flex items-center justify-center text-white text-3xl shadow-xl group-hover:scale-110 transition-transform">
                      <i className="fas fa-book"></i>
                    </div>
                    <div className="text-left">
                      <h4 className="text-2xl font-black text-gray-800">Amaah (Credit)</h4>
                      <p className="text-sm text-gray-400 font-bold uppercase tracking-widest">Deyn / Ku qor Buugga</p>
                    </div>
                    <i className="fas fa-chevron-right ml-auto text-gray-300"></i>
                  </button>
                </div>
              )}

              {/* Step 2: Specific Method Selection */}
              {paymentStep === 'Method' && (
                <div className="animate-fadeIn space-y-8">
                  <button 
                    onClick={() => setPaymentStep('Category')}
                    className="text-xs font-black text-gray-400 uppercase tracking-widest hover:text-brand-primary flex items-center gap-2"
                  >
                    <i className="fas fa-arrow-left"></i> Ka noqo category-ga
                  </button>

                  {paymentType === 'CashMobile' ? (
                    <>
                      <div className="p-4 bg-brand-secondary/10 rounded-2xl border border-brand-secondary/30 text-center">
                        <p className="text-[10px] font-black text-brand-primary uppercase tracking-widest mb-1">Payment Accounts</p>
                        <p className="text-sm font-bold text-brand-primary">{config.accountNumbers}</p>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                        {[
                          { id: 'Cash', icon: 'fa-money-bill-wave', label: 'Cash', color: 'bg-green-500' },
                          { id: 'EVC Plus', icon: 'fa-mobile-screen-button', label: 'EVC Plus', color: 'bg-blue-600' },
                          { id: 'E-Dahab', icon: 'fa-wallet', label: 'E-Dahab', color: 'bg-orange-500' },
                          { id: 'Merchant', icon: 'fa-building-columns', label: 'Merchant', color: 'bg-purple-600' }
                        ].map(m => (
                          <button 
                            key={m.id} 
                            onClick={() => setPaymentMethod(m.id as PaymentMethod)} 
                            className={`flex flex-col items-center gap-3 p-5 rounded-3xl border-2 transition-all group ${paymentMethod === m.id ? 'border-brand-secondary bg-brand-secondary/5 text-brand-primary scale-105 shadow-md' : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'}`}
                          >
                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-lg transition-transform group-hover:scale-110 ${m.color}`}>
                              <i className={`fas ${m.icon} text-lg`}></i>
                            </div>
                            <span className="text-[10px] font-black uppercase tracking-widest">{m.label}</span>
                          </button>
                        ))}
                      </div>
                    </>
                  ) : (
                    <div className="bg-red-50 p-6 rounded-3xl border border-red-100 text-center space-y-4">
                       <i className="fas fa-user-edit text-4xl text-red-500"></i>
                       <h4 className="text-xl font-black text-red-600">Diiwaanka Amaahda</h4>
                       <p className="text-xs text-red-400 font-bold uppercase tracking-widest">Geli Magaca Macmiilka hoos</p>
                    </div>
                  )}

                  <div className="space-y-2">
                     <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">
                       {paymentType === 'Credit' ? 'Magaca Macmiilka (Required)' : 'Reference / Macmiil (Optional)'}
                     </label>
                     <input 
                      type="text" 
                      placeholder={paymentType === 'Credit' ? "Tusaale: Ahmed Cali" : "Magaca ama xog kale..."}
                      value={customerName}
                      onChange={(e) => setCustomerName(e.target.value)}
                      className="w-full px-6 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-center text-xl"
                     />
                  </div>

                  <button 
                    onClick={handleCompleteSale} 
                    className="w-full bg-brand-primary text-white py-6 rounded-3xl font-black text-2xl shadow-2xl active:scale-95 transition-all hover:bg-black"
                  >
                    Xaqiiji {config.currencySymbol}{total.toFixed(2)}
                  </button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default POS;

export enum UserRole {
  ADMIN = 'Admin',
  MANAGER = 'Manager',
  WAITER = 'Waiter',
  CASHIER = 'Cashier',
  STORE_KEEPER = 'Store Keeper'
}

export type View = 'DASHBOARD' | 'POS' | 'INVENTORY' | 'STAFF' | 'REPORTS' | 'FINANCE' | 'SETTINGS';

export interface SystemConfig {
  name: string;
  description: string;
  primaryColor: string;
  secondaryColor: string;
  logoUrl: string;
  loginBgUrl: string;
  appBgUrl: string; // Added for main app background control
  currencySymbol: string;
  address: string;
  phone: string;
  accountNumbers: string;
  enabledModules: View[]; // Tracks which views are "Open" or "Closed"
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  stock: number;
  image: string;
  minStock: number;
}

export interface OrderItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
}

export type PaymentMethod = 'Cash' | 'EVC Plus' | 'E-Dahab' | 'Merchant' | 'Card' | 'Credit';

export interface Order {
  id: string;
  items: OrderItem[];
  subtotal: number;
  tax: number;
  total: number;
  discount: number;
  paymentMethod: PaymentMethod;
  timestamp: Date;
  staffId: string;
  customerName?: string;
}

export interface PendingOrder {
  id: string;
  items: OrderItem[];
  subtotal: number;
  tax: number;
  total: number;
  waiterId: string;
  waiterName: string;
  timestamp: Date;
  tableNumber?: string;
}

export interface Expense {
  id: string;
  title: string;
  amount: number;
  category: string;
  date: string;
}

export interface StaffMember {
  id: string;
  name: string;
  role: UserRole;
  phone: string;
  joinDate: string;
  status: 'Active' | 'On Leave' | 'Inactive';
  pin: string;
}

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import Inventory from './components/Inventory';
import Staff from './components/Staff';
import Finance from './components/Finance';
import Settings from './components/Settings';
import Login from './components/Login';
import { View, UserRole, Product, StaffMember, Order, Expense, PendingOrder, SystemConfig } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';

const DEFAULT_CONFIG: SystemConfig = {
  name: 'Koob Coffee',
  description: 'The Best Coffee & Snacks Experience in Mogadishu.',
  primaryColor: '#3d2b1f',
  secondaryColor: '#c6a07d',
  logoUrl: '', 
  loginBgUrl: 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&q=80',
  appBgUrl: '',
  currencySymbol: '$',
  address: 'Mogadishu, Somalia',
  phone: '+252 61 XXX XXXX',
  accountNumbers: 'EVC: 61XXXX, Dahab: 12345',
  enabledModules: ['DASHBOARD', 'POS', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS']
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  const [systemConfig, setSystemConfig] = useState<SystemConfig>(() => {
    const saved = localStorage.getItem('koob_system_config');
    const parsed = saved ? JSON.parse(saved) : DEFAULT_CONFIG;
    // Ensure all required fields exist for legacy data
    return { ...DEFAULT_CONFIG, ...parsed };
  });

  useEffect(() => {
    document.documentElement.style.setProperty('--brand-primary', systemConfig.primaryColor);
    document.documentElement.style.setProperty('--brand-secondary', systemConfig.secondaryColor);
    localStorage.setItem('koob_system_config', JSON.stringify(systemConfig));
  }, [systemConfig]);

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('koob_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [staff, setStaff] = useState<StaffMember[]>(() => {
    const saved = localStorage.getItem('koob_staff');
    return saved ? JSON.parse(saved) : INITIAL_STAFF;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('koob_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>(() => {
    const saved = localStorage.getItem('koob_pending_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('koob_expenses');
    return saved ? JSON.parse(saved) : MOCK_EXPENSES;
  });

  const [taxRate, setTaxRate] = useState<number>(() => {
    const saved = localStorage.getItem('koob_tax_rate');
    return saved ? JSON.parse(saved) : 5;
  });

  const [isTaxEnabled, setIsTaxEnabled] = useState<boolean>(() => {
    const saved = localStorage.getItem('koob_is_tax_enabled');
    return saved ? JSON.parse(saved) : true;
  });

  useEffect(() => localStorage.setItem('koob_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('koob_staff', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('koob_orders', JSON.stringify(orders)), [orders]);
  useEffect(() => localStorage.setItem('koob_pending_orders', JSON.stringify(pendingOrders)), [pendingOrders]);
  useEffect(() => localStorage.setItem('koob_expenses', JSON.stringify(expenses)), [expenses]);
  useEffect(() => localStorage.setItem('koob_tax_rate', JSON.stringify(taxRate)), [taxRate]);
  useEffect(() => localStorage.setItem('koob_is_tax_enabled', JSON.stringify(isTaxEnabled)), [isTaxEnabled]);

  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
    if (matchedStaff.role === UserRole.WAITER || matchedStaff.role === UserRole.CASHIER) {
      setCurrentView('POS');
    } else {
      setCurrentView('DASHBOARD');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const handleCompleteOrder = (order: Order, pendingOrderId?: string) => {
    setOrders(prev => [order, ...prev]);
    setProducts(prev => prev.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) return { ...p, stock: p.stock - itemInOrder.quantity };
      return p;
    }));
    if (pendingOrderId) {
      setPendingOrders(prev => prev.filter(po => po.id !== pendingOrderId));
    }
  };

  const renderView = () => {
    if (!currentUser) return null;

    // Safety check: if view is disabled, redirect to dashboard
    if (currentView !== 'SETTINGS' && currentView !== 'DASHBOARD' && !systemConfig.enabledModules.includes(currentView)) {
        return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
    }

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
      case 'POS': return (
        <POS 
          products={products} 
          onCompleteOrder={handleCompleteOrder} 
          onAddPendingOrder={(po) => setPendingOrders(prev => [po, ...prev])}
          pendingOrders={pendingOrders}
          currentUser={currentUser}
          taxRate={taxRate}
          globalTaxEnabled={isTaxEnabled}
          config={systemConfig}
        />
      );
      case 'INVENTORY': return (
        <Inventory 
          products={products} 
          onAddProduct={(p) => setProducts(prev => [p, ...prev])} 
          onUpdateProduct={(u) => setProducts(prev => prev.map(p => p.id === u.id ? u : p))}
          onDeleteProduct={(id) => confirm("Ma hubtaa?") && setProducts(prev => prev.filter(p => p.id !== id))}
          currentUser={currentUser}
        />
      );
      case 'STAFF': return (
        <Staff 
          staff={staff} 
          onAddStaff={(s) => setStaff(prev => [s, ...prev])} 
          onUpdateStaff={(u) => setStaff(prev => prev.map(s => s.id === u.id ? u : s))} 
          onDeleteStaff={(id) => setStaff(prev => prev.filter(s => s.id !== id))}
          currentUser={currentUser} 
        />
      );
      case 'FINANCE': return <Finance orders={orders} expenses={expenses} onAddExpense={(e) => setExpenses(prev => [e, ...prev])} />;
      case 'SETTINGS': return (
        <Settings 
          taxRate={taxRate} 
          onUpdateTaxRate={setTaxRate}
          isTaxEnabled={isTaxEnabled}
          onToggleTax={setIsTaxEnabled}
          systemConfig={systemConfig}
          onUpdateConfig={setSystemConfig}
          onResetData={() => { localStorage.clear(); window.location.reload(); }}
        />
      );
      case 'REPORTS': 
        return (
          <div className="p-8">
            <h2 className="text-2xl font-bold mb-6 text-gray-800">Order Reports</h2>
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
               <table className="w-full text-left">
                  <thead className="bg-gray-50 text-xs font-bold uppercase text-gray-500">
                    <tr>
                      <th className="px-6 py-4">ID</th>
                      <th className="px-6 py-4">Items</th>
                      <th className="px-6 py-4">Tax</th>
                      <th className="px-6 py-4">Total</th>
                      <th className="px-6 py-4">Staff</th>
                      <th className="px-6 py-4">Date</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {orders.map(o => (
                      <tr key={o.id} className="hover:bg-gray-50">
                        <td className="px-6 py-4 font-mono text-xs">{o.id}</td>
                        <td className="px-6 py-4 text-sm">{o.items.map(i => `${i.quantity}x ${i.name}`).join(', ')}</td>
                        <td className="px-6 py-4 text-sm">{systemConfig.currencySymbol}{o.tax.toFixed(2)}</td>
                        <td className="px-6 py-4 font-bold">{systemConfig.currencySymbol}{o.total.toFixed(2)}</td>
                        <td className="px-6 py-4 text-sm">{staff.find(s => s.id === o.staffId)?.name || 'Unknown'}</td>
                        <td className="px-6 py-4 text-xs text-gray-400">{new Date(o.timestamp).toLocaleString()}</td>
                      </tr>
                    ))}
                  </tbody>
               </table>
            </div>
          </div>
        );
      default: return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} config={systemConfig} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50 relative overflow-hidden">
      {/* Global Background Control */}
      {systemConfig.appBgUrl && (
        <div className="absolute inset-0 z-0 opacity-5 pointer-events-none">
          <img src={systemConfig.appBgUrl} className="w-full h-full object-cover" alt="" />
        </div>
      )}

      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        userRole={currentUser.role} 
        currentUser={currentUser} 
        config={systemConfig} 
      />

      <main className="flex-1 overflow-y-auto relative z-10">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between">
          <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">{currentView.replace('_', ' ')}</h2>
          <div className="flex items-center gap-6">
            <button onClick={handleLogout} className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2">
              <i className="fas fa-sign-out-alt"></i> Logout
            </button>
            <div className="h-8 w-[1px] bg-gray-200"></div>
            <div className="flex items-center gap-2">
               <div className="text-right hidden sm:block">
                  <p className="text-sm font-bold text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] text-brand-secondary uppercase font-bold tracking-widest">{currentUser.role}</p>
               </div>
               <div className="w-10 h-10 bg-brand-primary rounded-xl flex items-center justify-center text-white shadow-lg border border-white/20">
                  <i className="fas fa-user-check"></i>
               </div>
            </div>
          </div>
        </header>
        <div className="animate-fadeIn">
          {renderView()}
        </div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        :root {
          --brand-primary: ${systemConfig.primaryColor};
          --brand-secondary: ${systemConfig.secondaryColor};
        }
        .bg-brand-primary { background-color: var(--brand-primary); }
        .bg-brand-secondary { background-color: var(--brand-secondary); }
        .text-brand-primary { color: var(--brand-primary); }
        .text-brand-secondary { color: var(--brand-secondary); }
        .border-brand-primary { border-color: var(--brand-primary); }
        .border-brand-secondary { border-color: var(--brand-secondary); }
        .ring-brand-secondary:focus { --tw-ring-color: var(--brand-secondary); }

        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scaleIn { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}} />
    </div>
  );
};

export default App;

import React from 'react';
import { View, UserRole, StaffMember, SystemConfig } from '../types';

interface SidebarProps {
  currentView: View;
  setView: (view: View) => void;
  userRole: UserRole;
  currentUser: StaffMember;
  config: SystemConfig;
}

const DefaultLogo = () => (
  <svg viewBox="0 0 100 100" className="w-10 h-10 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Sidebar: React.FC<SidebarProps> = ({ currentView, setView, userRole, currentUser, config }) => {
  const menuItems = [
    { id: 'DASHBOARD' as View, icon: 'fa-gauge', label: 'Dashboard', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'POS' as View, icon: 'fa-cash-register', label: 'POS (Iibka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER, UserRole.WAITER] },
    { id: 'INVENTORY' as View, icon: 'fa-boxes-stacked', label: 'Inventory (Kaydka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.STORE_KEEPER] },
    { id: 'STAFF' as View, icon: 'fa-users-gear', label: 'Staff (Shaqaalaha)', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'REPORTS' as View, icon: 'fa-chart-line', label: 'Reports', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'FINANCE' as View, icon: 'fa-money-bill-trend-up', label: 'Finance', roles: [UserRole.ADMIN] },
    { id: 'SETTINGS' as View, icon: 'fa-cog', label: 'Settings', roles: [UserRole.ADMIN] },
  ];

  // Filter by user role AND system module enablement
  const allowedItems = menuItems.filter(item => {
    const isRoleAllowed = item.roles.includes(userRole);
    const isModuleEnabled = item.id === 'SETTINGS' || item.id === 'DASHBOARD' || config.enabledModules.includes(item.id);
    return isRoleAllowed && isModuleEnabled;
  });

  return (
    <div className="w-64 bg-brand-primary text-white flex flex-col min-h-screen sticky top-0 shadow-2xl z-40">
      <div className="p-6 flex items-center gap-3 border-b border-white/10">
        <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-lg transform -rotate-3 border border-brand-secondary/30 overflow-hidden shrink-0">
          {config.logoUrl ? (
            <img src={config.logoUrl} className="w-full h-full object-cover" alt="Logo" />
          ) : (
            <DefaultLogo />
          )}
        </div>
        <h1 className="text-xl font-playfair tracking-wide uppercase font-black text-white truncate flex-1">{config.name}</h1>
      </div>

      <nav className="flex-1 mt-6 px-4 space-y-1 overflow-y-auto no-scrollbar">
        {allowedItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setView(item.id)}
            className={`w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all duration-300 ${
              currentView === item.id 
                ? 'bg-brand-secondary text-white shadow-xl scale-105' 
                : 'text-white/50 hover:bg-white/10 hover:text-white'
            }`}
          >
            <div className={`w-8 h-8 rounded-xl flex items-center justify-center transition-colors ${currentView === item.id ? 'bg-white/20' : 'bg-transparent'}`}>
              <i className={`fas ${item.icon} text-sm`}></i>
            </div>
            <span className="font-bold text-xs uppercase tracking-widest">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-white/10">
        <div className="flex items-center gap-3 p-3 bg-white/10 rounded-2xl border border-white/5 backdrop-blur-sm">
          <img src={`https://i.pravatar.cc/150?u=${currentUser.id}`} alt="Avatar" className="w-10 h-10 rounded-xl bg-white/20" />
          <div className="overflow-hidden">
            <p className="text-sm font-bold truncate">{currentUser.name}</p>
            <div className="flex items-center gap-1.5">
               <span className="w-1.5 h-1.5 rounded-full bg-green-400"></span>
               <p className="text-[9px] text-white/50 uppercase font-bold tracking-wider">{currentUser.role}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { SystemConfig, View } from '../types';

interface SettingsProps {
  taxRate: number;
  onUpdateTaxRate: (rate: number) => void;
  isTaxEnabled: boolean;
  onToggleTax: (enabled: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateConfig: (config: SystemConfig) => void;
  onResetData: () => void;
}

const Settings: React.FC<SettingsProps> = ({ 
  taxRate, onUpdateTaxRate, isTaxEnabled, onToggleTax, 
  systemConfig, onUpdateConfig, onResetData 
}) => {
  const [tempTax, setTempTax] = useState(taxRate.toString());
  const [tempConfig, setTempConfig] = useState<SystemConfig>(systemConfig);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);

  const handleUpdateTax = (e: React.FormEvent) => {
    e.preventDefault();
    const rate = parseFloat(tempTax);
    if (isNaN(rate) || rate < 0 || rate > 100) {
      setMessage({ text: 'Fadlan geli boqolley sax ah.', type: 'error' });
      return;
    }
    onUpdateTaxRate(rate);
    setMessage({ text: 'Canshuurta waa la keydiyay!', type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleUpdateBranding = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateConfig(tempConfig);
    setMessage({ text: 'Habaynta nidaamka waa la cusboonaysiiyay!', type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const toggleModule = (module: View) => {
    setTempConfig(prev => {
      const isEnabled = prev.enabledModules.includes(module);
      const newModules = isEnabled 
        ? prev.enabledModules.filter(m => m !== module)
        : [...prev.enabledModules, module];
      return { ...prev, enabledModules: newModules };
    });
  };

  return (
    <div className="p-8 max-w-6xl mx-auto space-y-8 animate-fadeIn pb-20">
      <div className="mb-8">
        <h2 className="text-3xl font-black text-gray-800">Master Control Panel</h2>
        <p className="text-gray-500 font-medium">Halkan ka maamul nidaamka oo dhan (Open/Close modules and update branding).</p>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">

        {/* SECTION 1: SYSTEM CONTROLS (OPEN/CLOSE MODULES) */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-100 text-orange-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-toggle-on text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Nidaamka Maamulka (System Control)</h3>
              <p className="text-sm text-gray-500">Xer ama Fur qeybaha nidaamka.</p>
            </div>
          </div>

          <div className="space-y-4">
            {[
              { id: 'POS' as View, label: 'POS Service (Iibka)', icon: 'fa-cash-register' },
              { id: 'INVENTORY' as View, label: 'Inventory (Kaydka)', icon: 'fa-boxes-stacked' },
              { id: 'STAFF' as View, label: 'Staff (Shaqaalaha)', icon: 'fa-users-gear' },
              { id: 'FINANCE' as View, label: 'Finance (Lacagta)', icon: 'fa-money-bill-trend-up' },
              { id: 'REPORTS' as View, label: 'Reports (Warbixin)', icon: 'fa-chart-line' },
            ].map(module => (
              <div key={module.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl border border-transparent hover:border-gray-200 transition-all">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${tempConfig.enabledModules.includes(module.id) ? 'bg-brand-secondary text-white' : 'bg-gray-200 text-gray-400'}`}>
                    <i className={`fas ${module.icon} text-sm`}></i>
                  </div>
                  <span className="font-bold text-gray-700">{module.label}</span>
                </div>
                <button 
                  onClick={() => toggleModule(module.id)}
                  className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    tempConfig.enabledModules.includes(module.id) 
                      ? 'bg-green-100 text-green-600' 
                      : 'bg-red-100 text-red-600'
                  }`}
                >
                  {tempConfig.enabledModules.includes(module.id) ? 'Open (Furan)' : 'Closed (Xiran)'}
                </button>
              </div>
            ))}
            <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 mt-4">
               <p className="text-[10px] text-blue-600 font-bold uppercase">Note: Dashboard and Settings cannot be closed.</p>
