                placeholder="https://example.com/bg.png"
                className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-medium text-sm" 
              />
            </div>

            <div className="md:col-span-2 flex gap-4 pt-4 border-t border-gray-50">
              <div className="flex-1 space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Currency</label>
                <input 
                  value={tempConfig.currencySymbol} 
                  onChange={e => setTempConfig({...tempConfig, currencySymbol: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl text-center font-bold" 
                />
              </div>
              <div className="flex-[3] space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Phone Number</label>
                <input 
                  value={tempConfig.phone} 
                  onChange={e => setTempConfig({...tempConfig, phone: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl font-bold" 
                />
              </div>
            </div>

            <button type="submit" className="md:col-span-2 w-full py-5 bg-brand-primary text-white rounded-3xl font-black text-lg shadow-xl hover:opacity-90 transition-all">
              Update Identity
            </button>
          </form>
        </div>

        {/* SECTION 3: VAT & TAX */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center">
                  <i className="fas fa-percent text-xl"></i>
                </div>
                <div>
                  <h3 className="font-bold text-lg text-gray-800">VAT Settings</h3>
                  <p className="text-sm text-gray-500">Canshuurta iyo biilasha.</p>
                </div>
              </div>
              <button 
