import React from 'react';
import { View, UserRole, StaffMember, SystemConfig } from '../types';

interface SidebarProps {
  currentView: View;
  setView: (view: View) => void;
  userRole: UserRole;
  currentUser: StaffMember;
  config: SystemConfig;
}

const DefaultLogo = () => (
  <svg viewBox="0 0 100 100" className="w-10 h-10 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Sidebar: React.FC<SidebarProps> = ({ currentView, setView, userRole, currentUser, config }) => {
  const menuItems = [
    { id: 'DASHBOARD' as View, icon: 'fa-gauge', label: 'Dashboard', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'POS' as View, icon: 'fa-cash-register', label: 'POS (Iibka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER, UserRole.WAITER] },
    { id: 'INVENTORY' as View, icon: 'fa-boxes-stacked', label: 'Inventory (Kaydka)', roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.STORE_KEEPER] },
    { id: 'STAFF' as View, icon: 'fa-users-gear', label: 'Staff (Shaqaalaha)', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'REPORTS' as View, icon: 'fa-chart-line', label: 'Reports', roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { id: 'FINANCE' as View, icon: 'fa-money-bill-trend-up', label: 'Finance', roles: [UserRole.ADMIN] },
    { id: 'SETTINGS' as View, icon: 'fa-cog', label: 'Settings', roles: [UserRole.ADMIN] },
