<content>
import React, { useState, useRef } from 'react';
import { SystemConfig, View } from '../types';

interface SettingsProps {
  taxRate: number;
  onUpdateTaxRate: (rate: number) => void;
  isTaxEnabled: boolean;
  onToggleTax: (enabled: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateConfig: (config: SystemConfig) => void;
  onResetData: () => void;
}

const DefaultLogoSVG = () => (
  <svg viewBox="0 0 100 100" className="w-12 h-12 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Settings: React.FC<SettingsProps> = ({ 
  taxRate, onUpdateTaxRate, isTaxEnabled, onToggleTax, 
  systemConfig, onUpdateConfig, onResetData 
}) => {
  const [tempTax, setTempTax] = useState(taxRate.toString());
  const [tempConfig, setTempConfig] = useState<SystemConfig>(systemConfig);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleUpdateTax = (e: React.FormEvent) => {
    e.preventDefault();
    const rate = parseFloat(tempTax);
    if (isNaN(rate) || rate < 0 || rate > 100) {
      setMessage({ text: 'Fadlan geli boqolley sax ah.', type: 'error' });
      return;
    }
    onUpdateTaxRate(rate);
    setMessage({ text: 'Canshuurta waa la keydiyay!', type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleUpdateBranding = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateConfig(tempConfig);
    setMessage({ text: 'Habaynta nidaamka waa la cusboonaysiiyay!', type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const toggleModule = (module: View) => {
    setTempConfig(prev => {
      const isEnabled = prev.enabledModules.includes(module);
      const newModules = isEnabled 
        ? prev.enabledModules.filter(m => m !== module)
        : [...prev.enabledModules, module];
      return { ...prev, enabledModules: newModules };
    });
  };

  const handleClearLogo = () => {
    setTempConfig({ ...tempConfig, logoUrl: '' });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) { // 2MB Limit
        setMessage({ text: 'Sawirku aad buu u weyn yahay (Max 2MB).', type: 'error' });
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempConfig({ ...tempConfig, logoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="p-8 max-w-6xl mx-auto space-y-8 animate-fadeIn pb-20">
      <div className="mb-8">
        <h2 className="text-3xl font-black text-gray-800">Maamulka Guud (Settings)</h2>
        <p className="text-gray-500 font-medium">Halkan ka maamul nidaamka, Bedelka Logo-da (Sawir ama URL), midabada, iyo qaybaha furan.</p>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">

        {/* SECTION 1: SYSTEM CONTROLS (OPEN/CLOSE MODULES) */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-100 text-orange-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-toggle-on text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Nidaamka Maamulka (Module Control)</h3>
              <p className="text-sm text-gray-500">Xer ama Fur qeybaha nidaamka.</p>
            </div>
          </div>

          <div className="space-y-4">
            {[
              { id: 'POS' as View, label: 'POS Service (Iibka)', icon: 'fa-cash-register' },
              { id: 'INVENTORY' as View, label: 'Inventory (Kaydka)', icon: 'fa-boxes-stacked' },
              { id: 'STAFF' as View, label: 'Staff (Shaqaalaha)', icon: 'fa-users-gear' },
              { id: 'FINANCE' as View, label: 'Finance (Lacagta)', icon: 'fa-money-bill-trend-up' },
              { id: 'REPORTS' as View, label: 'Reports (Warbixin)', icon: 'fa-chart-line' },
            ].map(module => (
              <div key={module.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl border border-transparent hover:border-gray-200 transition-all">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${tempConfig.enabledModules.includes(module.id) ? 'bg-brand-secondary text-white' : 'bg-gray-200 text-gray-400'}`}>
                    <i className={`fas ${module.icon} text-sm`}></i>
                  </div>
                  <span className="font-bold text-gray-700">{module.label}</span>
                </div>
                <button 
                  onClick={() => toggleModule(module.id)}
                  className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    tempConfig.enabledModules.includes(module.id) 
                      ? 'bg-green-100 text-green-600' 
                      : 'bg-red-100 text-red-600'
                  }`}
                >
                  {tempConfig.enabledModules.includes(module.id) ? 'Open (Furan)' : 'Closed (Xiran)'}
                </button>
              </div>
            ))}
          </div>
          <button onClick={handleUpdateBranding} className="w-full py-4 bg-brand-primary text-white rounded-2xl font-black shadow-lg">Keydi Maamulka Qaybaha</button>
        </div>

        {/* SECTION 2: BRANDING & LOGO */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-purple-100 text-purple-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-palette text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Bedelka Logo-da iyo Aqoonsiga</h3>
              <p className="text-sm text-gray-500">Muuqaalka, Logo-da (Sawir ama URL), iyo midabada ganacsiga.</p>
            </div>
          </div>

          <form onSubmit={handleUpdateBranding} className="space-y-6">
            {/* Logo Management Area */}
            <div className="p-6 bg-gray-50 rounded-[2rem] border border-gray-100 flex flex-col items-center gap-6">
              <div className="text-center">
                 <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Halkan ka arag Logo-daada</p>
                 <div className="w-32 h-32 bg-white rounded-[2rem] shadow-xl border-4 border-brand-secondary/20 overflow-hidden flex items-center justify-center group relative">
                    {tempConfig.logoUrl ? (
                      <img src={tempConfig.logoUrl} className="w-full h-full object-cover" alt="Logo Preview" onError={() => setMessage({text: "Logo-ka ma shaqeynayo!", type: 'error'})} />
                    ) : (
                      <DefaultLogoSVG />
                    )}
                    <button 
                      type="button" 
                      onClick={() => fileInputRef.current?.click()}
                      className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center text-white transition-opacity"
                    >
                      <i className="fas fa-camera text-2xl"></i>
                    </button>
                 </div>
              </div>

              <div className="w-full space-y-4">
                <div className="space-y-2">
                  <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Dooro Qaabka (Choose Method)</label>
                  <div className="flex gap-2">
                    <button 
                      type="button"
                      onClick={() => fileInputRef.current?.click()}
                      className="flex-1 px-4 py-4 bg-brand-secondary/10 border border-brand-secondary/20 rounded-2xl text-brand-primary font-bold text-sm hover:bg-brand-secondary/20 transition-all flex items-center justify-center gap-2"
                    >
                      <i className="fas fa-upload"></i> Soo geli Sawir
                    </button>
                    <input 
                      type="file" 
                      ref={fileInputRef} 
