import { GoogleGenAI } from "@google/genai";

export const getBusinessInsights = async (salesData: any, inventoryData: any) => {
  // Always use process.env.API_KEY directly as a named parameter in the constructor.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Maamulaha ganacsiga "Koob Coffee" waxaan u baahanahay talo ku saabsan ganacsiga.
    Halkan waa xogta iibka ee hadda: ${JSON.stringify(salesData)}
    Halkan waa xogta kaydka (inventory): ${JSON.stringify(inventoryData)}

    Fadlan i sii 3 dhibcood oo muhiim ah oo ku saabsan sida aan u horumarin karno iibka ama aan u badbaadin karno kharashka. 
    U soo qor af-Soomaali fudud oo ganacsi ku dheehan yahay.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    if (!response || !response.text) {
      return "AI-gu wax jawaab ah ma soo bixin. Fadlan mar kale isku day.";
    }

    return response.text;
  } catch (error: any) {
    console.error("Gemini Error:", error);

    // Handle Quota Exceeded (429) specifically
    const errorString = JSON.stringify(error).toUpperCase();
    if (errorString.includes("429") || errorString.includes("RESOURCE_EXHAUSTED") || errorString.includes("QUOTA")) {
      return "Nidaamka AI-ga wuxuu gaaray xadkiisii (Quota/Limit). Fadlan sug waxyar ama hubi qorshahaaga Google AI Studio si aad u sii waddo isticmaalka.";
    }

    return "Raalli ahow, hadda ma awoodo inaan bixiyo faallooyinka AI sababo farsamo awgeed. Fadlan mar kale isku day waxyar ka dib.";
  }
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { getBusinessInsights } from '../services/geminiService';
import { Product, Order } from '../types';

interface DashboardProps {
  products: Product[];
  orders: Order[];
  systemName: string;
}

const Dashboard: React.FC<DashboardProps> = ({ products, orders, systemName }) => {
  const [insights, setInsights] = useState<string | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);

  const stats = useMemo(() => {
    const today = new Date(); today.setHours(0,0,0,0);
    const todayOrders = orders.filter(o => new Date(o.timestamp) >= today);
    const dailyRevenue = todayOrders.reduce((sum, o) => sum + o.total, 0);
    const lowStockCount = products.filter(p => p.stock <= p.minStock).length;
    return { revenue: dailyRevenue.toFixed(2), orders: todayOrders.length, customers: todayOrders.length, lowStock: lowStockCount };
  }, [orders, products]);

  const salesByDay = useMemo(() => {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const data = days.map(d => ({ name: d, sales: 0 }));
    orders.forEach(o => { data[new Date(o.timestamp).getDay()].sales += o.total; });
    return data;
  }, [orders]);

  const fetchInsights = useCallback(async () => {
    setLoadingInsights(true);
    try {
      const res = await getBusinessInsights(salesByDay, { lowStockCount: stats.lowStock });
      setInsights(res);
    } catch (err) { 
      setInsights("Error loading insights. Fadlan hubi khadkaaga internetka."); 
    }
    finally { setLoadingInsights(false); }
  }, [salesByDay, stats.lowStock]);

  useEffect(() => { 
    // Initial fetch
    fetchInsights(); 
  }, [fetchInsights]);

  return (
    <div className="p-8 space-y-8 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-gray-800 tracking-tight">Soo dhawoow, {systemName}!</h2>
          <p className="text-gray-500 font-medium">Falanqaynta ganacsiga iyo warbixinnada maanta.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Revenue" value={`$${stats.revenue}`} icon="fa-dollar-sign" color="bg-green-100 text-green-600" trend="Maanta" />
        <StatCard title="Orders" value={stats.orders} icon="fa-receipt" color="bg-blue-100 text-blue-600" trend="Iibka" />
        <StatCard title="Customers" value={stats.customers} icon="fa-users" color="bg-purple-100 text-purple-600" trend="Tirada" />
        <StatCard title="Low Stock" value={stats.lowStock} icon="fa-box-open" color="bg-orange-100 text-orange-600" trend="Digniin" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100">
          <h3 className="text-lg font-black mb-8 uppercase tracking-widest text-gray-400">Weekly Performance</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesByDay}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }} />
                <Bar dataKey="sales" fill="var(--brand-secondary)" radius={[8, 8, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-brand-primary text-white p-8 rounded-[2.5rem] shadow-2xl flex flex-col relative overflow-hidden group">
          <div className="absolute top-[-10%] right-[-10%] w-40 h-40 bg-white/5 rounded-full blur-3xl group-hover:scale-150 transition-transform duration-1000"></div>
          <div className="flex items-center gap-3 mb-6 relative z-10">
            <div className="w-10 h-10 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/20">
              <i className="fas fa-wand-magic-sparkles text-brand-secondary"></i>
            </div>
            <h3 className="text-lg font-black uppercase tracking-widest">AI Insights</h3>
          </div>
          <div className="flex-1 space-y-4 text-white/80 leading-relaxed relative z-10">
            {loadingInsights ? (
              <div className="space-y-4 animate-pulse"><div className="h-4 bg-white/10 rounded w-3/4"></div><div className="h-4 bg-white/10 rounded w-full"></div><div className="h-4 bg-white/10 rounded w-5/6"></div></div>
            ) : (
              <div className={`prose prose-sm prose-invert whitespace-pre-wrap text-sm font-medium ${insights?.includes('Quota') ? 'text-orange-300' : ''}`}>
                {insights || "Wax faallo ah lagama helin AI-ga."}
              </div>
            )}
          </div>
          <button onClick={fetchInsights} disabled={loadingInsights} className="mt-8 w-full py-4 bg-brand-secondary text-brand-primary rounded-2xl text-xs font-black uppercase tracking-widest transition-all hover:scale-105 active:scale-95 relative z-10 shadow-lg disabled:opacity-50">
            {loadingInsights ? 'Analyzing...' : 'Refresh AI Analysis'}
          </button>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color, trend }: any) => (
