}

const DefaultLogoSVG = () => (
  <svg viewBox="0 0 100 100" className="w-12 h-12 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Settings: React.FC<SettingsProps> = ({ 
  taxRate, onUpdateTaxRate, isTaxEnabled, onToggleTax, 
  systemConfig, onUpdateConfig, onResetData 
}) => {
  const [tempTax, setTempTax] = useState(taxRate.toString());
  const [tempConfig, setTempConfig] = useState<SystemConfig>(systemConfig);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const [updateProgress, setUpdateProgress] = useState<number | null>(null);
  const [updateStatus, setUpdateStatus] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleUpdateBranding = (e?: React.FormEvent) => {
    e?.preventDefault();
    onUpdateConfig(tempConfig);
    setMessage({ text: 'Habaynta nidaamka waa la cusboonaysiiyay!', type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const toggleModule = (module: View) => {
    setTempConfig(prev => {
      const isEnabled = prev.enabledModules.includes(module);
      const newModules = isEnabled 
        ? prev.enabledModules.filter(m => m !== module)
        : [...prev.enabledModules, module];
      return { ...prev, enabledModules: newModules };
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        setMessage({ text: 'Sawirku aad buu u weyn yahay (Max 2MB).', type: 'error' });
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempConfig({ ...tempConfig, logoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const simulateUpdate = () => {
    setUpdateProgress(0);
    setUpdateStatus('Hubinta nooca cusub...');

    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 15;
      if (progress >= 100) {
        progress = 100;
        setUpdateProgress(100);
        setUpdateStatus('Nidaamka waa la cusboonaysiiyay!');
        clearInterval(interval);

        // Update version in state
        const nextVersion = (parseFloat(tempConfig.version) + 0.1).toFixed(1);
        const updatedConfig = { ...tempConfig, version: nextVersion };
        setTempConfig(updatedConfig);
        onUpdateConfig(updatedConfig);

        setTimeout(() => {
          setUpdateProgress(null);
          setUpdateStatus('');
          setMessage({ text: `Version ${nextVersion} ayaa hadda shaqeynaya!`, type: 'success' });
        }, 2000);
      } else {
        setUpdateProgress(progress);
        if (progress > 20 && progress < 50) setUpdateStatus('Soo dejinta faylasha cusub...');
        if (progress >= 50 && progress < 80) setUpdateStatus('Ku rakibidda isbeddellada...');
        if (progress >= 80) setUpdateStatus('U diyaarinaya isticmaalka...');
      }
    }, 400);
  };

  return (
    <div className="p-8 max-w-6xl mx-auto space-y-8 animate-fadeIn pb-20">
      <div className="mb-8">
        <h2 className="text-3xl font-black text-gray-800">Maamulka Guud (Settings)</h2>
        <p className="text-gray-500 font-medium">Halkan ka maamul nidaamka, logo-da, iyo automatic updates-ka.</p>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">

        {/* AUTOMATIC UPDATES & SYSTEM INFO */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-sync text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Cusboonaysiinta Nidaamka (Updates)</h3>
              <p className="text-sm text-gray-500">Nooca hadda: <span className="font-black text-brand-primary">v{tempConfig.version}</span></p>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex items-center justify-between p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100">
               <div>
                 <h4 className="font-bold text-indigo-900">Automatic Update</h4>
                 <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">Markuu update cusub soo baxo isagaa is sameynaya</p>
               </div>
               <button 
                  onClick={() => {
                    const newConfig = { ...tempConfig, autoUpdate: !tempConfig.autoUpdate };
                    setTempConfig(newConfig);
                    onUpdateConfig(newConfig);
                  }}
                  className={`w-14 h-8 rounded-full p-1 transition-all duration-300 ${tempConfig.autoUpdate ? 'bg-indigo-600' : 'bg-gray-300'}`}
                >
                  <div className={`w-6 h-6 bg-white rounded-full shadow-md transition-all duration-300 transform ${tempConfig.autoUpdate ? 'translate-x-6' : 'translate-x-0'}`}></div>
                </button>
            </div>

            {updateProgress !== null ? (
              <div className="space-y-4 p-6 bg-gray-50 rounded-3xl border border-gray-100 animate-fadeIn">
                 <div className="flex justify-between items-center mb-1">
                    <span className="text-xs font-black text-gray-500 uppercase tracking-widest">{updateStatus}</span>
                    <span className="text-xs font-black text-brand-primary">{Math.round(updateProgress)}%</span>
                 </div>
                 <div className="w-full h-3 bg-gray-200 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-brand-primary transition-all duration-300"
                      style={{ width: `${updateProgress}%` }}
                    ></div>
                 </div>
              </div>
            ) : (
              <div className="flex flex-col items-center gap-4 py-4">
                 <div className="flex items-center gap-2 text-green-500 bg-green-50 px-4 py-2 rounded-full border border-green-100">
                    <i className="fas fa-check-circle text-xs"></i>
                    <span className="text-[10px] font-black uppercase tracking-widest">Nidaamku waa up-to-date</span>
                 </div>
                 <button 
                  onClick={simulateUpdate}
                  className="w-full py-4 bg-white border-2 border-indigo-100 text-indigo-600 rounded-2xl font-black text-sm hover:bg-indigo-600 hover:text-white hover:border-indigo-600 transition-all shadow-sm flex items-center justify-center gap-2"
                 >
                    <i className="fas fa-cloud-download-alt"></i> Hubi Update Cusub
                 </button>
              </div>
            )}
          </div>
        </div>

        {/* SECTION 1: SYSTEM CONTROLS */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-orange-100 text-orange-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-toggle-on text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Nidaamka Maamulka (Module Control)</h3>
              <p className="text-sm text-gray-500">Xer ama Fur qeybaha nidaamka.</p>
            </div>
          </div>

          <div className="space-y-4">
            {[
              { id: 'POS' as View, label: 'POS Service (Iibka)', icon: 'fa-cash-register' },
              { id: 'INVENTORY' as View, label: 'Inventory (Kaydka)', icon: 'fa-boxes-stacked' },
              { id: 'STAFF' as View, label: 'Staff (Shaqaalaha)', icon: 'fa-users-gear' },
              { id: 'FINANCE' as View, label: 'Finance (Lacagta)', icon: 'fa-money-bill-trend-up' },
              { id: 'REPORTS' as View, label: 'Reports (Warbixin)', icon: 'fa-chart-line' },
            ].map(module => (
              <div key={module.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl border border-transparent hover:border-gray-200 transition-all">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${tempConfig.enabledModules.includes(module.id) ? 'bg-brand-secondary text-white' : 'bg-gray-200 text-gray-400'}`}>
                    <i className={`fas ${module.icon} text-sm`}></i>
                  </div>
                  <span className="font-bold text-gray-700">{module.label}</span>
                </div>
                <button 
                  onClick={() => toggleModule(module.id)}
                  className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    tempConfig.enabledModules.includes(module.id) 
                      ? 'bg-green-100 text-green-600' 
                      : 'bg-red-100 text-red-600'
                  }`}
                >
                  {tempConfig.enabledModules.includes(module.id) ? 'Open (Furan)' : 'Closed (Xiran)'}
                </button>
              </div>
            ))}
          </div>
          <button onClick={() => handleUpdateBranding()} className="w-full py-4 bg-brand-primary text-white rounded-2xl font-black shadow-lg">Keydi Maamulka Qaybaha</button>
        </div>

        {/* SECTION 2: BRANDING & LOGO */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-purple-100 text-purple-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-palette text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Bedelka Logo-da iyo Aqoonsiga</h3>
