              <div className="w-full space-y-4">
                <button 
                  type="button"
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full py-4 bg-white border-2 border-dashed border-gray-200 rounded-2xl text-gray-500 font-bold text-sm hover:border-brand-secondary hover:text-brand-secondary transition-all"
                >
                  <i className="fas fa-upload mr-2"></i> Soo geli Logo-da
                </button>
                <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept="image/*" className="hidden" />
                <input 
                  value={tempConfig.logoUrl.startsWith('data:') ? '' : tempConfig.logoUrl} 
                  onChange={e => setTempConfig({...tempConfig, logoUrl: e.target.value})}
