            <div className="w-12 h-12 bg-pink-100 text-pink-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-brush text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Midabada Nidaamka</h3>
              <p className="text-sm text-gray-500">Dooro midabada u gaarka ah ganacsigaaga.</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-3">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Midabka Koowaad (Primary)</label>
              <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-2xl border border-gray-100">
                <input 
                  type="color" 
                  value={tempConfig.primaryColor}
                  onChange={(e) => setTempConfig({...tempConfig, primaryColor: e.target.value})}
                  className="w-10 h-10 border-none rounded-lg cursor-pointer bg-transparent"
                />
                <input 
                  type="text" 
