export interface Order {
  id: string;
  items: OrderItem[];
  subtotal: number;
  tax: number;
  total: number;
  discount: number;
  paymentMethod: PaymentMethod;
  timestamp: Date;
  staffId: string;
  customerName?: string;
}

export interface PendingOrder {
  id: string;
  items: OrderItem[];
  subtotal: number;
  tax: number;
  total: number;
  waiterId: string;
  waiterName: string;
  timestamp: Date;
  tableNumber?: string;
}

export interface Expense {
  id: string;
  title: string;
  amount: number;
  category: string;
  date: string;
}

export interface StaffMember {
  id: string;
  name: string;
  role: UserRole;
  phone: string;
  joinDate: string;
  status: 'Active' | 'On Leave' | 'Inactive';
  pin: string;
  image?: string;
}

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import Inventory from './components/Inventory';
import Staff from './components/Staff';
import Finance from './components/Finance';
import Settings from './components/Settings';
import Login from './components/Login';
import { View, UserRole, Product, StaffMember, Order, Expense, PendingOrder, SystemConfig } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';

const DEFAULT_CONFIG: SystemConfig = {
  name: 'Koob Coffee',
  description: 'The Best Coffee & Snacks Experience in Mogadishu.',
  primaryColor: '#3d2b1f',
  secondaryColor: '#c6a07d',
  logoUrl: '', 
  loginBgUrl: 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&q=80',
  appBgUrl: '',
  currencySymbol: '$',
  address: 'Mogadishu, Somalia',
  phone: '+252 61 XXX XXXX',
  accountNumbers: 'EVC: 61XXXX, Dahab: 12345',
  enabledModules: ['DASHBOARD', 'POS', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS'],
  version: '2.5.1',
  autoUpdate: true,
  autoPrintReceipts: false
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  const [systemConfig, setSystemConfig] = useState<SystemConfig>(() => {
    const saved = localStorage.getItem('koob_system_config');
    const parsed = saved ? JSON.parse(saved) : DEFAULT_CONFIG;
    return { ...DEFAULT_CONFIG, ...parsed };
  });

  useEffect(() => {
    document.documentElement.style.setProperty('--brand-primary', systemConfig.primaryColor);
    document.documentElement.style.setProperty('--brand-secondary', systemConfig.secondaryColor);
    localStorage.setItem('koob_system_config', JSON.stringify(systemConfig));
  }, [systemConfig]);

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('koob_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [staff, setStaff] = useState<StaffMember[]>(() => {
    const saved = localStorage.getItem('koob_staff');
    return saved ? JSON.parse(saved) : INITIAL_STAFF;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('koob_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>(() => {
    const saved = localStorage.getItem('koob_pending_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('koob_expenses');
    return saved ? JSON.parse(saved) : MOCK_EXPENSES;
  });

  const [taxRate, setTaxRate] = useState<number>(() => {
    const saved = localStorage.getItem('koob_tax_rate');
    return saved ? JSON.parse(saved) : 5;
  });

  const [isTaxEnabled, setIsTaxEnabled] = useState<boolean>(() => {
    const saved = localStorage.getItem('koob_is_tax_enabled');
    return saved ? JSON.parse(saved) : true;
  });

  useEffect(() => localStorage.setItem('koob_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('koob_staff', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('koob_orders', JSON.stringify(orders)), [orders]);
  useEffect(() => localStorage.setItem('koob_pending_orders', JSON.stringify(pendingOrders)), [pendingOrders]);
  useEffect(() => localStorage.setItem('koob_expenses', JSON.stringify(expenses)), [expenses]);
  useEffect(() => localStorage.setItem('koob_tax_rate', JSON.stringify(taxRate)), [taxRate]);
  useEffect(() => localStorage.setItem('koob_is_tax_enabled', JSON.stringify(isTaxEnabled)), [isTaxEnabled]);

  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
    if (matchedStaff.role === UserRole.WAITER || matchedStaff.role === UserRole.CASHIER) {
      setCurrentView('POS');
    } else {
      setCurrentView('DASHBOARD');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const handleCompleteOrder = (order: Order, pendingOrderId?: string) => {
    setOrders(prev => [order, ...prev]);
    setProducts(prev => prev.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) return { ...p, stock: p.stock - itemInOrder.quantity };
      return p;
    }));
    if (pendingOrderId) {
      setPendingOrders(prev => prev.filter(po => po.id !== pendingOrderId));
    }
  };

  const handleUpdatePendingOrder = (updated: PendingOrder) => {
    setPendingOrders(prev => prev.map(po => po.id === updated.id ? updated : po));
  };

  const handleDeletePendingOrder = (id: string) => {
    if (confirm("Ma hubtaa inaad tirtirto dalabkan furan?")) {
      setPendingOrders(prev => prev.filter(po => po.id !== id));
    }
  };

  const renderView = () => {
    if (!currentUser) return null;
    if (currentView !== 'SETTINGS' && currentView !== 'DASHBOARD' && !systemConfig.enabledModules.includes(currentView)) {
        return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
    }

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
      case 'POS': return (
        <POS 
          products={products} 
          onCompleteOrder={handleCompleteOrder} 
          onAddPendingOrder={(po) => setPendingOrders(prev => [po, ...prev])}
          onUpdatePendingOrder={handleUpdatePendingOrder}
          onDeletePendingOrder={handleDeletePendingOrder}
          pendingOrders={pendingOrders}
          currentUser={currentUser}
          taxRate={taxRate}
          globalTaxEnabled={isTaxEnabled}
          config={systemConfig}
        />
      );
      case 'INVENTORY': return (
        <Inventory 
          products={products} 
          onAddProduct={(p) => setProducts(prev => [p, ...prev])} 
          onUpdateProduct={(u) => setProducts(prev => prev.map(p => p.id === u.id ? u : p))}
          onDeleteProduct={(id) => confirm("Ma hubtaa?") && setProducts(prev => prev.filter(p => id !== p.id))}
          currentUser={currentUser}
        />
      );
      case 'STAFF': return (
        <Staff 
          staff={staff} 
          onAddStaff={(s) => setStaff(prev => [s, ...prev])} 
          onUpdateStaff={(u) => setStaff(prev => prev.map(s => s.id === u.id ? u : s))} 
          onDeleteStaff={(id) => setStaff(prev => prev.filter(s => s.id !== id))}
          currentUser={currentUser} 
        />
      );
      case 'FINANCE': return <Finance orders={orders} expenses={expenses} onAddExpense={(e) => setExpenses(prev => [e, ...prev])} />;
      case 'SETTINGS': return (
        <Settings 
          taxRate={taxRate} 
          onUpdateTaxRate={setTaxRate}
          isTaxEnabled={isTaxEnabled}
          onToggleTax={setIsTaxEnabled}
          systemConfig={systemConfig}
          onUpdateConfig={setSystemConfig}
          onResetData={() => { localStorage.clear(); window.location.reload(); }}
        />
      );
      case 'REPORTS': 
        return (
          <div className="p-8">
            <h2 className="text-2xl font-bold mb-6 text-gray-800">Order Reports</h2>
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
               <table className="w-full text-left">
                  <thead className="bg-gray-50 text-xs font-bold uppercase text-gray-500">
                    <tr>
                      <th className="px-6 py-4">ID</th>
                      <th className="px-6 py-4">Items</th>
                      <th className="px-6 py-4">Tax</th>
                      <th className="px-6 py-4">Total</th>
                      <th className="px-6 py-4">Staff</th>
                      <th className="px-6 py-4">Date</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {orders.map(o => (
                      <tr key={o.id} className="hover:bg-gray-50">
                        <td className="px-6 py-4 font-mono text-xs">{o.id}</td>
                        <td className="px-6 py-4 text-sm">{o.items.map(i => `${i.quantity}x ${i.name}`).join(', ')}</td>
                        <td className="px-6 py-4 text-sm">{systemConfig.currencySymbol}{o.tax.toFixed(2)}</td>
                        <td className="px-6 py-4 font-bold">{systemConfig.currencySymbol}{o.total.toFixed(2)}</td>
                        <td className="px-6 py-4 text-sm">{staff.find(s => s.id === o.staffId)?.name || 'Unknown'}</td>
                        <td className="px-6 py-4 text-xs text-gray-400">{new Date(o.timestamp).toLocaleString()}</td>
                      </tr>
                    ))}
                  </tbody>
               </table>
            </div>
          </div>
        );
      default: return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} config={systemConfig} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50 relative overflow-hidden">
      {systemConfig.appBgUrl && (
        <div className="absolute inset-0 z-0 opacity-5 pointer-events-none">
          <img src={systemConfig.appBgUrl} className="w-full h-full object-cover" alt="" />
        </div>
      )}

      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        userRole={currentUser.role} 
        currentUser={currentUser} 
        config={systemConfig} 
      />

      <main className="flex-1 overflow-y-auto relative z-10">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between">
          <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">{currentView.replace('_', ' ')}</h2>
          <div className="flex items-center gap-6">
            <button onClick={handleLogout} className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2">
              <i className="fas fa-sign-out-alt"></i> Logout
            </button>
            <div className="h-8 w-[1px] bg-gray-200"></div>
            <div className="flex items-center gap-2">
               <div className="text-right hidden sm:block">
                  <p className="text-sm font-bold text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] text-brand-secondary uppercase font-bold tracking-widest">{currentUser.role}</p>
               </div>
               <div className="w-10 h-10 bg-brand-primary rounded-xl flex items-center justify-center text-white shadow-lg border border-white/20">
                  <i className="fas fa-user-check"></i>
               </div>
            </div>
          </div>
        </header>
        <div className="animate-fadeIn">
          {renderView()}
        </div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        :root {
          --brand-primary: ${systemConfig.primaryColor};
          --brand-secondary: ${systemConfig.secondaryColor};
        }
        .bg-brand-primary { background-color: var(--brand-primary); }
        .bg-brand-secondary { background-color: var(--brand-secondary); }
        .text-brand-primary { color: var(--brand-primary); }
        .text-brand-secondary { color: var(--brand-secondary); }
        .border-brand-primary { border-color: var(--brand-primary); }
        .border-brand-secondary { border-color: var(--brand-secondary); }
        .ring-brand-secondary:focus { --tw-ring-color: var(--brand-secondary); }

        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scaleIn { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole, PendingOrder, SystemConfig, PaymentMethod } from '../types';
import { CATEGORIES } from '../constants';

interface POSProps {
  products: Product[];
  onCompleteOrder: (order: Order, pendingOrderId?: string) => void;
  onAddPendingOrder: (po: PendingOrder) => void;
  onUpdatePendingOrder: (po: PendingOrder) => void;
  onDeletePendingOrder: (id: string) => void;
  pendingOrders: PendingOrder[];
  currentUser: StaffMember;
  taxRate: number;
  globalTaxEnabled: boolean;
  config: SystemConfig;
}

const DefaultLogoSVG = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-12 h-12 fill-brand-primary"}>
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const POS: React.FC<POSProps> = ({ 
  products, onCompleteOrder, onAddPendingOrder, onUpdatePendingOrder, onDeletePendingOrder, 
  pendingOrders, currentUser, taxRate, globalTaxEnabled, config 
}) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [showReceipt, setShowReceipt] = useState(false);
  const [paymentStep, setPaymentStep] = useState<'Category' | 'Method'>('Category');
  const [paymentType, setPaymentType] = useState<'CashMobile' | 'Credit' | null>(null);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Cash');
  const [customerName, setCustomerName] = useState('');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);
  const [applyTax, setApplyTax] = useState(globalTaxEnabled);

  // Print Logic: Trigger automatically if config enabled
  useEffect(() => {
    if (showReceipt && config.autoPrintReceipts) {
      const timer = setTimeout(() => {
        window.print();
      }, 700);
      return () => clearTimeout(timer);
    }
  }, [showReceipt, config.autoPrintReceipts]);

  useEffect(() => {
    if (cart.length === 0) {
      setApplyTax(globalTaxEnabled);
      setCustomerName('');
      setPaymentStep('Category');
      setPaymentType(null);
      setActivePendingId(null);
    }
  }, [globalTaxEnabled, cart.length]);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);
  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const taxAmount = applyTax ? (subtotal * (taxRate / 100)) : 0;
  const total = subtotal + taxAmount;

  const filteredProducts = useMemo(() => 
    products.filter(p => (activeCategory === 'All' || p.category === activeCategory) && p.name.toLowerCase().includes(search.toLowerCase())),
    [activeCategory, search, products]
  );

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return alert("Waa ka dhammaatay!");
    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return (alert("Stock limit!"), prev);
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const handleSelectCategory = (category: 'CashMobile' | 'Credit') => {
    setPaymentType(category);
    if (category === 'Credit') setPaymentMethod('Credit');
    setPaymentStep('Method');
  };

  const handleCompleteSale = () => {
    if (paymentMethod === 'Credit' && !customerName) {
      alert("Fadlan geli magaca macmiilka si loogu diwaangeliyo Amaahda (Buugga).");
      return;
    }

    onCompleteOrder({
      id: `ORD-${Date.now()}`,
      items: [...cart], 
      subtotal, 
      tax: taxAmount, 
      total, 
      discount: 0, 
      paymentMethod, 
      timestamp: new Date(), 
      staffId: currentUser.id,
      customerName: customerName || undefined
    }, activePendingId || undefined);

    setShowCheckout(false);
    setShowReceipt(true);
  };

  const handleCloseReceipt = () => {
    setShowReceipt(false);
    setCart([]); 
    setActivePendingId(null); 
    setCustomerName('');
    setPaymentStep('Category');
    setPaymentType(null);
  };

  const handleOpenOrder = (po: PendingOrder) => {
    setCart(po.items);
    setActivePendingId(po.id);
    setApplyTax(po.tax > 0);
  };

  const handleUpdateCurrentOrder = () => {
    if (!activePendingId) return;
    const updated: PendingOrder = {
      id: activePendingId,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };
    onUpdatePendingOrder(updated);
    setCart([]);
    setActivePendingId(null);
    alert("Dalabka waa la cusboonaysiiyay!");
  };

  const handleSendNewOrder = () => {
    const po: PendingOrder = {
      id: `PEND-${Date.now()}`,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };
    onAddPendingOrder(po);
    setCart([]);
    alert("Dalabka waa la diray!");
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {canProcessPayment && (
        <div className="w-80 bg-gray-50 border-r border-gray-200 flex flex-col no-print">
          <div className="p-4 border-b bg-white flex justify-between items-center">
            <h3 className="font-black text-gray-700 text-xs uppercase tracking-widest flex items-center gap-2">
              <i className="fas fa-clock text-brand-secondary"></i> Dalabyada Furan
            </h3>
            <span className="px-2 py-1 bg-brand-secondary/10 text-brand-secondary rounded-lg text-[10px] font-black">{pendingOrders.length}</span>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {pendingOrders.map(po => (
              <div 
                key={po.id} 
                className={`group relative p-4 rounded-2xl border transition-all cursor-pointer ${activePendingId === po.id ? 'bg-brand-primary border-brand-primary text-white shadow-lg' : 'bg-white border-gray-100 hover:border-brand-secondary'}`}
                onClick={() => handleOpenOrder(po)}
              >
                <div className="flex justify-between items-start mb-1 text-[10px] font-bold">
                  <span className="opacity-60">#{po.id.slice(-4)}</span>
                  <span>{new Date(po.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                </div>
                <p className="font-bold truncate text-sm">{po.waiterName}</p>
                <div className="flex justify-between items-center mt-2">
                  <span className="text-xs">{po.items.length} items</span>
                  <span className={`font-black ${activePendingId === po.id ? 'text-brand-secondary' : 'text-brand-primary'}`}>{config.currencySymbol}{po.total.toFixed(2)}</span>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); onDeletePendingOrder(po.id); }}
                  className="absolute -top-2 -right-2 w-8 h-8 bg-white border border-red-100 text-red-500 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center hover:bg-red-500 hover:text-white"
                >
                   <i className="fas fa-times text-xs"></i>
                </button>
              </div>
            ))}
            {pendingOrders.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-50 p-8 text-center">
                 <i className="fas fa-receipt text-4xl mb-4"></i>
                 <p className="text-xs font-bold uppercase tracking-widest">Ma jiraan dalabyo furan</p>
              </div>
            )}
          </div>
        </div>
      )}

      <div className="flex-1 flex flex-col p-6 gap-6 overflow-hidden no-print">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div className="relative w-72">
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" placeholder="Raadi alaab..." 
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-brand-secondary font-bold"
              value={search} onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-md">
            {CATEGORIES.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap ${activeCategory === cat ? 'bg-brand-secondary text-white shadow-md' : 'bg-gray-100 text-gray-600'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredProducts.map(product => (
            <button key={product.id} onClick={() => addToCart(product)} disabled={product.stock <= 0} className="bg-white p-3 rounded-2xl border border-gray-100 hover:shadow-xl transition-all flex flex-col text-left group">
              <img src={product.image} className="w-full h-28 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 text-sm truncate">{product.name}</h4>
              <div className="mt-auto flex justify-between items-center pt-2">
                <span className="text-brand-secondary font-black text-sm">{config.currencySymbol}{product.price.toFixed(2)}</span>
                <span className="text-[10px] text-gray-400 font-bold">Qty: {product.stock}</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="w-96 bg-white border-l border-gray-100 flex flex-col shadow-2xl no-print">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
          <div className="flex flex-col">
            <h3 className="text-xl font-black text-brand-primary">
              {activePendingId ? 'Dalabka Furan' : 'Dalab Cusub'}
            </h3>
            <p className="text-[9px] font-bold text-brand-secondary uppercase tracking-[0.2em]">
              {activePendingId ? `ID: #${activePendingId.slice(-4)}` : 'Transaction Panel'}
            </p>
          </div>
          <button onClick={() => { setCart([]); setActivePendingId(null); }} className="text-gray-400 hover:text-red-500 transition-colors"><i className="fas fa-trash-alt"></i></button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.map(item => (
            <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-2xl border border-transparent hover:border-brand-secondary/20 transition-all animate-fadeIn">
              <div className="flex-1"><h4 className="font-bold text-gray-800 text-sm truncate">{item.name}</h4><p className="text-xs text-brand-secondary font-black">{config.currencySymbol}{(item.price * item.quantity).toFixed(2)}</p></div>
              <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                 <button onClick={() => {setCart(prev => prev.map(i => i.productId === item.productId ? {...i, quantity: Math.max(0, i.quantity - 1)} : i).filter(i => i.quantity > 0))}} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">-</button>
                 <span className="text-xs font-black w-4 text-center">{item.quantity}</span>
                 <button onClick={() => addToCart(products.find(p => p.id === item.productId)!)} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">+</button>
              </div>
            </div>
          ))}
          {cart.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-gray-200 opacity-50 text-center">
              <i className="fas fa-shopping-basket text-6xl mb-4"></i>
              <p className="text-sm font-black uppercase tracking-widest">Dambiishu waa maran tahay</p>
            </div>
          )}
        </div>

