import React, { useState, useRef, useEffect } from 'react';
import { SystemConfig, View } from '../types';

interface SettingsProps {
  taxRate: number;
  onUpdateTaxRate: (rate: number) => void;
  isTaxEnabled: boolean;
  onToggleTax: (enabled: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateConfig: (config: SystemConfig) => void;
  onResetData: () => void;
}

const DefaultLogoSVG = () => (
  <svg viewBox="0 0 100 100" className="w-12 h-12 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Settings: React.FC<SettingsProps> = ({ 
  taxRate, onUpdateTaxRate, isTaxEnabled, onToggleTax, 
  systemConfig, onUpdateConfig, onResetData 
}) => {
  const [tempConfig, setTempConfig] = useState<SystemConfig>(systemConfig);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const [updateProgress, setUpdateProgress] = useState<number | null>(null);
  const [updateStatus, setUpdateStatus] = useState<string>('');

  const logoInputRef = useRef<HTMLInputElement>(null);
  const loginBgInputRef = useRef<HTMLInputElement>(null);
  const appBgInputRef = useRef<HTMLInputElement>(null);

  const handleUpdateBranding = (e?: React.FormEvent) => {
    e?.preventDefault();
    onUpdateConfig(tempConfig);
    setMessage({ text: 'Habaynta nidaamka waa la cusboonaysiiyay!', type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const toggleModule = (module: View) => {
    setTempConfig(prev => {
      const isEnabled = prev.enabledModules.includes(module);
      const newModules = isEnabled 
        ? prev.enabledModules.filter(m => m !== module)
        : [...prev.enabledModules, module];
      return { ...prev, enabledModules: newModules };
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'logoUrl' | 'loginBgUrl' | 'appBgUrl') => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        setMessage({ text: 'Sawirku aad buu u weyn yahay (Max 5MB).', type: 'error' });
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempConfig({ ...tempConfig, [field]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const simulateUpdate = () => {
    setUpdateProgress(0);
    setUpdateStatus('Hubinta nooca cusub...');

    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 12;
      if (progress >= 100) {
        progress = 100;
        setUpdateProgress(100);
        setUpdateStatus('Nidaamka waa la cusboonaysiiyay!');
        clearInterval(interval);

        const currentV = parseFloat(tempConfig.version) || 2.5;
        const nextVersion = (currentV + 0.1).toFixed(1);
        const updatedConfig = { ...tempConfig, version: nextVersion };
        setTempConfig(updatedConfig);
        onUpdateConfig(updatedConfig);

        setTimeout(() => {
          setUpdateProgress(null);
          setUpdateStatus('');
          setMessage({ text: `Version ${nextVersion} ayaa hadda shaqeynaya! Xogtaadu waa ammaan.`, type: 'success' });
        }, 2000);
      } else {
        setUpdateProgress(progress);
        if (progress > 10 && progress < 30) setUpdateStatus('Hubinta xogta ku jirta (Data Integrity)...');
        if (progress >= 30 && progress < 50) setUpdateStatus('Kaydinta xogtaada (Securing Database)...');
        if (progress >= 50 && progress < 80) setUpdateStatus('Soo dejinta faylasha cusub...');
        if (progress >= 80) setUpdateStatus('Ku rakibidda isbeddellada...');
      }
    }, 450);
  };

  return (
    <div className="p-8 max-w-6xl mx-auto space-y-8 animate-fadeIn pb-20">
      <div className="mb-8 flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Maamulka Guud (Settings)</h2>
          <p className="text-gray-500 font-medium">Maamul muuqaalka, midabada, iyo updates-ka nidaamka.</p>
        </div>
        <button 
          onClick={() => handleUpdateBranding()}
          className="px-8 py-4 bg-brand-primary text-white rounded-2xl font-black shadow-lg hover:scale-105 active:scale-95 transition-all"
        >
          Keydi Isbeddellada
        </button>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">

        {/* PRINT & RECEIPT SETTINGS */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-print text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">Habaynta Receipt-ka</h3>
              <p className="text-sm text-gray-500">U gaar ah thermal printers (X-Printer).</p>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex items-center justify-between p-5 bg-blue-50/50 rounded-2xl border border-blue-100">
               <div className="flex-1 pr-4">
                 <h4 className="font-bold text-blue-900 text-sm">Auto-Print Receipt</h4>
                 <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest leading-relaxed">Receipt-ka toos ayuu u soo baxayaa markii dalabka la xiro.</p>
               </div>
               <button 
                  onClick={() => setTempConfig({...tempConfig, autoPrintReceipts: !tempConfig.autoPrintReceipts})}
                  className={`w-14 h-8 rounded-full p-1 transition-all duration-300 ${tempConfig.autoPrintReceipts ? 'bg-blue-600' : 'bg-gray-300'}`}
                >
                  <div className={`w-6 h-6 bg-white rounded-full shadow-md transition-all duration-300 transform ${tempConfig.autoPrintReceipts ? 'translate-x-6' : 'translate-x-0'}`}></div>
                </button>
            </div>

            <div className="grid grid-cols-1 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Account Numbers (Receipt Footer)</label>
                <input 
                  type="text" 
                  value={tempConfig.accountNumbers}
                  onChange={(e) => setTempConfig({...tempConfig, accountNumbers: e.target.value})}
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-sm"
                  placeholder="EVC: 61XXXX, Dahab: 1234..."
