    { id: 'FINANCE' as View, icon: 'fa-money-bill-trend-up', label: 'Finance', roles: [UserRole.ADMIN] },
    { id: 'SETTINGS' as View, icon: 'fa-cog', label: 'Settings', roles: [UserRole.ADMIN] },
  ];

  // Filter by user role AND system module enablement
  const allowedItems = menuItems.filter(item => {
    const isRoleAllowed = item.roles.includes(userRole);
    // Customer book is also controlled by enablement if preferred, but specifically for Admin/Manager as per request
    const isModuleEnabled = item.id === 'SETTINGS' || item.id === 'DASHBOARD' || item.id === 'CUSTOMER_BOOK' || config.enabledModules.includes(item.id);
