          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-white/10">
        <div className="flex items-center gap-3 p-3 bg-white/10 rounded-2xl border border-white/5 backdrop-blur-sm">
          <img src={`https://i.pravatar.cc/150?u=${currentUser.id}`} alt="Avatar" className="w-10 h-10 rounded-xl bg-white/20" />
          <div className="overflow-hidden">
            <p className="text-sm font-bold truncate">{currentUser.name}</p>
