import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import Inventory from './components/Inventory';
import Staff from './components/Staff';
import Finance from './components/Finance';
import Settings from './components/Settings';
import Login from './components/Login';
import Reports from './components/Reports';
import CustomerBook from './components/CustomerBook';
import { View, UserRole, Product, StaffMember, Order, Expense, PendingOrder, SystemConfig, Customer } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';

const DEFAULT_CONFIG: SystemConfig = {
  name: 'Koob Coffee',
  description: 'The Best Coffee & Snacks Experience in Mogadishu.',
  primaryColor: '#3d2b1f',
  secondaryColor: '#c6a07d',
  logoUrl: '', 
  loginBgUrl: 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&q=80',
  appBgUrl: '',
  currencySymbol: '$',
  address: 'Mogadishu, Somalia',
  phone: '+252 61 XXX XXXX',
  accountNumbers: 'EVC: 61XXXX, Dahab: 12345',
  enabledModules: ['DASHBOARD', 'POS', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS', 'CUSTOMER_BOOK'],
  version: '2.6.1', 
  autoUpdate: true,
  autoPrintReceipts: false
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  const [systemConfig, setSystemConfig] = useState<SystemConfig>(() => {
    const saved = localStorage.getItem('koob_system_config');
    const parsed = saved ? JSON.parse(saved) : DEFAULT_CONFIG;
    return { ...DEFAULT_CONFIG, ...parsed };
  });

  useEffect(() => {
    document.documentElement.style.setProperty('--brand-primary', systemConfig.primaryColor);
    document.documentElement.style.setProperty('--brand-secondary', systemConfig.secondaryColor);
    localStorage.setItem('koob_system_config', JSON.stringify(systemConfig));
  }, [systemConfig]);

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('koob_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [staff, setStaff] = useState<StaffMember[]>(() => {
    const saved = localStorage.getItem('koob_staff');
    return saved ? JSON.parse(saved) : INITIAL_STAFF;
  });

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('koob_customers');
    return saved ? JSON.parse(saved) : [];
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('koob_orders');
    const parsed = saved ? JSON.parse(saved) : [];
    return parsed.map((o: any) => ({ ...o, timestamp: new Date(o.timestamp) }));
  });

  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>(() => {
    const saved = localStorage.getItem('koob_pending_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('koob_expenses');
    return saved ? JSON.parse(saved) : MOCK_EXPENSES;
  });

  const [taxRate, setTaxRate] = useState<number>(() => {
    const saved = localStorage.getItem('koob_tax_rate');
    return saved ? JSON.parse(saved) : 5;
  });

  const [isTaxEnabled, setIsTaxEnabled] = useState<boolean>(() => {
    const saved = localStorage.getItem('koob_is_tax_enabled');
    return saved ? JSON.parse(saved) : true;
  });

  useEffect(() => localStorage.setItem('koob_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('koob_staff', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('koob_customers', JSON.stringify(customers)), [customers]);
  useEffect(() => localStorage.setItem('koob_orders', JSON.stringify(orders)), [orders]);
  useEffect(() => localStorage.setItem('koob_pending_orders', JSON.stringify(pendingOrders)), [pendingOrders]);
  useEffect(() => localStorage.setItem('koob_expenses', JSON.stringify(expenses)), [expenses]);
  useEffect(() => localStorage.setItem('koob_tax_rate', JSON.stringify(taxRate)), [taxRate]);
  useEffect(() => localStorage.setItem('koob_is_tax_enabled', JSON.stringify(isTaxEnabled)), [isTaxEnabled]);

  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
    if (matchedStaff.role === UserRole.WAITER || matchedStaff.role === UserRole.CASHIER) {
      setCurrentView('POS');
    } else {
      setCurrentView('DASHBOARD');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const handleCompleteOrder = (order: Order, pendingOrderId?: string) => {
    setOrders(prev => [order, ...prev]);

    // Update Inventory
    setProducts(prev => prev.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) return { ...p, stock: p.stock - itemInOrder.quantity };
      return p;
    }));

    // Update Customer Debt if payment method is Credit
    if (order.paymentMethod === 'Credit' && order.customerName) {
      setCustomers(prev => {
        const existing = prev.find(c => c.name.toLowerCase() === order.customerName?.toLowerCase());
        if (existing) {
          return prev.map(c => c.id === existing.id ? { ...c, totalDebt: c.totalDebt + order.total, lastTransaction: new Date() } : c);
        } else {
          const newCust: Customer = {
            id: `C-${Date.now()}`,
            name: order.customerName!,
            phone: 'N/A',
            totalDebt: order.total,
            lastTransaction: new Date()
          };
          // Also link order back to this new ID
          order.customerId = newCust.id;
          return [...prev, newCust];
        }
      });
    }

    if (pendingOrderId) {
      setPendingOrders(prev => prev.filter(po => po.id !== pendingOrderId));
    }
  };

  const handleUpdatePendingOrder = (updated: PendingOrder) => {
    setPendingOrders(prev => prev.map(po => po.id === updated.id ? updated : po));
  };

  const handleDeletePendingOrder = (id: string) => {
    if (confirm("Ma hubtaa inaad tirtirto dalabkan furan?")) {
      setPendingOrders(prev => prev.filter(po => po.id !== id));
    }
  };

  const handleClearDebt = (customerId: string, amount: number) => {
    setCustomers(prev => prev.map(c => 
      c.id === customerId ? { ...c, totalDebt: Math.max(0, c.totalDebt - amount), lastTransaction: new Date() } : c
    ));
  };

  const handleAddCustomer = (customer: Customer) => {
    setCustomers(prev => [...prev, customer]);
  };

  const renderView = () => {
    if (!currentUser) return null;
    if (currentView !== 'SETTINGS' && currentView !== 'DASHBOARD' && !systemConfig.enabledModules.includes(currentView)) {
        return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
    }

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
      case 'POS': return (
        <POS 
          products={products} 
          onCompleteOrder={handleCompleteOrder} 
          onAddPendingOrder={(po) => setPendingOrders(prev => [po, ...prev])}
          onUpdatePendingOrder={handleUpdatePendingOrder}
          onDeletePendingOrder={handleDeletePendingOrder}
          pendingOrders={pendingOrders}
          currentUser={currentUser}
          taxRate={taxRate}
          globalTaxEnabled={isTaxEnabled}
          config={systemConfig}
        />
      );
      case 'CUSTOMER_BOOK': 
        return (
          <CustomerBook 
            customers={customers} 
            orders={orders} 
            config={systemConfig} 
            onUpdateCustomer={(u) => setCustomers(prev => prev.map(c => c.id === u.id ? u : c))}
            onAddCustomer={handleAddCustomer}
            onClearDebt={handleClearDebt}
          />
        );
      case 'INVENTORY': return (
        <Inventory 
          products={products} 
          onAddProduct={(p) => setProducts(prev => [p, ...prev])} 
          onUpdateProduct={(u) => setProducts(prev => prev.map(p => p.id === u.id ? u : p))}
          onDeleteProduct={(id) => confirm("Ma hubtaa?") && setProducts(prev => prev.filter(p => p.id !== id))}
          currentUser={currentUser}
        />
      );
      case 'STAFF': return (
        <Staff 
          staff={staff} 
          onAddStaff={(s) => setStaff(prev => [s, ...prev])} 
          onUpdateStaff={(u) => setStaff(prev => prev.map(s => s.id === u.id ? u : s))} 
          onDeleteStaff={(id) => setStaff(prev => prev.filter(s => s.id !== id))}
          currentUser={currentUser} 
        />
      );
      case 'FINANCE': return <Finance orders={orders} expenses={expenses} onAddExpense={(e) => setExpenses(prev => [e, ...prev])} />;
      case 'SETTINGS': return (
        <Settings 
          taxRate={taxRate} 
          onUpdateTaxRate={setTaxRate}
          isTaxEnabled={isTaxEnabled}
          onToggleTax={setIsTaxEnabled}
          systemConfig={systemConfig}
          onUpdateConfig={setSystemConfig}
          onResetData={() => { localStorage.clear(); window.location.reload(); }}
        />
      );
      case 'REPORTS': 
        return (
          <Reports 
            orders={orders} 
            products={products} 
            staff={staff} 
            config={systemConfig} 
          />
        );
      default: return <Dashboard products={products} orders={orders} systemName={systemConfig.name} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} config={systemConfig} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50 relative overflow-hidden">
      {systemConfig.appBgUrl && (
        <div className="absolute inset-0 z-0 opacity-5 pointer-events-none">
          <img src={systemConfig.appBgUrl} className="w-full h-full object-cover" alt="" />
        </div>
      )}

      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        userRole={currentUser.role} 
        currentUser={currentUser} 
        config={systemConfig} 
      />

      <main className="flex-1 overflow-y-auto relative z-10">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between no-print">
          <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">{currentView.replace('_', ' ')}</h2>
          <div className="flex items-center gap-6">
            <button onClick={handleLogout} className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2">
              <i className="fas fa-sign-out-alt"></i> Logout
            </button>
            <div className="h-8 w-[1px] bg-gray-200"></div>
            <div className="flex items-center gap-2">
               <div className="text-right hidden sm:block">
                  <p className="text-sm font-bold text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] text-brand-secondary uppercase font-bold tracking-widest">{currentUser.role}</p>
               </div>
               <div className="w-10 h-10 bg-brand-primary rounded-xl flex items-center justify-center text-white shadow-lg border border-white/20">
                  <i className="fas fa-user-check"></i>
               </div>
            </div>
          </div>
        </header>
        <div className="animate-fadeIn">
          {renderView()}
        </div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        :root {
          --brand-primary: ${systemConfig.primaryColor};
          --brand-secondary: ${systemConfig.secondaryColor};
        }
        .bg-brand-primary { background-color: var(--brand-primary); }
        .bg-brand-secondary { background-color: var(--brand-secondary); }
        .text-brand-primary { color: var(--brand-primary); }
        .text-brand-secondary { color: var(--brand-secondary); }
        .border-brand-primary { border-color: var(--brand-primary); }
        .border-brand-secondary { border-color: var(--brand-secondary); }
        .ring-brand-secondary:focus { --tw-ring-color: var(--brand-secondary); }

        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scaleIn { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Customer, Order, SystemConfig } from '../types';

interface CustomerBookProps {
  customers: Customer[];
  orders: Order[];
  config: SystemConfig;
  onUpdateCustomer: (customer: Customer) => void;
  onAddCustomer: (customer: Customer) => void;
  onClearDebt: (customerId: string, amount: number) => void;
  onAddManualDebt: (customerId: string, amount: number, note: string) => void;
}

const CustomerBook: React.FC<CustomerBookProps> = ({ 
  customers, 
  orders, 
  config, 
  onUpdateCustomer, 
  onAddCustomer, 
  onClearDebt,
  onAddManualDebt
}) => {
  const [search, setSearch] = useState('');
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [paymentAmount, setPaymentAmount] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [isAddingDebt, setIsAddingDebt] = useState(false);

  // New Customer Form State
  const [newCustomer, setNewCustomer] = useState({
    name: '',
    phone: '',
    guarantorName: '',
    guarantorPhone: '',
    notes: ''
  });

  // Manual Debt Form State
  const [manualDebt, setManualDebt] = useState({
    amount: '',
    note: ''
  });

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.toLowerCase().includes(search.toLowerCase()) || 
      c.phone.includes(search)
    ).sort((a, b) => b.totalDebt - a.totalDebt);
  }, [customers, search]);

  const customerOrders = useMemo(() => {
    if (!selectedCustomer) return [];
    return orders.filter(o => o.customerId === selectedCustomer.id || o.customerName === selectedCustomer.name)
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [selectedCustomer, orders]);

  const totalGlobalDebt = customers.reduce((sum, c) => sum + c.totalDebt, 0);

  const handleClearDebt = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomer || !paymentAmount) return;
    const amount = parseFloat(paymentAmount);
    if (isNaN(amount) || amount <= 0) return alert("Fadlan geli lacag sax ah.");

    onClearDebt(selectedCustomer.id, amount);
    setPaymentAmount('');
    alert(`Waxaad ka jartay ${config.currencySymbol}${amount} deynta ${selectedCustomer.name}`);
  };

  const handleManualDebtSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomer || !manualDebt.amount) return;
    const amount = parseFloat(manualDebt.amount);
    if (isNaN(amount) || amount <= 0) return alert("Fadlan geli lacag sax ah.");

    onAddManualDebt(selectedCustomer.id, amount, manualDebt.note);
    setManualDebt({ amount: '', note: '' });
    setIsAddingDebt(false);
    alert(`Waxaad ku dartay ${config.currencySymbol}${amount} deynta ${selectedCustomer.name}`);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCustomer.name) return alert("Fadlan geli magaca macmiilka.");

    const customer: Customer = {
      id: `C-${Date.now()}`,
      name: newCustomer.name,
      phone: newCustomer.phone || 'N/A',
      guarantorName: newCustomer.guarantorName,
      guarantorPhone: newCustomer.guarantorPhone,
      totalDebt: 0,
      lastTransaction: new Date(),
      notes: newCustomer.notes
    };

    onAddCustomer(customer);
    setIsAdding(false);
    setNewCustomer({ name: '', phone: '', guarantorName: '', guarantorPhone: '', notes: '' });
  };

  return (
    <div className="p-8 space-y-8 animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-gray-800 tracking-tight">Buugga Macaamiisha (Ledger)</h2>
          <p className="text-gray-500 font-medium">Maamul macaamiisha amaahda kugu leh iyo diiwaanka lacagaha.</p>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => setIsAdding(true)}
            className="px-6 py-4 bg-brand-secondary text-brand-primary rounded-2xl font-black shadow-lg hover:scale-105 active:scale-95 transition-all flex items-center gap-2"
          >
            <i className="fas fa-user-plus"></i> Ku dar Macmiil
          </button>
          <div className="bg-red-50 px-6 py-4 rounded-3xl border border-red-100 flex items-center gap-4">
             <div className="w-12 h-12 bg-red-500 rounded-2xl flex items-center justify-center text-white shadow-lg">
                <i className="fas fa-hand-holding-dollar text-xl"></i>
             </div>
             <div>
                <p className="text-[10px] font-black text-red-400 uppercase tracking-widest leading-none mb-1">Deynta Guud</p>
                <h3 className="text-2xl font-black text-red-600 leading-none">{config.currencySymbol}{totalGlobalDebt.toFixed(2)}</h3>
             </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Customer List */}
        <div className="lg:col-span-1 space-y-4">
          <div className="relative">
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" 
              placeholder="Raadi macmiil..." 
              className="w-full pl-12 pr-4 py-4 bg-white border border-gray-100 rounded-[2rem] shadow-sm focus:ring-2 focus:ring-brand-secondary outline-none font-bold text-sm"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>

          <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 overflow-hidden max-h-[600px] overflow-y-auto no-scrollbar">
            <div className="p-6 border-b border-gray-50">
               <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Liiska Macaamiisha</h4>
            </div>
            <div className="divide-y divide-gray-50">
              {filteredCustomers.map(c => (
                <button 
                  key={c.id} 
                  onClick={() => setSelectedCustomer(c)}
                  className={`w-full text-left p-6 transition-all hover:bg-gray-50 flex items-center justify-between ${selectedCustomer?.id === c.id ? 'bg-gray-50 border-l-4 border-brand-secondary' : ''}`}
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-full bg-brand-primary text-white flex items-center justify-center font-black text-xs">
                      {c.name.charAt(0)}
                    </div>
                    <div>
                      <p className="font-bold text-gray-800 text-sm">{c.name}</p>
                      <p className="text-[10px] text-gray-400 font-medium">{c.phone}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`font-black text-sm ${c.totalDebt > 0 ? 'text-red-500' : 'text-green-500'}`}>
                      {config.currencySymbol}{c.totalDebt.toFixed(2)}
                    </p>
                    <p className="text-[9px] text-gray-400 font-bold uppercase tracking-tighter">Balance</p>
                  </div>
                </button>
              ))}
              {filteredCustomers.length === 0 && (
                <div className="p-12 text-center text-gray-400 italic text-sm">Macmiil lama helin</div>
              )}
            </div>
          </div>
        </div>

        {/* Right: Detail View */}
        <div className="lg:col-span-2 space-y-8">
          {selectedCustomer ? (
            <div className="animate-fadeIn space-y-8">
              <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-6">
                  <div className="w-20 h-20 rounded-[2rem] bg-brand-primary text-white flex items-center justify-center text-3xl font-black shadow-xl">
                    {selectedCustomer.name.charAt(0)}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-gray-800">{selectedCustomer.name}</h3>
                    <p className="text-gray-400 font-bold uppercase tracking-widest text-[10px] mb-2">{selectedCustomer.phone}</p>

                    {selectedCustomer.guarantorName && (
                      <div className="flex flex-col gap-1 p-3 bg-gray-50 rounded-xl border border-gray-100">
                         <span className="text-[9px] font-black text-brand-secondary uppercase tracking-widest">Damiinka (Guarantor)</span>
                         <p className="text-xs font-bold text-gray-700">{selectedCustomer.guarantorName} - <span className="font-mono">{selectedCustomer.guarantorPhone}</span></p>
                      </div>
                    )}
                  </div>
                </div>

                <div className="flex flex-col items-end">
                   <div className="text-right">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Mugga Deynta</p>
                      <p className="text-4xl font-black text-red-600">{config.currencySymbol}{selectedCustomer.totalDebt.toFixed(2)}</p>
                   </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Repayment Form */}
                <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6">
                  <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                    <i className="fas fa-money-check-dollar text-green-500"></i> Bixi Deynta (Repayment)
                  </h4>
                  <form onSubmit={handleClearDebt} className="space-y-4">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Lacagta la bixinayo</label>
                      <input 
                        type="number" 
                        step="0.01" 
                        placeholder="0.00"
                        className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-green-500 font-black text-2xl text-center"
                        value={paymentAmount}
                        onChange={(e) => setPaymentAmount(e.target.value)}
                      />
                    </div>
                    <button type="submit" className="w-full py-4 bg-green-600 text-white rounded-2xl font-black shadow-lg hover:scale-[1.02] active:scale-95 transition-all">
                      Xaqiiji Lacag bixinta
                    </button>
                  </form>
                </div>

                {/* Manual Debt Form Button */}
                <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6 flex flex-col justify-center">
                  <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                    <i className="fas fa-file-invoice-dollar text-red-500"></i> Diiwaangeli Amaah Cusub
                  </h4>
                  <p className="text-xs text-gray-500">Haddii macmiilku qaatay wax ka baxsan POS-ka, halkan kaga dar deynta.</p>
                  <button 
                    onClick={() => setIsAddingDebt(true)}
                    className="w-full py-4 bg-red-500 text-white rounded-2xl font-black shadow-lg hover:scale-[1.02] active:scale-95 transition-all"
                  >
                    <i className="fas fa-plus mr-2"></i> Amaah ku dar (Add Credit)
                  </button>
                </div>
              </div>

              {/* Order History Table */}
              <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 overflow-hidden">
                 <div className="p-8 border-b border-gray-50 flex items-center justify-between">
                    <h3 className="font-black text-gray-400 uppercase tracking-widest text-xs">Diiwaanka Dalabyada</h3>
                    <span className="px-3 py-1 bg-gray-50 text-gray-400 rounded-lg text-[10px] font-bold uppercase">{customerOrders.length} Dalab</span>
                 </div>
                 <div className="overflow-x-auto">
                    <table className="w-full text-left">
                       <thead>
                          <tr className="bg-gray-50/50 text-[10px] font-black uppercase text-gray-500 tracking-widest">
                             <th className="px-8 py-5">Order ID</th>
                             <th className="px-8 py-5">Alaabta</th>
                             <th className="px-8 py-5">Total</th>
                             <th className="px-8 py-5">Status</th>
                             <th className="px-8 py-5">Taariikh</th>
                          </tr>
                       </thead>
                       <tbody className="divide-y divide-gray-50">
                          {customerOrders.map(o => (
                             <tr key={o.id} className="hover:bg-gray-50/50 transition-colors">
                                <td className="px-8 py-5 font-mono text-xs text-brand-secondary font-bold">#{o.id.split('-')[1]}</td>
                                <td className="px-8 py-5 text-xs text-gray-600 truncate max-w-[150px] font-medium">
                                  {o.items.length > 0 ? o.items.map(i => i.name).join(', ') : 'Manual Adjustment'}
                                </td>
                                <td className="px-8 py-5 font-black text-gray-800 text-sm">{config.currencySymbol}{o.total.toFixed(2)}</td>
                                <td className="px-8 py-5">
                                   <span className={`px-2 py-1 rounded-md text-[9px] font-black uppercase ${o.paymentMethod === 'Credit' ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>
                                      {o.paymentMethod === 'Credit' ? 'Amaah' : 'Paid'}
                                   </span>
                                </td>
                                <td className="px-8 py-5 text-[10px] text-gray-400 font-bold whitespace-nowrap">{new Date(o.timestamp).toLocaleDateString()}</td>
                             </tr>
                          ))}
                       </tbody>
                    </table>
                 </div>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-50 p-24 text-center">
               <div className="w-32 h-32 bg-gray-100 rounded-[2.5rem] flex items-center justify-center mb-8 border-4 border-white shadow-inner">
                  <i className="fas fa-book-open text-5xl"></i>
               </div>
               <h3 className="text-2xl font-black uppercase tracking-widest text-gray-400">Buugga Macaamiisha</h3>
               <p className="max-w-xs text-sm font-medium mt-4">Fadlan ka dooro macmiil dhinaca bidix si aad u aragto deynta iyo xogtiisa buuxda.</p>
            </div>
          )}
        </div>
      </div>

      {/* ADD CUSTOMER MODAL */}
      {isAdding && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-10 animate-scaleIn shadow-2xl overflow-y-auto max-h-[90vh] no-scrollbar">
              <div className="flex justify-between items-center mb-8">
                 <div>
                   <h3 className="text-2xl font-black text-gray-800 uppercase tracking-tight">Diiwaangeli Macmiil</h3>
                   <p className="text-sm text-gray-500">Geli xogta macmiilka iyo damiinkiisa.</p>
                 </div>
                 <button onClick={() => setIsAdding(false)} className="w-12 h-12 bg-gray-100 rounded-2xl flex items-center justify-center text-gray-400 hover:text-red-500 transition-all">
                    <i className="fas fa-times text-xl"></i>
                 </button>
              </div>

              <form onSubmit={handleAddSubmit} className="space-y-6">
                 <div className="space-y-2 text-left">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Magaca Macmiilka</label>
                    <input required value={newCustomer.name} onChange={e => setNewCustomer({...newCustomer, name: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" placeholder="Tusaale: Ahmed Ali" />
                 </div>

                 <div className="space-y-2 text-left">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Telefoonka Macmiilka</label>
                    <input value={newCustomer.phone} onChange={e => setNewCustomer({...newCustomer, phone: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" placeholder="+252 61..." />
                 </div>

                 <div className="p-6 bg-brand-secondary/5 rounded-3xl border border-brand-secondary/10 space-y-4">
                    <h4 className="text-[10px] font-black text-brand-secondary uppercase tracking-widest mb-2 flex items-center gap-2">
                       <i className="fas fa-user-shield"></i> Xogta Damiinka (Guarantor)
                    </h4>
                    <div className="space-y-2 text-left">
                       <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest ml-1">Magaca Damiinka</label>
                       <input value={newCustomer.guarantorName} onChange={e => setNewCustomer({...newCustomer, guarantorName: e.target.value})} className="w-full px-5 py-3 bg-white border-none rounded-xl focus:ring-2 focus:ring-brand-secondary font-bold text-sm" placeholder="Magaca damiinka" />
                    </div>
                    <div className="space-y-2 text-left">
                       <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest ml-1">Telefoonka Damiinka</label>
                       <input value={newCustomer.guarantorPhone} onChange={e => setNewCustomer({...newCustomer, guarantorPhone: e.target.value})} className="w-full px-5 py-3 bg-white border-none rounded-xl focus:ring-2 focus:ring-brand-secondary font-bold text-sm font-mono" placeholder="252..." />
                    </div>
                 </div>

                 <div className="space-y-2 text-left">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Notes (Faahfaahin)</label>
                    <textarea value={newCustomer.notes} onChange={e => setNewCustomer({...newCustomer, notes: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold min-h-[100px]" placeholder="Warbixin dheeri ah..."></textarea>
                 </div>

                 <button type="submit" className="w-full bg-brand-primary text-white py-5 rounded-3xl font-black text-xl shadow-xl hover:opacity-95 transition-all">
                    Keydi Macmiilka Cusub
                 </button>
              </form>
           </div>
        </div>
      )}

      {/* MANUAL DEBT MODAL */}
      {isAddingDebt && selectedCustomer && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 animate-scaleIn shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-2xl font-black text-red-600 uppercase tracking-tight">Deym ku dar</h3>
                <p className="text-xs text-gray-500">{selectedCustomer.name}</p>
              </div>
              <button onClick={() => setIsAddingDebt(false)} className="w-12 h-12 bg-gray-100 rounded-2xl flex items-center justify-center text-gray-400 hover:text-red-500 transition-all">
                <i className="fas fa-times text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleManualDebtSubmit} className="space-y-6">
              <div className="space-y-2 text-left">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Lacagta deynta ah</label>
                <input 
                  required 
                  type="number" 
                  step="0.01" 
                  value={manualDebt.amount} 
                  onChange={e => setManualDebt({...manualDebt, amount: e.target.value})} 
                  className="w-full px-6 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-red-500 font-black text-2xl text-center" 
                  placeholder="0.00" 
                />
              </div>

              <div className="space-y-2 text-left">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Sababta / Note</label>
                <textarea 
                  value={manualDebt.note} 
                  onChange={e => setManualDebt({...manualDebt, note: e.target.value})} 
                  className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-red-500 font-bold min-h-[100px]" 
                  placeholder="Sababta deynta loo qorayo..."
                ></textarea>
              </div>

              <button type="submit" className="w-full bg-red-600 text-white py-5 rounded-3xl font-black text-xl shadow-xl hover:opacity-95 transition-all">
                Keydi Amaahda
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

