                    <div className="flex-1"><h4 className="text-2xl font-black text-gray-800">Amaah (Credit)</h4><p className="text-sm text-gray-400 font-bold uppercase tracking-widest">Deyn / Ku qor Buugga</p></div>
                    <i className="fas fa-chevron-right text-gray-300"></i>
