          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center">
              <i className="fas fa-globe text-xl"></i>
            </div>
            <div>
              <h3 className="font-bold text-lg text-gray-800">{t.language}</h3>
              <p className="text-sm text-gray-500">Choose the system interface language.</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button 
              onClick={() => setTempConfig({...tempConfig, language: 'Somali'})}
              className={`flex flex-col items-center gap-3 p-6 rounded-[2rem] border-2 transition-all ${tempConfig.language === 'Somali' ? 'border-brand-secondary bg-brand-secondary/5' : 'bg-gray-50 border-transparent hover:border-gray-200'}`}
            >
