                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Receipt Footer Accounts</label>
                <input value={tempConfig.accountNumbers} onChange={e => setTempConfig({...tempConfig, accountNumbers: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-sm" />
