      <div className="flex flex-col lg:flex-row gap-10">
        <aside className="lg:w-72 space-y-2">
          {[
            { id: 'General', icon: 'fa-info-circle', label: 'General' },
            { id: 'Appearance', icon: 'fa-brush', label: 'Branding' },
            { id: 'Modules', icon: 'fa-layer-group', label: 'Modules' },
            { id: 'Language', icon: 'fa-globe', label: 'Language' },
            { id: 'Advanced', icon: 'fa-cog', label: 'Advanced' }
