// @ts-nocheck
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { getBusinessInsights } from '../services/geminiService';
import { Product, Order, SystemConfig } from '../types';
import { translations } from '../translations';

interface DashboardProps {
  products: Product[];
  orders: Order[];
  systemName: string;
  config: SystemConfig;
}

const Dashboard: React.FC<DashboardProps> = ({ products, orders, systemName, config }) => {
  const t = translations[config.language];
  const [insights, setInsights] = useState<string | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);

  const stats = useMemo(() => {
    const today = new Date(); today.setHours(0,0,0,0);
    const todayOrders = orders.filter(o => new Date(o.timestamp) >= today);
    const dailyRevenue = todayOrders.reduce((sum, o) => sum + o.total, 0);
    const lowStockCount = products.filter(p => p.stock <= p.minStock).length;
    return { revenue: dailyRevenue.toFixed(2), orders: todayOrders.length, customers: todayOrders.length, lowStock: lowStockCount };
  }, [orders, products]);

  const salesByDay = useMemo(() => {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const data = days.map(d => ({ name: d, sales: 0 }));
    orders.forEach(o => { data[new Date(o.timestamp).getDay()].sales += o.total; });
    return data;
  }, [orders]);

  const fetchInsights = useCallback(async () => {
    setLoadingInsights(true);
    try {
      const res = await getBusinessInsights(salesByDay, { lowStockCount: stats.lowStock });
      setInsights(res);
    } catch (err) { 
      setInsights(config.language === 'Somali' ? "Error loading insights. Fadlan hubi khadkaaga internetka." : "Error loading insights. Please check your connection."); 
    }
    finally { setLoadingInsights(false); }
  }, [salesByDay, stats.lowStock, config.language]);

  useEffect(() => { 
    fetchInsights(); 
  }, [fetchInsights]);

  return (
    <div className="p-8 space-y-8 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-gray-800 tracking-tight">{t.welcome}, {systemName}!</h2>
          <p className="text-gray-500 font-medium">{config.language === 'Somali' ? 'Falanqaynta ganacsiga iyo warbixinnada maanta.' : 'Business analysis and reports for today.'}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title={t.revenue} value={`${config.currencySymbol}${stats.revenue}`} icon="fa-dollar-sign" color="bg-green-100 text-green-600" trend={t.date} />
        <StatCard title={t.orders} value={stats.orders} icon="fa-receipt" color="bg-blue-100 text-blue-600" trend={t.pos} />
        <StatCard title={t.customers} value={stats.customers} icon="fa-users" color="bg-purple-100 text-purple-600" trend={t.customers} />
        <StatCard title={t.low_stock} value={stats.lowStock} icon="fa-box-open" color="bg-orange-100 text-orange-600" trend={t.inventory} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100">
          <h3 className="text-lg font-black mb-8 uppercase tracking-widest text-gray-400">{t.weekly_perf}</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesByDay}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }} />
                <Bar dataKey="sales" fill="var(--brand-secondary)" radius={[8, 8, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-brand-primary text-white p-8 rounded-[2.5rem] shadow-2xl flex flex-col relative overflow-hidden group">
          <div className="absolute top-[-10%] right-[-10%] w-40 h-40 bg-white/5 rounded-full blur-3xl group-hover:scale-150 transition-transform duration-1000"></div>
          <div className="flex items-center gap-3 mb-6 relative z-10">
            <div className="w-10 h-10 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/20">
              <i className="fas fa-wand-magic-sparkles text-brand-secondary"></i>
            </div>
            <h3 className="text-lg font-black uppercase tracking-widest">{t.ai_insights}</h3>
          </div>
          <div className="flex-1 space-y-4 text-white/80 leading-relaxed relative z-10">
            {loadingInsights ? (
              <div className="space-y-4 animate-pulse"><div className="h-4 bg-white/10 rounded w-3/4"></div><div className="h-4 bg-white/10 rounded w-full"></div><div className="h-4 bg-white/10 rounded w-5/6"></div></div>
            ) : (
              <div className={`prose prose-sm prose-invert whitespace-pre-wrap text-sm font-medium ${insights?.includes('Quota') ? 'text-orange-300' : ''}`}>
                {insights || (config.language === 'Somali' ? "Wax faallo ah lagama helin AI-ga." : "No insights found from AI.")}
              </div>
            )}
          </div>
          <button onClick={fetchInsights} disabled={loadingInsights} className="mt-8 w-full py-4 bg-brand-secondary text-brand-primary rounded-2xl text-xs font-black uppercase tracking-widest transition-all hover:scale-105 active:scale-95 relative z-10 shadow-lg disabled:opacity-50">
            {loadingInsights ? (config.language === 'Somali' ? 'Falanqaynayaa...' : 'Analyzing...') : t.refresh_ai}
          </button>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color, trend }: any) => (
  <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:shadow-lg transition-all">
    <div className="flex items-start justify-between">
      <div>
        <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest mb-1">{title}</p>
        <h3 className="text-3xl font-black text-gray-800">{value}</h3>
      </div>
      <div className={`p-4 rounded-2xl shadow-inner ${color}`}><i className={`fas ${icon} text-xl`}></i></div>
    </div>
    <div className="mt-4"><span className="text-[10px] font-bold text-gray-400 uppercase bg-gray-50 px-2 py-1 rounded-md">{trend}</span></div>
  </div>
);

export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole, PendingOrder, SystemConfig, PaymentMethod, Customer } from '../types';
import { CATEGORIES } from '../constants';
import { translations } from '../translations';

interface POSProps {
  products: Product[];
  customers: Customer[]; 
  onCompleteOrder: (order: Order, pendingOrderId?: string) => void;
  onAddPendingOrder: (po: PendingOrder) => void;
  onUpdatePendingOrder: (po: PendingOrder) => void;
  onDeletePendingOrder: (id: string) => void;
  pendingOrders: PendingOrder[];
  currentUser: StaffMember;
  taxRate: number;
  globalTaxEnabled: boolean;
  config: SystemConfig;
}

const DefaultLogoSVG = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-12 h-12 fill-brand-primary"}>
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const POS: React.FC<POSProps> = ({ 
  products, customers, onCompleteOrder, onAddPendingOrder, onUpdatePendingOrder, onDeletePendingOrder, 
  pendingOrders, currentUser, taxRate, globalTaxEnabled, config 
}) => {
  const t = translations[config.language];
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [showReceipt, setShowReceipt] = useState(false);
  const [paymentStep, setPaymentStep] = useState<'Category' | 'Method'>('Category');
  const [paymentType, setPaymentType] = useState<'CashMobile' | 'Credit' | null>(null);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Cash');
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [manualCustomerName, setManualCustomerName] = useState('');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);
  const [applyTax, setApplyTax] = useState(globalTaxEnabled);

  const filteredCustomers = useMemo(() => {
    if (!customerSearch) return [];
    return customers.filter(c => 
      c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
      c.phone.includes(customerSearch)
    ).slice(0, 5);
  }, [customers, customerSearch]);

  useEffect(() => {
    if (showReceipt && config.autoPrintReceipts) {
      const timer = setTimeout(() => {
        window.print();
      }, 700);
      return () => clearTimeout(timer);
    }
  }, [showReceipt, config.autoPrintReceipts]);

  useEffect(() => {
    if (cart.length === 0) {
      setApplyTax(globalTaxEnabled);
      setSelectedCustomer(null);
      setManualCustomerName('');
      setCustomerSearch('');
      setPaymentStep('Category');
      setPaymentType(null);
      setActivePendingId(null);
    }
  }, [globalTaxEnabled, cart.length]);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);
  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const taxAmount = applyTax ? (subtotal * (taxRate / 100)) : 0;
  const total = subtotal + taxAmount;

  const filteredProducts = useMemo(() => 
    products.filter(p => (activeCategory === 'All' || p.category === activeCategory) && p.name.toLowerCase().includes(search.toLowerCase())),
    [activeCategory, search, products]
  );

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return alert(config.language === 'Somali' ? "Waa ka dhammaatay!" : "Out of stock!");
    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return (alert("Stock limit!"), prev);
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
  };

  const handleSelectCategory = (category: 'CashMobile' | 'Credit') => {
    setPaymentType(category);
    if (category === 'Credit') setPaymentMethod('Credit');
    setPaymentStep('Method');
  };

  const handleCompleteSale = () => {
    const finalCustomerName = selectedCustomer ? selectedCustomer.name : manualCustomerName;

    if (paymentMethod === 'Credit' && !finalCustomerName) {
      alert(config.language === 'Somali' ? "Fadlan dooro macmiil ama qor magaca si loogu diwaangeliyo Amaahda." : "Please select a customer or write name for credit registration.");
      return;
    }

    if (paymentMethod === 'Credit' && selectedCustomer) {
      if (selectedCustomer.totalDebt + total > selectedCustomer.creditLimit) {
        if (!confirm(config.language === 'Somali' ? `DIGNIIN: Macmiilkan wuxuu dhaafayaa xadka deynta (${config.currencySymbol}${selectedCustomer.creditLimit}). Ma rabtaa inaad sii wadid?` : `WARNING: This customer exceeds credit limit (${config.currencySymbol}${selectedCustomer.creditLimit}). Continue?`)) {
          return;
        }
      }
    }

    onCompleteOrder({
      id: `ORD-${Date.now()}`,
      items: [...cart], 
      subtotal, 
      tax: taxAmount, 
      total, 
      discount: 0, 
      paymentMethod, 
      timestamp: new Date(), 
      staffId: currentUser.id,
      customerName: finalCustomerName || undefined,
      customerId: selectedCustomer?.id
    }, activePendingId || undefined);

    setShowCheckout(false);
    setShowReceipt(true);
  };

  const handleCloseReceipt = () => {
    setShowReceipt(false);
    setCart([]); 
    setActivePendingId(null); 
    setSelectedCustomer(null);
    setManualCustomerName('');
    setCustomerSearch('');
    setPaymentStep('Category');
    setPaymentType(null);
  };

  const handleOpenOrder = (po: PendingOrder) => {
    setCart(po.items);
    setActivePendingId(po.id);
    setApplyTax(po.tax > 0);
  };

  const handleUpdateCurrentOrder = () => {
    if (!activePendingId) return;
    const updated: PendingOrder = {
      id: activePendingId,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };
    onUpdatePendingOrder(updated);
    setCart([]);
    setActivePendingId(null);
    alert(config.language === 'Somali' ? "Dalabka waa la cusboonaysiiyay!" : "Order updated!");
  };

  const handleSendNewOrder = () => {
    const po: PendingOrder = {
      id: `PEND-${Date.now()}`,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };
    onAddPendingOrder(po);
    setCart([]);
    alert(config.language === 'Somali' ? "Dalabka waa la diray!" : "Order sent!");
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {canProcessPayment && (
        <div className="w-80 bg-gray-50 border-r border-gray-200 flex flex-col no-print">
          <div className="p-4 border-b bg-white flex justify-between items-center">
            <h3 className="font-black text-gray-700 text-xs uppercase tracking-widest flex items-center gap-2">
              <i className="fas fa-clock text-brand-secondary"></i> {t.pending_orders}
            </h3>
            <span className="px-2 py-1 bg-brand-secondary/10 text-brand-secondary rounded-lg text-[10px] font-black">{pendingOrders.length}</span>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {pendingOrders.map(po => (
              <div 
                key={po.id} 
                className={`group relative p-4 rounded-2xl border transition-all cursor-pointer ${activePendingId === po.id ? 'bg-brand-primary border-brand-primary text-white shadow-lg' : 'bg-white border-gray-100 hover:border-brand-secondary'}`}
                onClick={() => handleOpenOrder(po)}
              >
