                        placeholder={config.language === 'Somali' ? 'Magaca macmiilka...' : 'Customer name...'} 
                        readOnly={!!selectedCustomer}
                     />
                     {selectedCustomer && (
                       <div className="mt-2 text-center">
                          <p className={`text-[10px] font-black uppercase mb-1 ${selectedCustomer.totalDebt + total > selectedCustomer.creditLimit ? 'text-red-500 animate-pulse' : 'text-gray-400'}`}>
                            {selectedCustomer.totalDebt + total > selectedCustomer.creditLimit ? (config.language === 'Somali' ? 'DIGNIIN: Xadka ayaa la dhaafay!' : 'WARNING: Limit exceeded!') : `Usage: ${config.currencySymbol}${ (selectedCustomer.totalDebt + total).toFixed(2) } / ${selectedCustomer.creditLimit}`}
                          </p>
                          <button onClick={() => setSelectedCustomer(null)} className="text-[10px] font-black text-red-400 uppercase tracking-widest hover:text-red-600 transition-all">
                            <i className="fas fa-times-circle mr-1"></i> {config.language === 'Somali' ? 'Ka saar macmiilkan' : 'Remove customer'}
                          </button>
                       </div>
                     )}
                  </div>

                  <button onClick={handleCompleteSale} className="w-full bg-brand-primary text-white py-6 rounded-3xl font-black text-2xl shadow-2xl active:scale-95 transition-all">{config.language === 'Somali' ? 'Xaqiiji & Xir Dalabka' : 'Confirm & Close Order'}</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

