import Login from './components/Login';
import Reports from './components/Reports';
import CustomerBook from './components/CustomerBook';
import { View, UserRole, Product, StaffMember, Order, Expense, PendingOrder, SystemConfig, Customer, Language } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';
import { translations } from './translations';

const DEFAULT_CONFIG: SystemConfig = {
  name: 'Koob Coffee',
  description: 'The Best Coffee & Snacks Experience in Mogadishu.',
  primaryColor: '#3d2b1f',
  secondaryColor: '#c6a07d',
  logoUrl: '', 
  loginBgUrl: 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&q=80',
  appBgUrl: '',
  currencySymbol: '$',
  address: 'Mogadishu, Somalia',
  phone: '+252 61 XXX XXXX',
  accountNumbers: 'EVC: 61XXXX, Dahab: 12345',
  enabledModules: ['DASHBOARD', 'POS', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS', 'CUSTOMER_BOOK'],
  version: '2.8.0', 
  autoUpdate: true,
  autoPrintReceipts: false,
  language: 'Somali'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);

  const [systemConfig, setSystemConfig] = useState<SystemConfig>(() => {
    const saved = localStorage.getItem('koob_system_config');
    const parsed = saved ? JSON.parse(saved) : DEFAULT_CONFIG;
    return { ...DEFAULT_CONFIG, ...parsed };
  });

  const t = translations[systemConfig.language];

  useEffect(() => {
    document.documentElement.style.setProperty('--brand-primary', systemConfig.primaryColor);
    document.documentElement.style.setProperty('--brand-secondary', systemConfig.secondaryColor);
    localStorage.setItem('koob_system_config', JSON.stringify(systemConfig));
  }, [systemConfig]);

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('koob_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [staff, setStaff] = useState<StaffMember[]>(() => {
    const saved = localStorage.getItem('koob_staff');
    if (saved) {
      return JSON.parse(saved).map((s: any) => ({
        ...s,
        gender: s.gender || 'Male'
      }));
    }
    return INITIAL_STAFF;
  });

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('koob_customers');
    return saved ? JSON.parse(saved).map((c: any) => ({
      ...c,
      registrationDate: c.registrationDate ? new Date(c.registrationDate) : new Date(),
      expiryDate: c.expiryDate ? new Date(c.expiryDate) : new Date(new Date().setMonth(new Date().getMonth() + 1)),
      gender: c.gender || 'Male'
    })) : [];
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('koob_orders');
    const parsed = saved ? JSON.parse(saved) : [];
    return parsed.map((o: any) => ({ ...o, timestamp: new Date(o.timestamp) }));
  });

  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>(() => {
    const saved = localStorage.getItem('koob_pending_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('koob_expenses');
    return saved ? JSON.parse(saved) : MOCK_EXPENSES;
  });

  const [taxRate, setTaxRate] = useState<number>(() => {
    const saved = localStorage.getItem('koob_tax_rate');
    return saved ? JSON.parse(saved) : 5;
  });

  const [isTaxEnabled, setIsTaxEnabled] = useState<boolean>(() => {
    const saved = localStorage.getItem('koob_is_tax_enabled');
    return saved ? JSON.parse(saved) : true;
  });

  useEffect(() => localStorage.setItem('koob_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('koob_staff', JSON.stringify(staff)), [staff]);
  useEffect(() => localStorage.setItem('koob_customers', JSON.stringify(customers)), [customers]);
  useEffect(() => localStorage.setItem('koob_orders', JSON.stringify(orders)), [orders]);
  useEffect(() => localStorage.setItem('koob_pending_orders', JSON.stringify(pendingOrders)), [pendingOrders]);
  useEffect(() => localStorage.setItem('koob_expenses', JSON.stringify(expenses)), [expenses]);
  useEffect(() => localStorage.setItem('koob_tax_rate', JSON.stringify(taxRate)), [taxRate]);
  useEffect(() => localStorage.setItem('koob_is_tax_enabled', JSON.stringify(isTaxEnabled)), [isTaxEnabled]);

  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
    if (matchedStaff.role === UserRole.WAITER || matchedStaff.role === UserRole.CASHIER) {
      setCurrentView('POS');
    } else {
      setCurrentView('DASHBOARD');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const setLanguage = (lang: Language) => {
    setSystemConfig(prev => ({ ...prev, language: lang }));
  };

  const handleCompleteOrder = (order: Order, pendingOrderId?: string) => {
    setOrders(prev => [order, ...prev]);

    setProducts(prev => prev.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) return { ...p, stock: p.stock - itemInOrder.quantity };
      return p;
    }));

    if (order.paymentMethod === 'Credit' && order.customerName) {
      setCustomers(prev => {
        const existing = order.customerId 
          ? prev.find(c => c.id === order.customerId)
          : prev.find(c => c.name.toLowerCase() === order.customerName?.toLowerCase());

        if (existing) {
          return prev.map(c => c.id === existing.id ? { ...c, totalDebt: c.totalDebt + order.total, lastTransaction: new Date() } : c);
        } else {
          const newCust: Customer = {
            id: `C-${Date.now()}`,
            name: order.customerName!,
            phone: 'N/A',
            gender: 'Male',
            creditLimit: 500,
            registrationDate: new Date(),
            expiryDate: new Date(new Date().setMonth(new Date().getMonth() + 1)),
            totalDebt: order.total,
            lastTransaction: new Date()
          };
          order.customerId = newCust.id;
          return [...prev, newCust];
        }
      });
    }

    if (pendingOrderId) {
      setPendingOrders(prev => prev.filter(po => po.id !== pendingOrderId));
    }
  };

  const handleUpdatePendingOrder = (updated: PendingOrder) => {
    setPendingOrders(prev => prev.map(po => po.id === updated.id ? updated : po));
  };

  const handleDeletePendingOrder = (id: string) => {
    if (confirm(systemConfig.language === 'Somali' ? "Ma hubtaa inaad tirtirto dalabkan?" : "Are you sure?")) {
      setPendingOrders(prev => prev.filter(po => po.id !== id));
    }
  };

  const handleDeleteProduct = (id: string) => {
    const confirmationMsg = systemConfig.language === 'Somali' 
      ? "Ma hubtaa inaad tirtirto alaabtan? Waxay sidoo kale ka tirtirmi doontaa dhamaan dalabyada furan (Pending Orders) ee ay ku jirtay." 
      : "Are you sure you want to delete this product? It will also be removed from any open pending orders.";

    if (confirm(confirmationMsg)) {
      // 1. Tirtir alaabta inventory-ga
      setProducts(prev => prev.filter(p => p.id !== id));

      // 2. Automatic cleanup: Ka saar dalabyada furan
      setPendingOrders(prev => {
        return prev.map(order => {
          const updatedItems = order.items.filter(item => item.productId !== id);

          // Haddii dalabku eber noqdo, tirtir isna
          if (updatedItems.length === 0) return null;

          // Haddii kale, dib u xisaabi lacagta (Subtotal & Total)
          const subtotal = updatedItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
          const tax = order.tax > 0 ? (subtotal * (taxRate / 100)) : 0;

          return {
            ...order,
            items: updatedItems,
            subtotal,
            tax,
            total: subtotal + tax
          };
        }).filter((order): order is PendingOrder => order !== null);
      });
    }
  };

  const handleClearDebt = (customerId: string, amount: number) => {
    setCustomers(prev => prev.map(c => 
      c.id === customerId ? { ...c, totalDebt: Math.max(0, c.totalDebt - amount), lastTransaction: new Date() } : c
    ));

    const customer = customers.find(c => c.id === customerId);
    if (customer) {
      const paymentOrder: Order = {
        id: `PAY-${Date.now()}`,
        items: [],
        subtotal: 0,
        tax: 0,
        total: amount,
        discount: 0,
        paymentMethod: 'Cash',
        timestamp: new Date(),
        staffId: currentUser?.id || 'System',
        customerName: customer.name,
        customerId: customer.id
      };
      setOrders(prev => [paymentOrder, ...prev]);
    }
  };

  const handleAddManualDebt = (customerId: string, amount: number, note: string) => {
    setCustomers(prev => prev.map(c => 
      c.id === customerId ? { ...c, totalDebt: c.totalDebt + amount, lastTransaction: new Date() } : c
    ));

    const customer = customers.find(c => c.id === customerId);
    if (customer) {
      const debtOrder: Order = {
        id: `DEBT-${Date.now()}`,
        items: [], 
        subtotal: amount,
        tax: 0,
        total: amount,
        discount: 0,
        paymentMethod: 'Credit',
        timestamp: new Date(),
        staffId: currentUser?.id || 'System',
        customerName: customer.name,
        customerId: customer.id
      };
      setOrders(prev => [debtOrder, ...prev]);
    }
  };

  const handleAddCustomer = (customer: Customer) => {
    setCustomers(prev => [...prev, customer]);
  };

  const handleUpdateCustomer = (updated: Customer) => {
    setCustomers(prev => prev.map(c => c.id === updated.id ? updated : c));
  };

  const handleDeleteCustomer = (id: string) => {
    setCustomers(prev => prev.filter(c => c.id !== id));
  };

  const renderView = () => {
    if (!currentUser) return null;
    if (currentView !== 'SETTINGS' && currentView !== 'DASHBOARD' && !systemConfig.enabledModules.includes(currentView)) {
        return <Dashboard products={products} orders={orders} systemName={systemConfig.name} config={systemConfig} />;
    }

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} systemName={systemConfig.name} config={systemConfig} />;
      case 'POS': return (
        <POS 
          products={products} 
          customers={customers}
          onCompleteOrder={handleCompleteOrder} 
          onAddPendingOrder={(po) => setPendingOrders(prev => [po, ...prev])}
          onUpdatePendingOrder={handleUpdatePendingOrder}
          onDeletePendingOrder={handleDeletePendingOrder}
          pendingOrders={pendingOrders}
          currentUser={currentUser}
          taxRate={taxRate}
          globalTaxEnabled={isTaxEnabled}
          config={systemConfig}
        />
      );
      case 'CUSTOMER_BOOK': 
        return (
          <CustomerBook 
            customers={customers} 
            orders={orders} 
            config={systemConfig} 
            onUpdateCustomer={handleUpdateCustomer}
            onAddCustomer={handleAddCustomer}
            onDeleteCustomer={handleDeleteCustomer}
            onClearDebt={handleClearDebt}
            onAddManualDebt={handleAddManualDebt}
          />
        );
      case 'INVENTORY': return (
        <Inventory 
          products={products} 
          onAddProduct={(p) => setProducts(prev => [p, ...prev])} 
          onUpdateProduct={(u) => setProducts(prev => prev.map(p => p.id === u.id ? u : p))}
          onDeleteProduct={handleDeleteProduct}
          currentUser={currentUser}
          config={systemConfig}
        />
      );
      case 'STAFF': return (
        <Staff 
          staff={staff} 
          onAddStaff={(s) => setStaff(prev => [s, ...prev])} 
          onUpdateStaff={(u) => setStaff(prev => prev.map(s => s.id === u.id ? u : s))} 
          onDeleteStaff={(id) => setStaff(prev => prev.filter(s => s.id !== id))}
          currentUser={currentUser} 
          config={systemConfig}
        />
      );
      case 'FINANCE': return <Finance orders={orders} expenses={expenses} onAddExpense={(e) => setExpenses(prev => [e, ...prev])} config={systemConfig} />;
      case 'SETTINGS': return (
        <Settings 
          taxRate={taxRate} 
          onUpdateTaxRate={setTaxRate}
          isTaxEnabled={isTaxEnabled}
          onToggleTax={setIsTaxEnabled}
          systemConfig={systemConfig}
          onUpdateConfig={setSystemConfig}
          onResetData={() => { localStorage.clear(); window.location.reload(); }}
        />
      );
      case 'REPORTS': 
        return (
          <Reports 
            orders={orders} 
            products={products} 
            staff={staff} 
            config={systemConfig} 
          />
        );
      default: return <Dashboard products={products} orders={orders} systemName={systemConfig.name} config={systemConfig} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} config={systemConfig} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50 relative overflow-hidden">
      {systemConfig.appBgUrl && (
        <div className="absolute inset-0 z-0 opacity-5 pointer-events-none">
          <img src={systemConfig.appBgUrl} className="w-full h-full object-cover" alt="" />
        </div>
      )}

      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        userRole={currentUser.role} 
        currentUser={currentUser} 
        config={systemConfig} 
        onLanguageChange={setLanguage}
      />

      <main className="flex-1 overflow-y-auto relative z-10">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between no-print">
          <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">
            {t[currentView.toLowerCase()] || currentView.replace('_', ' ')}
          </h2>
          <div className="flex items-center gap-6">
            <button onClick={handleLogout} className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2">
              <i className="fas fa-sign-out-alt"></i> {t.logout}
            </button>
            <div className="h-8 w-[1px] bg-gray-200"></div>
            <div className="flex items-center gap-2">
               <div className="text-right hidden sm:block">
                  <p className="text-sm font-bold text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] text-brand-secondary uppercase font-bold tracking-widest">{currentUser.role}</p>
               </div>
               <div className="w-10 h-10 bg-brand-primary rounded-xl flex items-center justify-center text-white shadow-lg border border-white/20">
                  <i className="fas fa-user-check"></i>
               </div>
            </div>
          </div>
        </header>
        <div className="animate-fadeIn">
          {renderView()}
        </div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        :root {
          --brand-primary: ${systemConfig.primaryColor};
          --brand-secondary: ${systemConfig.secondaryColor};
        }
        .bg-brand-primary { background-color: var(--brand-primary); }
        .bg-brand-secondary { background-color: var(--brand-secondary); }
        .text-brand-primary { color: var(--brand-primary); }
        .text-brand-secondary { color: var(--brand-secondary); }
        .border-brand-primary { border-color: var(--brand-primary); }
        .border-brand-secondary { border-color: var(--brand-secondary); }
        .ring-brand-secondary:focus { --tw-ring-color: var(--brand-secondary); }

        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scaleIn { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { SystemConfig, View, Language } from '../types';
import { translations } from '../translations';

interface SettingsProps {
  taxRate: number;
  onUpdateTaxRate: (rate: number) => void;
  isTaxEnabled: boolean;
  onToggleTax: (enabled: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateConfig: (config: SystemConfig) => void;
  onResetData: () => void;
}

const DefaultLogoSVG = () => (
  <svg viewBox="0 0 100 100" className="w-12 h-12 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Settings: React.FC<SettingsProps> = ({ 
  taxRate, onUpdateTaxRate, isTaxEnabled, onToggleTax, 
  systemConfig, onUpdateConfig, onResetData 
}) => {
  const [activeTab, setActiveTab] = useState<'General' | 'Appearance' | 'Modules' | 'Language' | 'Advanced'>('General');
  const [tempConfig, setTempConfig] = useState<SystemConfig>(systemConfig);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);

  const [updateStatus, setUpdateStatus] = useState<'idle' | 'checking' | 'available' | 'updating' | 'restarting'>('idle');
  const [updateProgress, setUpdateProgress] = useState(0);

  const logoInputRef = useRef<HTMLInputElement>(null);
  const loginBgInputRef = useRef<HTMLInputElement>(null);
  const appBgInputRef = useRef<HTMLInputElement>(null);
  const restoreInputRef = useRef<HTMLInputElement>(null);

  const t = translations[systemConfig.language];

  const handleSave = () => {
    onUpdateConfig(tempConfig);
    onUpdateTaxRate(taxRate);
    onToggleTax(isTaxEnabled);
    setMessage({ text: t.save_changes, type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleBackup = () => {
    const backupData: Record<string, string> = {};
    const keys = [
      'koob_products', 'koob_staff', 'koob_customers', 'koob_orders', 
      'koob_pending_orders', 'koob_expenses', 'koob_tax_rate', 
      'koob_is_tax_enabled', 'koob_system_config'
    ];

    keys.forEach(key => {
      const val = localStorage.getItem(key);
      if (val) backupData[key] = val;
    });

    const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Koob_Coffee_Backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    setMessage({ text: "Backup-ka waa la soo dejiyay!", type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!confirm(systemConfig.language === 'Somali' ? "Digniin: Soo celinta xogtani waxay tirtiri doontaa xogta hadda jirta. Ma rabtaa inaad sii wadid?" : "Warning: Restoring will overwrite current data. Continue?")) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        Object.entries(data).forEach(([key, val]) => {
          localStorage.setItem(key, val as string);
        });
        setMessage({ text: "Xogtii waa la soo celiyay! System-ka ayaa dib u furmaya...", type: 'success' });
        setTimeout(() => window.location.reload(), 2000);
      } catch (err) {
        alert("File-ku ma saxna.");
      }
    };
    reader.readAsText(file);
  };

  const handleLanguageUpdate = (lang: Language) => {
    const updated = { ...tempConfig, language: lang };
    setTempConfig(updated);
    onUpdateConfig(updated);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'logoUrl' | 'loginBgUrl' | 'appBgUrl') => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        alert("Sawirku aad buu u weyn yahay (Max 5MB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempConfig({ ...tempConfig, [field]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const toggleModule = (module: View) => {
    const enabled = [...tempConfig.enabledModules];
    if (enabled.includes(module)) {
      if (module === 'DASHBOARD' || module === 'SETTINGS') return; 
      setTempConfig({ ...tempConfig, enabledModules: enabled.filter(m => m !== module) });
    } else {
      setTempConfig({ ...tempConfig, enabledModules: [...enabled, module] });
    }
  };

  const checkUpdate = () => {
    setUpdateStatus('checking');
    setTimeout(() => {
      setUpdateStatus('available');
    }, 2000);
  };

  const startUpdate = () => {
    setUpdateStatus('updating');
    setUpdateProgress(0);
    const interval = setInterval(() => {
      setUpdateProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setUpdateStatus('restarting');
          setTimeout(() => {
            const nextVersion = `2.9.${Math.floor(Math.random() * 10)}`;
            const updatedConfig = { ...tempConfig, version: nextVersion };
            onUpdateConfig(updatedConfig);
            setUpdateStatus('idle');
            setUpdateProgress(0);
            setMessage({ text: `Software Updated to v${nextVersion}! No data was lost.`, type: 'success' });
          }, 2000);
          return 100;
        }
        return prev + 5;
      });
    }, 200);
  };

  const renderTabContent = () => {
    switch (activeTab) {
      case 'General':
        return (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-blue-100 text-blue-600 rounded-xl flex items-center justify-center"><i className="fas fa-info-circle"></i></div>
               {t.business_info}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.name}</label>
                <input value={tempConfig.name} onChange={e => setTempConfig({...tempConfig, name: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.description}</label>
                <input value={tempConfig.description} onChange={e => setTempConfig({...tempConfig, description: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.phone}</label>
                <input value={tempConfig.phone} onChange={e => setTempConfig({...tempConfig, phone: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.address}</label>
                <input value={tempConfig.address} onChange={e => setTempConfig({...tempConfig, address: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.currency}</label>
                <input value={tempConfig.currencySymbol} onChange={e => setTempConfig({...tempConfig, currencySymbol: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-center text-xl" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Tax Rate (%)</label>
                <input type="number" value={taxRate} onChange={e => onUpdateTaxRate(parseFloat(e.target.value))} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-center text-xl" />
              </div>
            </div>
          </div>
        );
      case 'Appearance':
        return (
          <div className="space-y-8 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-pink-100 text-pink-600 rounded-xl flex items-center justify-center"><i className="fas fa-brush"></i></div>
               {t.system_branding}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.theme_colors}</label>
                  <div className="grid grid-cols-2 gap-4">
                     <div className="p-4 bg-gray-50 rounded-2xl flex items-center justify-between">
                        <span className="text-xs font-bold text-gray-600">Primary</span>
                        <input type="color" value={tempConfig.primaryColor} onChange={e => setTempConfig({...tempConfig, primaryColor: e.target.value})} className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-none" />
                     </div>
                     <div className="p-4 bg-gray-50 rounded-2xl flex items-center justify-between">
                        <span className="text-xs font-bold text-gray-600">Secondary</span>
                        <input type="color" value={tempConfig.secondaryColor} onChange={e => setTempConfig({...tempConfig, secondaryColor: e.target.value})} className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-none" />
                     </div>
                  </div>
               </div>
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Logo</label>
                  <div className="flex items-center gap-4 p-4 bg-gray-50 rounded-2xl">
                     <div className="w-16 h-16 bg-white rounded-xl border border-gray-200 overflow-hidden flex items-center justify-center">
                        {tempConfig.logoUrl ? <img src={tempConfig.logoUrl} className="w-full h-full object-cover" /> : <DefaultLogoSVG />}
                     </div>
                     <button onClick={() => logoInputRef.current?.click()} className="px-4 py-2 bg-white text-brand-primary border border-brand-primary rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-brand-primary hover:text-white transition-all">
                        {t.logo_upload}
                     </button>
                     <input type="file" ref={logoInputRef} onChange={e => handleFileUpload(e, 'logoUrl')} className="hidden" accept="image/*" />
                  </div>
               </div>
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.login_bg}</label>
                  <div className="relative group rounded-3xl overflow-hidden border-2 border-dashed border-gray-200 hover:border-brand-secondary transition-all">
                     <img src={tempConfig.loginBgUrl} className="w-full h-32 object-cover opacity-50 group-hover:opacity-80" />
                     <button onClick={() => loginBgInputRef.current?.click()} className="absolute inset-0 flex items-center justify-center text-xs font-black uppercase tracking-widest text-brand-primary group-hover:scale-110 transition-transform">
                        Change Image
                     </button>
                     <input type="file" ref={loginBgInputRef} onChange={e => handleFileUpload(e, 'loginBgUrl')} className="hidden" accept="image/*" />
                  </div>
               </div>
            </div>
          </div>
        );
      case 'Modules':
        const modules: View[] = ['DASHBOARD', 'POS', 'CUSTOMER_BOOK', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS'];
        return (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center"><i className="fas fa-layer-group"></i></div>
               {t.module_management}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
               {modules.map(mod => (
                 <button 
                  key={mod} 
                  onClick={() => toggleModule(mod)}
                  className={`p-6 rounded-3xl border-2 transition-all text-left flex items-center justify-between group ${tempConfig.enabledModules.includes(mod) ? 'border-brand-secondary bg-brand-secondary/5' : 'bg-gray-50 border-transparent opacity-60'}`}
                 >
                    <div>
                       <h4 className="font-black text-sm text-gray-800 uppercase tracking-widest">{t[mod.toLowerCase()] || mod.replace('_', ' ')}</h4>
                       <p className="text-[10px] text-gray-400 font-bold uppercase">{tempConfig.enabledModules.includes(mod) ? 'Enabled' : 'Disabled'}</p>
                    </div>
                    <div className={`w-12 h-6 rounded-full p-1 transition-all ${tempConfig.enabledModules.includes(mod) ? 'bg-brand-secondary' : 'bg-gray-300'}`}>
                       <div className={`w-4 h-4 bg-white rounded-full shadow-md transition-all transform ${tempConfig.enabledModules.includes(mod) ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </div>
                 </button>
               ))}
            </div>
          </div>
        );
      case 'Language':
        return (
          <div className="space-y-8 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-purple-100 text-purple-600 rounded-xl flex items-center justify-center"><i className="fas fa-globe"></i></div>
               {t.language}
            </h3>
            <div className="grid grid-cols-2 gap-6 max-w-md">
               <button 
                onClick={() => handleLanguageUpdate('Somali')}
                className={`p-10 rounded-[2.5rem] border-4 transition-all flex flex-col items-center gap-4 ${systemConfig.language === 'Somali' ? 'border-brand-secondary bg-brand-secondary/5 scale-105 shadow-xl' : 'border-transparent bg-gray-50 hover:bg-gray-100'}`}
               >
                  <span className="text-5xl">🇸🇴</span>
                  <span className="font-black uppercase tracking-widest text-gray-800">Soomaali</span>
               </button>
               <button 
                onClick={() => handleLanguageUpdate('English')}
                className={`p-10 rounded-[2.5rem] border-4 transition-all flex flex-col items-center gap-4 ${systemConfig.language === 'English' ? 'border-brand-secondary bg-brand-secondary/5 scale-105 shadow-xl' : 'border-transparent bg-gray-50 hover:bg-gray-100'}`}
               >
                  <span className="text-5xl">🇺🇸</span>
                  <span className="font-black uppercase tracking-widest text-gray-800">English</span>
               </button>
            </div>
          </div>
        );
      case 'Advanced':
        return (
          <div className="space-y-12 animate-fadeIn">
            <div className="space-y-6">
              <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
                <div className="w-10 h-10 bg-green-100 text-green-600 rounded-xl flex items-center justify-center"><i className="fas fa-database"></i></div>
                Xogta & Kaydka (Data Safety)
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div className="p-6 bg-gray-50 rounded-[2rem] border border-gray-100 space-y-4">
                    <h4 className="font-black text-gray-800 text-sm uppercase">{t.backup_data}</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">{t.backup_desc}</p>
                    <button onClick={handleBackup} className="w-full py-3 bg-white border-2 border-brand-secondary text-brand-primary rounded-xl font-black text-xs uppercase tracking-widest hover:bg-brand-secondary hover:text-white transition-all">
                       <i className="fas fa-download mr-2"></i> Download Backup
                    </button>
                 </div>
                 <div className="p-6 bg-gray-50 rounded-[2rem] border border-gray-100 space-y-4">
                    <h4 className="font-black text-gray-800 text-sm uppercase">{t.restore_data}</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">{t.restore_desc}</p>
                    <button onClick={() => restoreInputRef.current?.click()} className="w-full py-3 bg-white border-2 border-indigo-500 text-indigo-600 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 hover:text-white transition-all">
                       <i className="fas fa-upload mr-2"></i> Restore From File
                    </button>
                    <input type="file" ref={restoreInputRef} onChange={handleRestore} className="hidden" accept=".json" />
                 </div>
              </div>
            </div>

            <div className="space-y-6">
              <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
                <div className="w-10 h-10 bg-blue-100 text-blue-600 rounded-xl flex items-center justify-center"><i className="fas fa-sync-alt"></i></div>
                {t.system_update}
              </h3>
              <div className="p-8 bg-gray-50 rounded-[2.5rem] border border-gray-100 space-y-6">
                 <div className="flex items-center justify-between">
                    <div>
                       <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{t.current_version}</p>
                       <h4 className="text-2xl font-black text-gray-800">v{tempConfig.version}</h4>
                    </div>
                    {updateStatus === 'idle' && (
                      <button onClick={checkUpdate} className="px-6 py-3 bg-white border border-gray-200 text-gray-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:border-brand-secondary hover:text-brand-secondary transition-all">
                        {t.check_update}
                      </button>
                    )}
                 </div>
                 {updateStatus === 'available' && (
                    <div className="p-6 bg-brand-secondary/10 rounded-3xl border border-brand-secondary/20 animate-fadeIn">
                       <button onClick={startUpdate} className="w-full py-4 bg-brand-primary text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:scale-105 transition-all">
                          {t.install_update} (Safe Update)
                       </button>
                    </div>
                 )}
                 {(updateStatus === 'updating' || updateStatus === 'restarting') && (
                   <div className="space-y-4">
                      <div className="h-4 bg-white rounded-full overflow-hidden p-1 shadow-inner border border-gray-200">
                         <div className="h-full bg-brand-secondary rounded-full transition-all duration-300 shadow-lg" style={{ width: `${updateProgress}%` }}></div>
                      </div>
                   </div>
                 )}
              </div>
            </div>

            <div className="space-y-6">
              <h3 className="text-xl font-black text-red-600 flex items-center gap-3">
                <div className="w-10 h-10 bg-red-100 text-red-600 rounded-xl flex items-center justify-center"><i className="fas fa-exclamation-triangle"></i></div>
                {t.danger_zone}
              </h3>
              <div className="p-8 border-2 border-dashed border-red-200 rounded-[2.5rem] bg-red-50/30">
                 <p className="text-sm font-bold text-red-600 mb-6 uppercase tracking-wider">Digniin: Tallaabadan dib loogama noqon karo. Waxay tirtiraysaa dhamaan iibka, macaamiisha, iyo alaabta.</p>
                 <button onClick={() => { if(confirm(t.reset_system + "?")) onResetData(); }} className="px-8 py-4 bg-red-600 text-white rounded-2xl font-black shadow-lg hover:scale-105 active:scale-95 transition-all">
                    {t.reset_system}
                 </button>
              </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto pb-24 animate-fadeIn">
      <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tight">{t.settings}</h2>
          <p className="text-gray-500 font-medium text-lg">Halkan kaga bedel nidaamka oo dhan.</p>
        </div>
        <button onClick={handleSave} disabled={updateStatus !== 'idle'} className="px-10 py-5 bg-brand-primary text-white rounded-[2rem] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3 disabled:opacity-50">
          <i className="fas fa-save text-xl"></i> {t.save_changes}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row gap-10">
        <aside className="lg:w-72 space-y-2">
          {['General', 'Appearance', 'Modules', 'Language', 'Advanced'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold uppercase tracking-widest text-[10px] ${activeTab === tab ? 'bg-brand-secondary text-white shadow-xl' : 'bg-white text-gray-400 hover:bg-gray-50'}`}>
              {tab}
            </button>
          ))}
        </aside>

        <div className="flex-1 bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100 min-h-[600px]">
          {renderTabContent()}
        </div>
      </div>

      {message && (
        <div className={`fixed bottom-10 right-10 px-8 py-5 rounded-3xl shadow-2xl animate-fadeIn z-[200] border-2 flex items-center gap-3 ${message.type === 'success' ? 'bg-brand-primary text-white border-white/20' : 'bg-red-600 text-white border-white/20'}`}>
          <i className="fas fa-check-circle text-xl"></i>
          <p className="font-black uppercase tracking-widest text-xs">{message.text}</p>
        </div>
      )}
    </div>
  );
};

export default Settings;

import React, { useState, useRef, useEffect } from 'react';
import { SystemConfig, View, Language } from '../types';
import { translations } from '../translations';

interface SettingsProps {
  taxRate: number;
  onUpdateTaxRate: (rate: number) => void;
  isTaxEnabled: boolean;
  onToggleTax: (enabled: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateConfig: (config: SystemConfig) => void;
  onResetData: () => void;
}

const DefaultLogoSVG = () => (
  <svg viewBox="0 0 100 100" className="w-12 h-12 fill-brand-primary">
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const Settings: React.FC<SettingsProps> = ({ 
  taxRate, onUpdateTaxRate, isTaxEnabled, onToggleTax, 
  systemConfig, onUpdateConfig, onResetData 
}) => {
  const [activeTab, setActiveTab] = useState<'General' | 'Appearance' | 'Modules' | 'Language' | 'Advanced'>('General');
  const [tempConfig, setTempConfig] = useState<SystemConfig>(systemConfig);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);

  const [updateStatus, setUpdateStatus] = useState<'idle' | 'checking' | 'available' | 'updating' | 'restarting'>('idle');
  const [updateProgress, setUpdateProgress] = useState(0);

  const logoInputRef = useRef<HTMLInputElement>(null);
  const loginBgInputRef = useRef<HTMLInputElement>(null);
  const appBgInputRef = useRef<HTMLInputElement>(null);
  const restoreInputRef = useRef<HTMLInputElement>(null);

  const t = translations[systemConfig.language];

  const handleSave = () => {
    onUpdateConfig(tempConfig);
    onUpdateTaxRate(taxRate);
    onToggleTax(isTaxEnabled);
    setMessage({ text: t.save_changes, type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleBackup = () => {
    const backupData: Record<string, string> = {};
    const keys = [
      'koob_products', 'koob_staff', 'koob_customers', 'koob_orders', 
      'koob_pending_orders', 'koob_expenses', 'koob_tax_rate', 
      'koob_is_tax_enabled', 'koob_system_config'
    ];

    keys.forEach(key => {
      const val = localStorage.getItem(key);
      if (val) backupData[key] = val;
    });

    const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Koob_Coffee_Backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    setMessage({ text: "Backup-ka waa la soo dejiyay!", type: 'success' });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!confirm(systemConfig.language === 'Somali' ? "Digniin: Soo celinta xogtani waxay tirtiri doontaa xogta hadda jirta. Ma rabtaa inaad sii wadid?" : "Warning: Restoring will overwrite current data. Continue?")) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        Object.entries(data).forEach(([key, val]) => {
          localStorage.setItem(key, val as string);
        });
        setMessage({ text: "Xogtii waa la soo celiyay! System-ka ayaa dib u furmaya...", type: 'success' });
        setTimeout(() => window.location.reload(), 2000);
      } catch (err) {
        alert("File-ku ma saxna.");
      }
    };
    reader.readAsText(file);
  };

  const handleLanguageUpdate = (lang: Language) => {
    const updated = { ...tempConfig, language: lang };
    setTempConfig(updated);
    onUpdateConfig(updated);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'logoUrl' | 'loginBgUrl' | 'appBgUrl') => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        alert("Sawirku aad buu u weyn yahay (Max 5MB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempConfig({ ...tempConfig, [field]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const toggleModule = (module: View) => {
    const enabled = [...tempConfig.enabledModules];
    if (enabled.includes(module)) {
      if (module === 'DASHBOARD' || module === 'SETTINGS') return; 
      setTempConfig({ ...tempConfig, enabledModules: enabled.filter(m => m !== module) });
    } else {
      setTempConfig({ ...tempConfig, enabledModules: [...enabled, module] });
    }
  };

  const checkUpdate = () => {
    setUpdateStatus('checking');
    setTimeout(() => {
      setUpdateStatus('available');
    }, 2000);
  };

  const startUpdate = () => {
    setUpdateStatus('updating');
    setUpdateProgress(0);
    const interval = setInterval(() => {
      setUpdateProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setUpdateStatus('restarting');
          setTimeout(() => {
            const nextVersion = `2.9.${Math.floor(Math.random() * 10)}`;
            const updatedConfig = { ...tempConfig, version: nextVersion };
            onUpdateConfig(updatedConfig);
            setUpdateStatus('idle');
            setUpdateProgress(0);
            setMessage({ text: systemConfig.language === 'Somali' ? `System-ka waa la casriyeeyay (v${nextVersion}). Xogtaadu waa badbaado!` : `Software Updated to v${nextVersion}! All your data is safe.`, type: 'success' });
          }, 2000);
          return 100;
        }
        return prev + 5;
      });
    }, 200);
  };

  const renderTabContent = () => {
    switch (activeTab) {
      case 'General':
        return (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-blue-100 text-blue-600 rounded-xl flex items-center justify-center"><i className="fas fa-info-circle"></i></div>
               {t.business_info}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.name}</label>
                <input value={tempConfig.name} onChange={e => setTempConfig({...tempConfig, name: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.description}</label>
                <input value={tempConfig.description} onChange={e => setTempConfig({...tempConfig, description: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.phone}</label>
                <input value={tempConfig.phone} onChange={e => setTempConfig({...tempConfig, phone: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.address}</label>
                <input value={tempConfig.address} onChange={e => setTempConfig({...tempConfig, address: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.currency}</label>
                <input value={tempConfig.currencySymbol} onChange={e => setTempConfig({...tempConfig, currencySymbol: e.target.value})} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-center text-xl" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Tax Rate (%)</label>
                <input type="number" value={taxRate} onChange={e => onUpdateTaxRate(parseFloat(e.target.value))} className="w-full px-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-center text-xl" />
              </div>
            </div>
          </div>
        );
      case 'Appearance':
        return (
          <div className="space-y-8 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-pink-100 text-pink-600 rounded-xl flex items-center justify-center"><i className="fas fa-brush"></i></div>
               {t.system_branding}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.theme_colors}</label>
                  <div className="grid grid-cols-2 gap-4">
                     <div className="p-4 bg-gray-50 rounded-2xl flex items-center justify-between">
                        <span className="text-xs font-bold text-gray-600">Primary</span>
                        <input type="color" value={tempConfig.primaryColor} onChange={e => setTempConfig({...tempConfig, primaryColor: e.target.value})} className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-none" />
                     </div>
                     <div className="p-4 bg-gray-50 rounded-2xl flex items-center justify-between">
                        <span className="text-xs font-bold text-gray-600">Secondary</span>
                        <input type="color" value={tempConfig.secondaryColor} onChange={e => setTempConfig({...tempConfig, secondaryColor: e.target.value})} className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-none" />
                     </div>
                  </div>
               </div>
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Logo</label>
                  <div className="flex items-center gap-4 p-4 bg-gray-50 rounded-2xl">
                     <div className="w-16 h-16 bg-white rounded-xl border border-gray-200 overflow-hidden flex items-center justify-center">
                        {tempConfig.logoUrl ? <img src={tempConfig.logoUrl} className="w-full h-full object-cover" /> : <DefaultLogoSVG />}
                     </div>
                     <button onClick={() => logoInputRef.current?.click()} className="px-4 py-2 bg-white text-brand-primary border border-brand-primary rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-brand-primary hover:text-white transition-all">
                        {t.logo_upload}
                     </button>
                     <input type="file" ref={logoInputRef} onChange={e => handleFileUpload(e, 'logoUrl')} className="hidden" accept="image/*" />
                  </div>
               </div>
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{t.login_bg}</label>
                  <div className="relative group rounded-3xl overflow-hidden border-2 border-dashed border-gray-200 hover:border-brand-secondary transition-all">
                     <img src={tempConfig.loginBgUrl} className="w-full h-32 object-cover opacity-50 group-hover:opacity-80" />
                     <button onClick={() => loginBgInputRef.current?.click()} className="absolute inset-0 flex items-center justify-center text-xs font-black uppercase tracking-widest text-brand-primary group-hover:scale-110 transition-transform">
                        Change Image
                     </button>
                     <input type="file" ref={loginBgInputRef} onChange={e => handleFileUpload(e, 'loginBgUrl')} className="hidden" accept="image/*" />
                  </div>
               </div>
            </div>
          </div>
        );
      case 'Modules':
        const modules: View[] = ['DASHBOARD', 'POS', 'CUSTOMER_BOOK', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS'];
        return (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-indigo-100 text-indigo-600 rounded-xl flex items-center justify-center"><i className="fas fa-layer-group"></i></div>
               {t.module_management}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
               {modules.map(mod => (
                 <button 
                  key={mod} 
                  onClick={() => toggleModule(mod)}
                  className={`p-6 rounded-3xl border-2 transition-all text-left flex items-center justify-between group ${tempConfig.enabledModules.includes(mod) ? 'border-brand-secondary bg-brand-secondary/5' : 'bg-gray-50 border-transparent opacity-60'}`}
                 >
                    <div>
                       <h4 className="font-black text-sm text-gray-800 uppercase tracking-widest">{t[mod.toLowerCase()] || mod.replace('_', ' ')}</h4>
                       <p className="text-[10px] text-gray-400 font-bold uppercase">{tempConfig.enabledModules.includes(mod) ? 'Enabled' : 'Disabled'}</p>
                    </div>
                    <div className={`w-12 h-6 rounded-full p-1 transition-all ${tempConfig.enabledModules.includes(mod) ? 'bg-brand-secondary' : 'bg-gray-300'}`}>
                       <div className={`w-4 h-4 bg-white rounded-full shadow-md transition-all transform ${tempConfig.enabledModules.includes(mod) ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </div>
                 </button>
               ))}
            </div>
          </div>
        );
      case 'Language':
        return (
          <div className="space-y-8 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-purple-100 text-purple-600 rounded-xl flex items-center justify-center"><i className="fas fa-globe"></i></div>
               {t.language}
            </h3>
