                 {updateStatus === 'available' && (
                    <div className="p-6 bg-brand-secondary/10 rounded-3xl border border-brand-secondary/20 animate-fadeIn">
                       <button onClick={startUpdate} className="w-full py-4 bg-brand-primary text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:scale-105 transition-all">
                          {t.install_update} (Safe Update)
                       </button>
                    </div>
                 )}
                 {(updateStatus === 'updating' || updateStatus === 'restarting') && (
                   <div className="space-y-4">
                      <div className="flex justify-between items-end">
                         <p className="text-[9px] font-black text-brand-primary uppercase tracking-widest">Updating Engine...</p>
                         <p className="text-xs font-black text-brand-secondary tracking-widest">Data is Protected <i className="fas fa-lock"></i></p>
                      </div>
                      <div className="h-4 bg-white rounded-full overflow-hidden p-1 shadow-inner border border-gray-200">
                         <div className="h-full bg-brand-secondary rounded-full transition-all duration-300 shadow-lg" style={{ width: `${updateProgress}%` }}></div>
                      </div>
                   </div>
                 )}
              </div>
            </div>

            <div className="space-y-6">
              <h3 className="text-xl font-black text-red-600 flex items-center gap-3">
                <div className="w-10 h-10 bg-red-100 text-red-600 rounded-xl flex items-center justify-center"><i className="fas fa-exclamation-triangle"></i></div>
                {t.danger_zone}
              </h3>
              <div className="p-8 border-2 border-dashed border-red-200 rounded-[2.5rem] bg-red-50/30">
                 <p className="text-sm font-bold text-red-600 mb-6 uppercase tracking-wider">Digniin: Tallaabadan dib loogama noqon karo. Waxay tirtiraysaa dhamaan iibka, macaamiisha, iyo alaabta.</p>
                 <button onClick={() => { if(confirm(t.reset_system + "?")) onResetData(); }} className="px-8 py-4 bg-red-600 text-white rounded-2xl font-black shadow-lg hover:scale-105 active:scale-95 transition-all">
                    {t.reset_system}
                 </button>
              </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto pb-24 animate-fadeIn">
      <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tight">{t.settings}</h2>
          <p className="text-gray-500 font-medium text-lg">Halkan kaga bedel nidaamka oo dhan.</p>
        </div>
        <button onClick={handleSave} disabled={updateStatus !== 'idle'} className="px-10 py-5 bg-brand-primary text-white rounded-[2rem] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3 disabled:opacity-50">
          <i className="fas fa-save text-xl"></i> {t.save_changes}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row gap-10">
        <aside className="lg:w-72 space-y-2">
          {['General', 'Appearance', 'Modules', 'Language', 'Advanced'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} disabled={updateStatus !== 'idle'} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold uppercase tracking-widest text-[10px] ${activeTab === tab ? 'bg-brand-secondary text-white shadow-xl' : 'bg-white text-gray-400 hover:bg-gray-50'}`}>
              {tab}
            </button>
          ))}
        </aside>

        <div className="flex-1 bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100 min-h-[600px]">
          {renderTabContent()}
        </div>
      </div>

      {message && (
        <div className={`fixed bottom-10 right-10 px-8 py-5 rounded-3xl shadow-2xl animate-fadeIn z-[200] border-2 flex items-center gap-3 ${message.type === 'success' ? 'bg-brand-primary text-white border-white/20' : 'bg-red-600 text-white border-white/20'}`}>
          <i className="fas fa-check-circle text-xl"></i>
          <p className="font-black uppercase tracking-widest text-xs">{message.text}</p>
        </div>
      )}
    </div>
  );
};

export default Settings;

export class KoobDB {
  private dbName = 'KoobCoffeeDB';
  private version = 1;

  async open(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.dbName, this.version);

      request.onupgradeneeded = (event: any) => {
        const db = event.target.result;
        if (!db.objectStoreNames.contains('products')) db.createObjectStore('products', { keyPath: 'id' });
        if (!db.objectStoreNames.contains('orders')) db.createObjectStore('orders', { keyPath: 'id' });
        if (!db.objectStoreNames.contains('customers')) db.createObjectStore('customers', { keyPath: 'id' });
        if (!db.objectStoreNames.contains('staff')) db.createObjectStore('staff', { keyPath: 'id' });
        if (!db.objectStoreNames.contains('expenses')) db.createObjectStore('expenses', { keyPath: 'id' });
        if (!db.objectStoreNames.contains('config')) db.createObjectStore('config', { keyPath: 'id' });
      };

      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  async getAll(storeName: string): Promise<any[]> {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(storeName, 'readonly');
      const store = transaction.objectStore(storeName);
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  async put(storeName: string, data: any): Promise<void> {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(storeName, 'readwrite');
      const store = transaction.objectStore(storeName);
      const request = store.put(data);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }

  async delete(storeName: string, id: string): Promise<void> {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(storeName, 'readwrite');
      const store = transaction.objectStore(storeName);
      const request = store.delete(id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }

  async clearStore(storeName: string): Promise<void> {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(storeName, 'readwrite');
      const store = transaction.objectStore(storeName);
      const request = store.clear();
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }
}

export const db = new KoobDB();

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import Inventory from './components/Inventory';
import Staff from './components/Staff';
import Finance from './components/Finance';
import Settings from './components/Settings';
import Login from './components/Login';
import Reports from './components/Reports';
import CustomerBook from './components/CustomerBook';
import { View, UserRole, Product, StaffMember, Order, Expense, PendingOrder, SystemConfig, Customer, Language } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';
import { translations } from './translations';
import { db } from './db';

const DEFAULT_CONFIG: SystemConfig = {
  name: 'Koob Coffee',
  description: 'The Best Coffee & Snacks Experience in Mogadishu.',
  primaryColor: '#3d2b1f',
  secondaryColor: '#c6a07d',
  logoUrl: '', 
  loginBgUrl: 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&q=80',
  appBgUrl: '',
  currencySymbol: '$',
  address: 'Mogadishu, Somalia',
  phone: '+252 61 XXX XXXX',
  accountNumbers: 'EVC: 61XXXX, Dahab: 12345',
  enabledModules: ['DASHBOARD', 'POS', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS', 'CUSTOMER_BOOK'],
  version: '3.0.0-DB', 
  autoUpdate: true,
  autoPrintReceipts: false,
  language: 'Somali'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);
  const [dbReady, setDbReady] = useState(false);

  const [systemConfig, setSystemConfig] = useState<SystemConfig>(DEFAULT_CONFIG);
  const [products, setProducts] = useState<Product[]>([]);
  const [staff, setStaff] = useState<StaffMember[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [taxRate, setTaxRate] = useState<number>(5);
  const [isTaxEnabled, setIsTaxEnabled] = useState<boolean>(true);

  // Initialize Database on Mount
  useEffect(() => {
    const initDB = async () => {
      try {
        const savedConfig = await db.getAll('config');
        if (savedConfig.length > 0) {
          setSystemConfig({ ...DEFAULT_CONFIG, ...savedConfig[0] });
        } else {
          await db.put('config', { ...DEFAULT_CONFIG, id: 'main' });
        }

        const loadedProducts = await db.getAll('products');
        if (loadedProducts.length === 0) {
          for (const p of INITIAL_PRODUCTS) await db.put('products', p);
          setProducts(INITIAL_PRODUCTS);
        } else {
          setProducts(loadedProducts);
        }

        const loadedStaff = await db.getAll('staff');
        if (loadedStaff.length === 0) {
          for (const s of INITIAL_STAFF) await db.put('staff', s);
          setStaff(INITIAL_STAFF);
        } else {
          setStaff(loadedStaff);
        }

        const loadedCustomers = await db.getAll('customers');
        setCustomers(loadedCustomers);

        const loadedOrders = await db.getAll('orders');
        setOrders(loadedOrders.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));

        const loadedExpenses = await db.getAll('expenses');
        setExpenses(loadedExpenses);

        setDbReady(true);
      } catch (err) {
        console.error("Database initialization failed:", err);
      }
    };

    initDB();
  }, []);

  const t = translations[systemConfig.language];

  useEffect(() => {
    document.documentElement.style.setProperty('--brand-primary', systemConfig.primaryColor);
    document.documentElement.style.setProperty('--brand-secondary', systemConfig.secondaryColor);
    if (dbReady) db.put('config', { ...systemConfig, id: 'main' });
  }, [systemConfig, dbReady]);

  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
    if (matchedStaff.role === UserRole.WAITER || matchedStaff.role === UserRole.CASHIER) {
      setCurrentView('POS');
    } else {
      setCurrentView('DASHBOARD');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const handleCompleteOrder = async (order: Order, pendingOrderId?: string) => {
    // 1. Save to DB
    await db.put('orders', order);
    setOrders(prev => [order, ...prev]);

    // 2. Update stock
    const updatedProducts = products.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) {
        const updated = { ...p, stock: p.stock - itemInOrder.quantity };
        db.put('products', updated);
        return updated;
      }
      return p;
    });
    setProducts(updatedProducts);

    // 3. Update customers if credit
    if (order.paymentMethod === 'Credit' && order.customerName) {
      const existing = order.customerId 
          ? customers.find(c => c.id === order.customerId)
          : customers.find(c => c.name.toLowerCase() === order.customerName?.toLowerCase());

      if (existing) {
        const updated = { ...existing, totalDebt: existing.totalDebt + order.total, lastTransaction: new Date() };
        await db.put('customers', updated);
        setCustomers(prev => prev.map(c => c.id === existing.id ? updated : c));
      } else {
        const newCust: Customer = {
          id: `C-${Date.now()}`,
          name: order.customerName!,
          phone: 'N/A',
          gender: 'Male',
          creditLimit: 500,
          registrationDate: new Date(),
          expiryDate: new Date(new Date().setMonth(new Date().getMonth() + 1)),
          totalDebt: order.total,
          lastTransaction: new Date()
        };
        await db.put('customers', newCust);
        setCustomers(prev => [...prev, newCust]);
      }
    }

    if (pendingOrderId) {
      setPendingOrders(prev => prev.filter(po => po.id !== pendingOrderId));
    }
  };

  const handleDeleteProduct = async (id: string) => {
    const confirmationMsg = systemConfig.language === 'Somali' 
      ? "Ma hubtaa inaad tirtirto alaabtan? Database-ka ayaad ka tirtiraysaa." 
      : "Are you sure? You are deleting from the database.";

    if (confirm(confirmationMsg)) {
      await db.delete('products', id);
      setProducts(prev => prev.filter(p => p.id !== id));
      // Automatic cleanup logic from previous update follows...
      setPendingOrders(prev => prev.filter(order => !order.items.some(item => item.productId === id)));
    }
  };

  const handleAddProduct = async (p: Product) => {
    await db.put('products', p);
    setProducts(prev => [p, ...prev]);
  };

  const handleUpdateProduct = async (u: Product) => {
    await db.put('products', u);
    setProducts(prev => prev.map(p => p.id === u.id ? u : p));
  };

  const handleClearDebt = async (customerId: string, amount: number) => {
    const customer = customers.find(c => c.id === customerId);
    if (customer) {
      const updated = { ...customer, totalDebt: Math.max(0, customer.totalDebt - amount), lastTransaction: new Date() };
      await db.put('customers', updated);
      setCustomers(prev => prev.map(c => c.id === customerId ? updated : c));

      const paymentOrder: Order = {
        id: `PAY-${Date.now()}`,
        items: [],
        subtotal: 0,
        tax: 0,
        total: amount,
        discount: 0,
        paymentMethod: 'Cash',
        timestamp: new Date(),
        staffId: currentUser?.id || 'System',
        customerName: customer.name,
        customerId: customer.id
      };
      await db.put('orders', paymentOrder);
      setOrders(prev => [paymentOrder, ...prev]);
    }
  };

  const renderView = () => {
    if (!currentUser || !dbReady) return (
      <div className="h-full flex items-center justify-center p-20">
        <div className="flex flex-col items-center gap-4">
          <div className="w-16 h-16 border-4 border-brand-secondary border-t-transparent rounded-full animate-spin"></div>
          <p className="font-black text-brand-primary uppercase tracking-widest text-xs">Database Loading...</p>
        </div>
      </div>
    );

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} systemName={systemConfig.name} config={systemConfig} />;
      case 'POS': return (
        <POS 
          products={products} 
          customers={customers}
          onCompleteOrder={handleCompleteOrder} 
          onAddPendingOrder={(po) => setPendingOrders(prev => [po, ...prev])}
          onUpdatePendingOrder={(upd) => setPendingOrders(prev => prev.map(po => po.id === upd.id ? upd : po))}
          onDeletePendingOrder={(id) => setPendingOrders(prev => prev.filter(po => po.id !== id))}
          pendingOrders={pendingOrders}
          currentUser={currentUser}
          taxRate={taxRate}
          globalTaxEnabled={isTaxEnabled}
          config={systemConfig}
        />
      );
      case 'CUSTOMER_BOOK': 
        return (
          <CustomerBook 
            customers={customers} 
            orders={orders} 
            config={systemConfig} 
            onUpdateCustomer={async (c) => { await db.put('customers', c); setCustomers(prev => prev.map(x => x.id === c.id ? c : x)); }}
            onAddCustomer={async (c) => { await db.put('customers', c); setCustomers(prev => [...prev, c]); }}
            onDeleteCustomer={async (id) => { await db.delete('customers', id); setCustomers(prev => prev.filter(c => c.id !== id)); }}
            onClearDebt={handleClearDebt}
            onAddManualDebt={async (id, amt) => {
               const c = customers.find(x => x.id === id);
               if(c) {
                  const upd = {...c, totalDebt: c.totalDebt + amt};
                  await db.put('customers', upd);
                  setCustomers(prev => prev.map(x => x.id === id ? upd : x));
               }
            }}
          />
        );
      case 'INVENTORY': return (
        <Inventory 
          products={products} 
          onAddProduct={handleAddProduct} 
          onUpdateProduct={handleUpdateProduct}
          onDeleteProduct={handleDeleteProduct}
          currentUser={currentUser}
          config={systemConfig}
        />
      );
      case 'STAFF': return (
        <Staff 
          staff={staff} 
          onAddStaff={async (s) => { await db.put('staff', s); setStaff(prev => [...prev, s]); }} 
          onUpdateStaff={async (u) => { await db.put('staff', u); setStaff(prev => prev.map(s => s.id === u.id ? u : s)); }} 
          onDeleteStaff={async (id) => { await db.delete('staff', id); setStaff(prev => prev.filter(s => s.id !== id)); }}
          currentUser={currentUser} 
          config={systemConfig}
        />
      );
      case 'FINANCE': return (
        <Finance 
          orders={orders} 
          expenses={expenses} 
          onAddExpense={async (e) => { await db.put('expenses', e); setExpenses(prev => [e, ...prev]); }} 
          config={systemConfig} 
        />
      );
      case 'SETTINGS': return (
        <Settings 
          taxRate={taxRate} 
          onUpdateTaxRate={setTaxRate}
          isTaxEnabled={isTaxEnabled}
          onToggleTax={setIsTaxEnabled}
          systemConfig={systemConfig}
          onUpdateConfig={setSystemConfig}
          onResetData={async () => { 
            await db.clearStore('products');
            await db.clearStore('orders');
            await db.clearStore('customers');
            await db.clearStore('staff');
            await db.clearStore('expenses');
            await db.clearStore('config');
            window.location.reload(); 
          }}
        />
      );
      case 'REPORTS': return <Reports orders={orders} products={products} staff={staff} config={systemConfig} />;
      default: return <Dashboard products={products} orders={orders} systemName={systemConfig.name} config={systemConfig} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} config={systemConfig} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50 relative overflow-hidden">
      {systemConfig.appBgUrl && (
        <div className="absolute inset-0 z-0 opacity-5 pointer-events-none">
          <img src={systemConfig.appBgUrl} className="w-full h-full object-cover" alt="" />
        </div>
      )}

      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        userRole={currentUser.role} 
        currentUser={currentUser} 
        config={systemConfig} 
        onLanguageChange={(lang) => setSystemConfig(prev => ({ ...prev, language: lang }))}
      />

      <main className="flex-1 overflow-y-auto relative z-10">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between no-print">
          <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">
            {t[currentView.toLowerCase()] || currentView.replace('_', ' ')}
          </h2>
