            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
               {modules.map(mod => (
                 <button 
                  key={mod} 
                  onClick={() => toggleModule(mod)}
                  className={`p-6 rounded-3xl border-2 transition-all text-left flex items-center justify-between group ${tempConfig.enabledModules.includes(mod) ? 'border-brand-secondary bg-brand-secondary/5' : 'bg-gray-50 border-transparent opacity-60'}`}
                 >
                    <div>
                       <h4 className="font-black text-sm text-gray-800 uppercase tracking-widest">{t[mod.toLowerCase()] || mod.replace('_', ' ')}</h4>
                       <p className="text-[10px] text-gray-400 font-bold uppercase">{tempConfig.enabledModules.includes(mod) ? 'Enabled' : 'Disabled'}</p>
                    </div>
                    <div className={`w-12 h-6 rounded-full p-1 transition-all ${tempConfig.enabledModules.includes(mod) ? 'bg-brand-secondary' : 'bg-gray-300'}`}>
                       <div className={`w-4 h-4 bg-white rounded-full shadow-md transition-all transform ${tempConfig.enabledModules.includes(mod) ? 'translate-x-6' : 'translate-x-0'}`}></div>
                    </div>
                 </button>
               ))}
            </div>
          </div>
        );
      case 'Language':
        return (
          <div className="space-y-8 animate-fadeIn">
            <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
               <div className="w-10 h-10 bg-purple-100 text-purple-600 rounded-xl flex items-center justify-center"><i className="fas fa-globe"></i></div>
               {t.language}
            </h3>
            <div className="grid grid-cols-2 gap-6 max-w-md">
               <button 
                onClick={() => handleLanguageUpdate('Somali')}
                className={`p-10 rounded-[2.5rem] border-4 transition-all flex flex-col items-center gap-4 ${systemConfig.language === 'Somali' ? 'border-brand-secondary bg-brand-secondary/5 scale-105 shadow-xl' : 'border-transparent bg-gray-50 hover:bg-gray-100'}`}
               >
                  <span className="text-5xl">🇸🇴</span>
                  <span className="font-black uppercase tracking-widest text-gray-800">Soomaali</span>
               </button>
               <button 
                onClick={() => handleLanguageUpdate('English')}
                className={`p-10 rounded-[2.5rem] border-4 transition-all flex flex-col items-center gap-4 ${systemConfig.language === 'English' ? 'border-brand-secondary bg-brand-secondary/5 scale-105 shadow-xl' : 'border-transparent bg-gray-50 hover:bg-gray-100'}`}
               >
                  <span className="text-5xl">🇺🇸</span>
                  <span className="font-black uppercase tracking-widest text-gray-800">English</span>
               </button>
            </div>
          </div>
        );
      case 'Advanced':
        return (
          <div className="space-y-12 animate-fadeIn">
            {/* Data Guard Visual Section */}
            <div className="space-y-6">
              <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
                <div className="w-10 h-10 bg-emerald-100 text-emerald-600 rounded-xl flex items-center justify-center"><i className="fas fa-shield-halved"></i></div>
                {t.data_guard}
              </h3>
              <div className="p-6 bg-emerald-50 rounded-3xl border border-emerald-100 flex items-center gap-5">
                 <div className="w-16 h-16 bg-emerald-500 text-white rounded-2xl flex items-center justify-center text-2xl shadow-lg shadow-emerald-200">
                    <i className="fas fa-check-double"></i>
                 </div>
                 <div className="flex-1">
                    <h4 className="font-black text-emerald-800 text-sm uppercase mb-1">{t.data_guard_active}</h4>
                    <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-widest">{t.data_guard_desc}</p>
                 </div>
                 <div className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-lg text-[10px] font-black uppercase">Live DB Protected</div>
              </div>
            </div>

            <div className="space-y-6">
              <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
                <div className="w-10 h-10 bg-green-100 text-green-600 rounded-xl flex items-center justify-center"><i className="fas fa-database"></i></div>
                Database & Full Backup
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div className="p-6 bg-gray-50 rounded-[2rem] border border-gray-100 space-y-4">
                    <h4 className="font-black text-gray-800 text-sm uppercase">Full Export (DB)</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">Download all data directly from IndexedDB.</p>
                    <button onClick={handleBackup} className="w-full py-3 bg-white border-2 border-brand-secondary text-brand-primary rounded-xl font-black text-xs uppercase tracking-widest hover:bg-brand-secondary hover:text-white transition-all">
                       <i className="fas fa-download mr-2"></i> Download Full Backup
                    </button>
                 </div>
                 <div className="p-6 bg-gray-50 rounded-[2rem] border border-gray-100 space-y-4">
                    <h4 className="font-black text-gray-800 text-sm uppercase">Full Restore (DB)</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">Upload a .json file to overwrite the entire database.</p>
                    <button onClick={() => restoreInputRef.current?.click()} className="w-full py-3 bg-white border-2 border-indigo-500 text-indigo-600 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 hover:text-white transition-all">
                       <i className="fas fa-upload mr-2"></i> Restore DB from File
                    </button>
                    <input type="file" ref={restoreInputRef} onChange={handleRestore} className="hidden" accept=".json" />
                 </div>
              </div>
            </div>

            <div className="space-y-6">
              <h3 className="text-xl font-black text-gray-800 flex items-center gap-3">
                <div className="w-10 h-10 bg-blue-100 text-blue-600 rounded-xl flex items-center justify-center"><i className="fas fa-sync-alt"></i></div>
                {t.system_update}
              </h3>
              <div className="p-8 bg-gray-50 rounded-[2.5rem] border border-gray-100 space-y-6">
                 <div className="flex items-center justify-between">
                    <div>
                       <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{t.current_version}</p>
                       <h4 className="text-2xl font-black text-gray-800">v{tempConfig.version}</h4>
                    </div>
                    {updateStatus === 'idle' && (
                      <button onClick={checkUpdate} className="px-6 py-3 bg-white border border-gray-200 text-gray-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:border-brand-secondary hover:text-brand-secondary transition-all">
                        {t.check_update}
                      </button>
                    )}
                 </div>
                 {updateStatus === 'available' && (
                    <div className="p-6 bg-brand-secondary/10 rounded-3xl border border-brand-secondary/20 animate-fadeIn">
                       <button onClick={startUpdate} className="w-full py-4 bg-brand-primary text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:scale-105 transition-all">
                          {t.install_update} (Safe Update)
                       </button>
                    </div>
                 )}
                 {(updateStatus === 'updating' || updateStatus === 'restarting') && (
                   <div className="space-y-4">
                      <div className="flex justify-between items-end">
                         <p className="text-[9px] font-black text-brand-primary uppercase tracking-widest">Updating System Engine...</p>
                         <p className="text-xs font-black text-brand-secondary tracking-widest">IndexedDB is Protected <i className="fas fa-lock"></i></p>
                      </div>
                      <div className="h-4 bg-white rounded-full overflow-hidden p-1 shadow-inner border border-gray-200">
                         <div className="h-full bg-brand-secondary rounded-full transition-all duration-300 shadow-lg" style={{ width: `${updateProgress}%` }}></div>
                      </div>
                   </div>
                 )}
              </div>
            </div>

            <div className="space-y-6">
              <h3 className="text-xl font-black text-red-600 flex items-center gap-3">
                <div className="w-10 h-10 bg-red-100 text-red-600 rounded-xl flex items-center justify-center"><i className="fas fa-exclamation-triangle"></i></div>
                {t.danger_zone}
              </h3>
              <div className="p-8 border-2 border-dashed border-red-200 rounded-[2.5rem] bg-red-50/30">
                 <p className="text-sm font-bold text-red-600 mb-6 uppercase tracking-wider">Digniin: Tallaabadan dib loogama noqon karo. Waxay tirtiraysaa dhamaan iibka, macaamiisha, iyo alaabta ku jirta Database-ka.</p>
                 <button onClick={() => { if(confirm(t.reset_system + "?")) onResetData(); }} className="px-8 py-4 bg-red-600 text-white rounded-2xl font-black shadow-lg hover:scale-105 active:scale-95 transition-all">
                    {t.reset_system}
                 </button>
              </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto pb-24 animate-fadeIn">
      <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tight">{t.settings}</h2>
          <p className="text-gray-500 font-medium text-lg">Halkan kaga bedel nidaamka oo dhan.</p>
        </div>
        <button onClick={handleSave} disabled={updateStatus !== 'idle'} className="px-10 py-5 bg-brand-primary text-white rounded-[2rem] font-black shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3 disabled:opacity-50">
          <i className="fas fa-save text-xl"></i> {t.save_changes}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row gap-10">
        <aside className="lg:w-72 space-y-2">
          {['General', 'Appearance', 'Modules', 'Language', 'Advanced'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} disabled={updateStatus !== 'idle'} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all font-bold uppercase tracking-widest text-[10px] ${activeTab === tab ? 'bg-brand-secondary text-white shadow-xl' : 'bg-white text-gray-400 hover:bg-gray-50'}`}>
              {tab}
            </button>
          ))}
        </aside>

        <div className="flex-1 bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100 min-h-[600px]">
          {renderTabContent()}
        </div>
      </div>

      {message && (
        <div className={`fixed bottom-10 right-10 px-8 py-5 rounded-3xl shadow-2xl animate-fadeIn z-[200] border-2 flex items-center gap-3 ${message.type === 'success' ? 'bg-brand-primary text-white border-white/20' : 'bg-red-600 text-white border-white/20'}`}>
          <i className="fas fa-check-circle text-xl"></i>
          <p className="font-black uppercase tracking-widest text-xs">{message.text}</p>
        </div>
      )}
    </div>
  );
};

export default Settings;

import React, { useState, useMemo, useEffect } from 'react';
import { Product, OrderItem, Order, StaffMember, UserRole, PendingOrder, SystemConfig, PaymentMethod, Customer } from '../types';
import { CATEGORIES } from '../constants';
import { translations } from '../translations';

interface POSProps {
  products: Product[];
  customers: Customer[]; 
  onCompleteOrder: (order: Order, pendingOrderId?: string) => void;
  onAddPendingOrder: (po: PendingOrder) => void;
  onUpdatePendingOrder: (po: PendingOrder) => void;
  onDeletePendingOrder: (id: string) => void;
  pendingOrders: PendingOrder[];
  currentUser: StaffMember;
  taxRate: number;
  globalTaxEnabled: boolean;
  config: SystemConfig;
}

const DefaultLogoSVG = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-12 h-12 fill-brand-primary"}>
    <path d="M45,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M55,35 c0,0,5-10,0-15 c-5,5,0,15,0,15 M35,40 h30 v15 c0,10-10,15-15,15 s-15-5-15-15 V40 z M65,45 h5 c5,0,5,10,0,10 h-5 M25,70 c0,0,10,20,50,0 c-20,10-50,0-50,0" />
  </svg>
);

const POS: React.FC<POSProps> = ({ 
  products, customers, onCompleteOrder, onAddPendingOrder, onUpdatePendingOrder, onDeletePendingOrder, 
  pendingOrders, currentUser, taxRate, globalTaxEnabled, config 
}) => {
  const t = translations[config.language];
  const [activeCategory, setActiveCategory] = useState('All');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [search, setSearch] = useState('');
  const [customerSearch, setCustomerSearch] = useState('');
  const [showCheckout, setShowCheckout] = useState(false);
  const [showReceipt, setShowReceipt] = useState(false);
  const [paymentStep, setPaymentStep] = useState<'Category' | 'Method'>('Category');
  const [paymentType, setPaymentType] = useState<'CashMobile' | 'Credit' | null>(null);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Cash');
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [manualCustomerName, setManualCustomerName] = useState('');
  const [activePendingId, setActivePendingId] = useState<string | null>(null);
  const [applyTax, setApplyTax] = useState(globalTaxEnabled);

  // New state for right sidebar tabs
  const [rightTab, setRightTab] = useState<'CART' | 'OPEN'>('CART');

  const filteredCustomers = useMemo(() => {
    if (!customerSearch) return [];
    return customers.filter(c => 
      c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
      c.phone.includes(customerSearch)
    ).slice(0, 5);
  }, [customers, customerSearch]);

  useEffect(() => {
    if (showReceipt && config.autoPrintReceipts) {
      const timer = setTimeout(() => {
        window.print();
      }, 700);
      return () => clearTimeout(timer);
    }
  }, [showReceipt, config.autoPrintReceipts]);

  useEffect(() => {
    if (cart.length === 0) {
      setApplyTax(globalTaxEnabled);
      setSelectedCustomer(null);
      setManualCustomerName('');
      setCustomerSearch('');
      setPaymentStep('Category');
      setPaymentType(null);
      setActivePendingId(null);
    }
  }, [globalTaxEnabled, cart.length]);

  const canProcessPayment = [UserRole.ADMIN, UserRole.MANAGER, UserRole.CASHIER].includes(currentUser.role);
  const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const taxAmount = applyTax ? (subtotal * (taxRate / 100)) : 0;
  const total = subtotal + taxAmount;

  const filteredProducts = useMemo(() => 
    products.filter(p => (activeCategory === 'All' || p.category === activeCategory) && p.name.toLowerCase().includes(search.toLowerCase())),
    [activeCategory, search, products]
  );

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return alert(config.language === 'Somali' ? "Waa ka dhammaatay!" : "Out of stock!");
    setCart(prev => {
      const existing = prev.find(item => item.productId === product.id);
      if (existing) {
        if (existing.quantity >= product.stock) return (alert("Stock limit!"), prev);
        return prev.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId: product.id, name: product.name, price: product.price, quantity: 1 }];
    });
    setRightTab('CART'); // Switch to cart tab when adding items
  };

  const handleSelectCategory = (category: 'CashMobile' | 'Credit') => {
    setPaymentType(category);
    if (category === 'Credit') setPaymentMethod('Credit');
    setPaymentStep('Method');
  };

  const handleCompleteSale = () => {
    const finalCustomerName = selectedCustomer ? selectedCustomer.name : manualCustomerName;

    if (paymentMethod === 'Credit' && !finalCustomerName) {
      alert(config.language === 'Somali' ? "Fadlan dooro macmiil ama qor magaca si loogu diwaangeliyo Amaahda." : "Please select a customer or write name for credit registration.");
      return;
    }

    onCompleteOrder({
      id: `ORD-${Date.now()}`,
      items: [...cart], 
      subtotal, 
      tax: taxAmount, 
      total, 
      discount: 0, 
      paymentMethod, 
      timestamp: new Date(), 
      staffId: currentUser.id,
      customerName: finalCustomerName || undefined,
      customerId: selectedCustomer?.id
    }, activePendingId || undefined);

    setShowCheckout(false);
    setShowReceipt(true);
  };

  const handleCloseReceipt = () => {
    setShowReceipt(false);
    setCart([]); 
    setActivePendingId(null); 
    setSelectedCustomer(null);
    setManualCustomerName('');
    setCustomerSearch('');
    setPaymentStep('Category');
    setPaymentType(null);
  };

  const handleOpenOrder = (po: PendingOrder) => {
    setCart(po.items);
    setActivePendingId(po.id);
    setApplyTax(po.tax > 0);
    setRightTab('CART'); // Switch back to cart view once loaded
  };

  const handleUpdateCurrentOrder = () => {
    if (!activePendingId) return;
    const updated: PendingOrder = {
      id: activePendingId,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };
    onUpdatePendingOrder(updated);
    setCart([]);
    setActivePendingId(null);
    alert(config.language === 'Somali' ? "Dalabka waa la cusboonaysiiyay!" : "Order updated!");
  };

  const handleSendNewOrder = () => {
    const po: PendingOrder = {
      id: `PEND-${Date.now()}`,
      items: [...cart],
      subtotal,
      tax: taxAmount,
      total,
      waiterId: currentUser.id,
      waiterName: currentUser.name,
      timestamp: new Date()
    };
    onAddPendingOrder(po);
    setCart([]);
    alert(config.language === 'Somali' ? "Dalabka waa la diray!" : "Order sent!");
  };

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {/* Product Grid Area (Main) */}
      <div className="flex-1 flex flex-col p-6 gap-6 overflow-hidden no-print">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div className="relative w-72">
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" placeholder={t.search_product} 
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-brand-secondary font-bold"
              value={search} onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar max-w-md">
            {CATEGORIES.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap ${activeCategory === cat ? 'bg-brand-secondary text-white shadow-md' : 'bg-gray-100 text-gray-600'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredProducts.map(product => (
            <button key={product.id} onClick={() => addToCart(product)} disabled={product.stock <= 0} className="bg-white p-3 rounded-2xl border border-gray-100 hover:shadow-xl transition-all flex flex-col text-left group">
              <img src={product.image} className="w-full h-28 object-cover rounded-xl mb-3 group-hover:scale-105 transition-transform" />
              <h4 className="font-bold text-gray-800 text-sm truncate">{product.name}</h4>
              <div className="mt-auto flex justify-between items-center pt-2">
                <span className="text-brand-secondary font-black text-sm">{config.currencySymbol}{product.price.toFixed(2)}</span>
                <span className="text-[10px] text-gray-400 font-bold">Qty: {product.stock}</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Unified Right Sidebar */}
      <div className="w-96 bg-white border-l border-gray-100 flex flex-col shadow-2xl no-print">
        {/* Tab Headers */}
        <div className="p-4 border-b border-gray-100 flex bg-gray-50/50">
          <button 
            onClick={() => setRightTab('CART')}
            className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${rightTab === 'CART' ? 'bg-brand-primary text-white shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <i className="fas fa-shopping-cart"></i> {config.language === 'Somali' ? 'Dambiisha' : 'Cart'}
            {cart.length > 0 && <span className="w-4 h-4 bg-brand-secondary text-white rounded-full flex items-center justify-center text-[8px]">{cart.length}</span>}
          </button>
          <button 
            onClick={() => setRightTab('OPEN')}
            className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${rightTab === 'OPEN' ? 'bg-brand-primary text-white shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <i className="fas fa-clock"></i> {config.language === 'Somali' ? 'Furan' : 'Open'}
            {pendingOrders.length > 0 && <span className="w-4 h-4 bg-brand-secondary text-white rounded-full flex items-center justify-center text-[8px]">{pendingOrders.length}</span>}
          </button>
        </div>

        {/* Tab Content */}
        <div className="flex-1 overflow-y-auto p-4">
          {rightTab === 'CART' ? (
            <div className="space-y-3">
               <div className="flex justify-between items-end mb-4">
                  <div>
                    <h3 className="text-lg font-black text-brand-primary uppercase tracking-tight">
                      {activePendingId ? (config.language === 'Somali' ? 'Dalabka #' + activePendingId.slice(-4) : 'Order #' + activePendingId.slice(-4)) : (config.language === 'Somali' ? 'Dalab Cusub' : 'New Order')}
                    </h3>
                  </div>
                  <button onClick={() => { setCart([]); setActivePendingId(null); }} className="text-[10px] font-black text-red-400 uppercase tracking-widest hover:text-red-600 transition-all"><i className="fas fa-trash-alt mr-1"></i> Clear</button>
               </div>

               {cart.map(item => (
                <div key={item.productId} className="flex items-center gap-3 bg-gray-50 p-3 rounded-2xl border border-transparent hover:border-brand-secondary/20 transition-all animate-fadeIn">
                  <div className="flex-1"><h4 className="font-bold text-gray-800 text-sm truncate">{item.name}</h4><p className="text-xs text-brand-secondary font-black">{config.currencySymbol}{(item.price * item.quantity).toFixed(2)}</p></div>
                  <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                     <button onClick={() => {setCart(prev => prev.map(i => i.productId === item.productId ? {...i, quantity: Math.max(0, i.quantity - 1)} : i).filter(i => i.quantity > 0))}} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">-</button>
                     <span className="text-xs font-black w-4 text-center">{item.quantity}</span>
                     <button onClick={() => addToCart(products.find(p => p.id === item.productId)!)} className="w-6 h-6 flex items-center justify-center text-brand-secondary font-black">+</button>
                  </div>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="py-20 flex flex-col items-center justify-center text-gray-200 opacity-50 text-center">
                  <i className="fas fa-shopping-basket text-6xl mb-4"></i>
                  <p className="text-sm font-black uppercase tracking-widest">{config.language === 'Somali' ? 'Dambiishu waa maran tahay' : 'Cart is empty'}</p>
                </div>
              )}
            </div>
          ) : (
            <div className="space-y-3">
              <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">{t.pending_orders}</h4>
              {pendingOrders.map(po => (
                <div 
                  key={po.id} 
                  className={`group relative p-4 rounded-2xl border transition-all cursor-pointer ${activePendingId === po.id ? 'bg-brand-primary border-brand-primary text-white shadow-lg' : 'bg-white border-gray-100 hover:border-brand-secondary'}`}
                  onClick={() => handleOpenOrder(po)}
                >
                  <div className="flex justify-between items-start mb-1 text-[10px] font-bold">
                    <span className="opacity-60">#{po.id.slice(-4)}</span>
                    <span>{new Date(po.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                  </div>
                  <p className="font-bold truncate text-sm">{po.waiterName}</p>
                  <div className="flex justify-between items-center mt-2">
                    <span className="text-xs">{po.items.length} items</span>
                    <span className={`font-black ${activePendingId === po.id ? 'text-brand-secondary' : 'text-brand-primary'}`}>{config.currencySymbol}{po.total.toFixed(2)}</span>
                  </div>
                  <button 
                    onClick={(e) => { e.stopPropagation(); onDeletePendingOrder(po.id); }}
                    className="absolute -top-2 -right-2 w-8 h-8 bg-white border border-red-100 text-red-500 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center hover:bg-red-500 hover:text-white"
                  >
