              <div className="py-2 space-y-1">
                 <div className="flex font-black border-b border-black pb-1 mb-1">
                   <span className="flex-1">{config.language === 'Somali' ? 'Alaabta' : 'Item'}</span><span className="w-6 text-center">Qty</span><span className="w-12 text-right">Amt</span>
