                <p className="text-[7px] font-bold text-gray-600 mb-1 uppercase tracking-widest">{config.language === 'Somali' ? 'Xisaabaadka' : 'Payment Accounts'}</p>
                <p className="text-[9px] font-black">{config.accountNumbers}</p>
