            <div className="mt-8 flex flex-col gap-3 no-print">
              <button onClick={() => window.print()} className="w-full py-4 bg-brand-primary text-white rounded-2xl font-black text-sm uppercase shadow-lg"><i className="fas fa-print mr-2"></i> {t.print_receipt}</button>
              <button onClick={handleCloseReceipt} className="w-full py-3 bg-gray-100 text-gray-500 rounded-xl font-bold text-xs uppercase">{config.language === 'Somali' ? 'Xir (Done)' : 'Close'}</button>
            </div>
          </div>
        </div>
      )}

      {showCheckout && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 no-print">
           <div className="bg-white w-full max-w-xl rounded-[2.5rem] p-8 md:p-12 animate-scaleIn shadow-2xl relative max-h-[90vh] overflow-y-auto no-scrollbar">
              <div className="flex justify-between items-start mb-8">
                 <div className="text-left">
                    <h3 className="text-3xl font-black text-brand-primary uppercase tracking-tight">
                      {paymentStep === 'Category' ? t.complete_order : t.confirm_payment}
                    </h3>
                    <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">{t.total}: {config.currencySymbol}{total.toFixed(2)}</p>
                 </div>
                 <button onClick={() => setShowCheckout(false)} className="w-10 h-10 bg-gray-100 rounded-xl flex items-center justify-center text-gray-400 hover:text-red-500 transition-all">
                    <i className="fas fa-times"></i>
                 </button>
              </div>

              {paymentStep === 'Category' && (
                <div className="grid grid-cols-1 gap-6 animate-fadeIn">
                  <button onClick={() => handleSelectCategory('CashMobile')} className="flex items-center gap-6 p-8 bg-gray-50 rounded-[2rem] border-4 border-transparent hover:border-brand-secondary hover:bg-white transition-all group text-left">
                    <div className="w-20 h-20 bg-green-500 rounded-3xl flex items-center justify-center text-white text-3xl shadow-xl group-hover:scale-110 transition-transform shrink-0"><i className="fas fa-money-bill-transfer"></i></div>
                    <div className="flex-1"><h4 className="text-2xl font-black text-gray-800">{config.language === 'Somali' ? 'Cadaan / Mobile' : 'Cash / Mobile'}</h4><p className="text-sm text-gray-400 font-bold uppercase tracking-widest">EVC, Dahab, Merchant Code</p></div>
                    <i className="fas fa-chevron-right text-gray-300"></i>
                  </button>
                  <button onClick={() => handleSelectCategory('Credit')} className="flex items-center gap-6 p-8 bg-gray-50 rounded-[2rem] border-4 border-transparent hover:border-red-500 hover:bg-white transition-all group text-left">
                    <div className="w-20 h-20 bg-red-500 rounded-3xl flex items-center justify-center text-white text-3xl shadow-xl group-hover:scale-110 transition-transform shrink-0"><i className="fas fa-book"></i></div>
                    <div className="flex-1"><h4 className="text-2xl font-black text-gray-800">{config.language === 'Somali' ? 'Amaah (Credit)' : 'Credit'}</h4><p className="text-sm text-gray-400 font-bold uppercase tracking-widest">{config.language === 'Somali' ? 'Deyn / Ku qor Buugga' : 'Debt / Register on Book'}</p></div>
                    <i className="fas fa-chevron-right text-gray-300"></i>
                  </button>
                </div>
              )}

              {paymentStep === 'Method' && (
                <div className="animate-fadeIn space-y-8">
                  <button onClick={() => setPaymentStep('Category')} className="text-xs font-black text-gray-400 uppercase tracking-widest hover:text-brand-primary flex items-center gap-2"><i className="fas fa-arrow-left"></i> {config.language === 'Somali' ? 'Ka noqo' : 'Go back'}</button>
                  {paymentType === 'CashMobile' ? (
                    <div className="grid grid-cols-2 gap-4">
                        {[
                          { id: 'Cash', icon: 'fa-money-bill-wave', label: 'Cash', color: 'bg-green-500' },
                          { id: 'EVC Plus', icon: 'fa-mobile-screen-button', label: 'EVC Plus', color: 'bg-blue-600' },
                          { id: 'E-Dahab', icon: 'fa-wallet', label: 'E-Dahab', color: 'bg-orange-500' },
                          { id: 'Merchant', icon: 'fa-building-columns', label: 'Merchant', color: 'bg-purple-600' }
                        ].map(m => (
                          <button key={m.id} onClick={() => setPaymentMethod(m.id as PaymentMethod)} className={`flex flex-col items-center gap-3 p-5 rounded-3xl border-2 transition-all group ${paymentMethod === m.id ? 'border-brand-secondary bg-brand-secondary/5 text-brand-primary scale-105 shadow-md' : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'}`}>
                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-lg ${m.color}`}><i className={`fas ${m.icon} text-lg`}></i></div>
                            <span className="text-[10px] font-black uppercase tracking-widest">{m.label}</span>
                          </button>
                        ))}
                    </div>
                  ) : (
                    <div className="space-y-6">
                      <div className="bg-red-50 p-6 rounded-3xl border border-red-100 text-center space-y-4">
                        <i className="fas fa-user-check text-4xl text-red-500"></i>
                        <h4 className="text-xl font-black text-red-600">{config.language === 'Somali' ? 'Raadi Macmiilka Buugga leh' : 'Search Credit Customer'}</h4>
                      </div>
                      <div className="relative">
                        <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
                        <input 
                          type="text" 
                          value={customerSearch} 
                          onChange={(e) => {
                            setCustomerSearch(e.target.value);
                            if (selectedCustomer) setSelectedCustomer(null);
                          }}
                          className="w-full pl-12 pr-4 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold" 
                          placeholder={config.language === 'Somali' ? 'Raadi Macmiil (Magac ama Tel)...' : 'Search Customer (Name or Tel)...'} 
                        />
                        {filteredCustomers.length > 0 && !selectedCustomer && (
                          <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden z-[110] animate-fadeIn">
                             {filteredCustomers.map(c => (
                               <button 
                                key={c.id} 
                                onClick={() => {
                                  setSelectedCustomer(c);
                                  setCustomerSearch(c.name);
                                }}
                                className="w-full text-left p-4 hover:bg-gray-50 flex justify-between items-center transition-colors border-b last:border-none border-gray-50"
                               >
                                 <div>
                                    <p className="font-black text-gray-800 text-sm">{c.name}</p>
                                    <p className="text-[10px] text-gray-400 font-bold">{c.phone}</p>
                                 </div>
                                 <div className="text-right">
                                    <p className="text-xs font-black text-red-500">{config.currencySymbol}{c.totalDebt.toFixed(2)}</p>
                                    <p className="text-[9px] text-gray-400 uppercase font-black">Limit: {config.currencySymbol}{c.creditLimit.toFixed(0)}</p>
                                 </div>
                               </button>
                             ))}
                          </div>
                        )}
                      </div>
                    </div>
                  )}

                  <div className="space-y-2 text-left">
                     <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">
                        {paymentType === 'Credit' ? t.quick_add : t.customers}
                     </label>
                     <input 
                        type="text" 
                        value={selectedCustomer ? selectedCustomer.name : manualCustomerName} 
                        onChange={(e) => {
                          if (selectedCustomer) setSelectedCustomer(null);
                          setManualCustomerName(e.target.value);
                        }} 
                        className={`w-full px-6 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-brand-secondary font-bold text-center text-xl ${selectedCustomer ? 'text-brand-primary bg-brand-secondary/5 border-2 border-brand-secondary ring-2 ring-brand-secondary ring-offset-2' : ''}`} 
                        placeholder={config.language === 'Somali' ? 'Magaca macmiilka...' : 'Customer name...'} 
                        readOnly={!!selectedCustomer}
                     />
                  </div>

                  <button onClick={handleCompleteSale} className="w-full bg-brand-primary text-white py-6 rounded-3xl font-black text-2xl shadow-2xl active:scale-95 transition-all">{config.language === 'Somali' ? 'Xaqiiji & Xir Dalabka' : 'Confirm & Close Order'}</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import POS from './components/POS';
import Inventory from './components/Inventory';
import Staff from './components/Staff';
import Finance from './components/Finance';
import Settings from './components/Settings';
import Login from './components/Login';
import Reports from './components/Reports';
import CustomerBook from './components/CustomerBook';
import { View, UserRole, Product, StaffMember, Order, Expense, PendingOrder, SystemConfig, Customer, Language } from './types';
import { INITIAL_PRODUCTS, INITIAL_STAFF, MOCK_EXPENSES } from './constants';
import { translations } from './translations';
import { db } from './db';

const DEFAULT_CONFIG: SystemConfig = {
  name: 'Koob Coffee',
  description: 'The Best Coffee & Snacks Experience in Mogadishu.',
  primaryColor: '#3d2b1f',
  secondaryColor: '#c6a07d',
  logoUrl: '', 
  loginBgUrl: 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&q=80',
  appBgUrl: '',
  currencySymbol: '$',
  address: 'Mogadishu, Somalia',
  phone: '+252 61 XXX XXXX',
  accountNumbers: 'EVC: 61XXXX, Dahab: 12345',
  enabledModules: ['DASHBOARD', 'POS', 'INVENTORY', 'STAFF', 'REPORTS', 'FINANCE', 'SETTINGS', 'CUSTOMER_BOOK'],
  version: '3.0.0-DB', 
  autoUpdate: true,
  autoPrintReceipts: false,
  language: 'Somali'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<StaffMember | null>(null);
  const [dbReady, setDbReady] = useState(false);

  const [systemConfig, setSystemConfig] = useState<SystemConfig>(DEFAULT_CONFIG);
  const [products, setProducts] = useState<Product[]>([]);
  const [staff, setStaff] = useState<StaffMember[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [taxRate, setTaxRate] = useState<number>(5);
  const [isTaxEnabled, setIsTaxEnabled] = useState<boolean>(true);

  // Global Keydown Listener for Ctrl+P
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'p') {
        // Browser handles print natively, but we ensure we are in a printable state
        console.log("Print requested via shortcut...");
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Initialize Database on Mount
  useEffect(() => {
    const initDB = async () => {
      try {
        const savedConfig = await db.getAll('config');
        if (savedConfig.length > 0) {
          setSystemConfig({ ...DEFAULT_CONFIG, ...savedConfig[0] });
        } else {
          await db.put('config', { ...DEFAULT_CONFIG, id: 'main' });
        }

        const loadedProducts = await db.getAll('products');
        if (loadedProducts.length === 0) {
          for (const p of INITIAL_PRODUCTS) await db.put('products', p);
          setProducts(INITIAL_PRODUCTS);
        } else {
          setProducts(loadedProducts);
        }

        const loadedStaff = await db.getAll('staff');
        if (loadedStaff.length === 0) {
          for (const s of INITIAL_STAFF) await db.put('staff', s);
          setStaff(INITIAL_STAFF);
        } else {
          setStaff(loadedStaff);
        }

        const loadedCustomers = await db.getAll('customers');
        setCustomers(loadedCustomers);

        const loadedOrders = await db.getAll('orders');
        setOrders(loadedOrders.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));

        const loadedExpenses = await db.getAll('expenses');
        setExpenses(loadedExpenses);

        setDbReady(true);
      } catch (err) {
        console.error("Database initialization failed:", err);
      }
    };

    initDB();
  }, []);

  const t = translations[systemConfig.language];

  useEffect(() => {
    document.documentElement.style.setProperty('--brand-primary', systemConfig.primaryColor);
    document.documentElement.style.setProperty('--brand-secondary', systemConfig.secondaryColor);
    if (dbReady) db.put('config', { ...systemConfig, id: 'main' });
  }, [systemConfig, dbReady]);

  const handleLogin = (matchedStaff: StaffMember) => {
    setCurrentUser(matchedStaff);
    if (matchedStaff.role === UserRole.WAITER || matchedStaff.role === UserRole.CASHIER) {
      setCurrentView('POS');
    } else {
      setCurrentView('DASHBOARD');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('DASHBOARD');
  };

  const handleCompleteOrder = async (order: Order, pendingOrderId?: string) => {
    await db.put('orders', order);
    setOrders(prev => [order, ...prev]);

    const updatedProducts = products.map(p => {
      const itemInOrder = order.items.find(oi => oi.productId === p.id);
      if (itemInOrder) {
        const updated = { ...p, stock: p.stock - itemInOrder.quantity };
        db.put('products', updated);
        return updated;
      }
      return p;
    });
    setProducts(updatedProducts);

    if (order.paymentMethod === 'Credit' && order.customerName) {
      const existing = order.customerId 
          ? customers.find(c => c.id === order.customerId)
          : customers.find(c => c.name.toLowerCase() === order.customerName?.toLowerCase());

      if (existing) {
        const updated = { ...existing, totalDebt: existing.totalDebt + order.total, lastTransaction: new Date() };
        await db.put('customers', updated);
        setCustomers(prev => prev.map(c => c.id === existing.id ? updated : c));
      } else {
        const newCust: Customer = {
          id: `C-${Date.now()}`,
          name: order.customerName!,
          phone: 'N/A',
          gender: 'Male',
          creditLimit: 500,
          registrationDate: new Date(),
          expiryDate: new Date(new Date().setMonth(new Date().getMonth() + 1)),
          totalDebt: order.total,
          lastTransaction: new Date()
        };
        await db.put('customers', newCust);
        setCustomers(prev => [...prev, newCust]);
      }
    }

    if (pendingOrderId) {
      setPendingOrders(prev => prev.filter(po => po.id !== pendingOrderId));
    }
  };

  const renderView = () => {
    if (!currentUser || !dbReady) return (
      <div className="h-full flex items-center justify-center p-20">
        <div className="flex flex-col items-center gap-4">
          <div className="w-16 h-16 border-4 border-brand-secondary border-t-transparent rounded-full animate-spin"></div>
          <p className="font-black text-brand-primary uppercase tracking-widest text-xs">Database Loading...</p>
        </div>
      </div>
    );

    switch (currentView) {
      case 'DASHBOARD': return <Dashboard products={products} orders={orders} systemName={systemConfig.name} config={systemConfig} />;
      case 'POS': return (
        <POS 
          products={products} 
          customers={customers}
          onCompleteOrder={handleCompleteOrder} 
          onAddPendingOrder={(po) => setPendingOrders(prev => [po, ...prev])}
          onUpdatePendingOrder={(upd) => setPendingOrders(prev => prev.map(po => po.id === upd.id ? upd : po))}
          onDeletePendingOrder={(id) => setPendingOrders(prev => prev.filter(po => po.id !== id))}
          pendingOrders={pendingOrders}
          currentUser={currentUser}
          taxRate={taxRate}
          globalTaxEnabled={isTaxEnabled}
          config={systemConfig}
        />
      );
      case 'CUSTOMER_BOOK': 
        return (
          <CustomerBook 
            customers={customers} 
            orders={orders} 
            config={systemConfig} 
            onUpdateCustomer={async (c) => { await db.put('customers', c); setCustomers(prev => prev.map(x => x.id === c.id ? c : x)); }}
            onAddCustomer={async (c) => { await db.put('customers', c); setCustomers(prev => [...prev, c]); }}
            onDeleteCustomer={async (id) => { await db.delete('customers', id); setCustomers(prev => prev.filter(c => c.id !== id)); }}
            onClearDebt={async (id, amt) => {
              const customer = customers.find(c => c.id === id);
              if (customer) {
                const updated = { ...customer, totalDebt: Math.max(0, customer.totalDebt - amt), lastTransaction: new Date() };
                await db.put('customers', updated);
                setCustomers(prev => prev.map(c => c.id === id ? updated : c));
                const paymentOrder: Order = {
                  id: `PAY-${Date.now()}`,
                  items: [],
                  subtotal: 0,
                  tax: 0,
                  total: amt,
                  discount: 0,
                  paymentMethod: 'Cash',
                  timestamp: new Date(),
                  staffId: currentUser?.id || 'System',
                  customerName: customer.name,
                  customerId: customer.id
                };
                await db.put('orders', paymentOrder);
                setOrders(prev => [paymentOrder, ...prev]);
              }
            }}
            onAddManualDebt={async (id, amt) => {
               const c = customers.find(x => x.id === id);
               if(c) {
                  const upd = {...c, totalDebt: c.totalDebt + amt};
                  await db.put('customers', upd);
                  setCustomers(prev => prev.map(x => x.id === id ? upd : x));
               }
            }}
          />
        );
      case 'INVENTORY': return (
        <Inventory 
          products={products} 
          onAddProduct={async (p) => { await db.put('products', p); setProducts(prev => [p, ...prev]); }} 
          onUpdateProduct={async (u) => { await db.put('products', u); setProducts(prev => prev.map(p => p.id === u.id ? u : p)); }}
          onDeleteProduct={async (id) => { if(confirm(t.reset_system + "?")) { await db.delete('products', id); setProducts(prev => prev.filter(p => p.id !== id)); } }}
          currentUser={currentUser}
          config={systemConfig}
        />
      );
      case 'STAFF': return (
        <Staff 
          staff={staff} 
          onAddStaff={async (s) => { await db.put('staff', s); setStaff(prev => [...prev, s]); }} 
          onUpdateStaff={async (u) => { await db.put('staff', u); setStaff(prev => prev.map(s => s.id === u.id ? u : s)); }} 
          onDeleteStaff={async (id) => { await db.delete('staff', id); setStaff(prev => prev.filter(s => s.id !== id)); }}
          currentUser={currentUser} 
          config={systemConfig}
        />
      );
      case 'FINANCE': return (
        <Finance 
          orders={orders} 
          expenses={expenses} 
          onAddExpense={async (e) => { await db.put('expenses', e); setExpenses(prev => [e, ...prev]); }} 
          config={systemConfig} 
        />
      );
      case 'SETTINGS': return (
        <Settings 
          taxRate={taxRate} 
          onUpdateTaxRate={setTaxRate}
          isTaxEnabled={isTaxEnabled}
          onToggleTax={setIsTaxEnabled}
          systemConfig={systemConfig}
          onUpdateConfig={setSystemConfig}
          onResetData={async () => { 
            await db.clearStore('products');
            await db.clearStore('orders');
            await db.clearStore('customers');
            await db.clearStore('staff');
            await db.clearStore('expenses');
            await db.clearStore('config');
            window.location.reload(); 
          }}
        />
      );
      case 'REPORTS': return <Reports orders={orders} products={products} staff={staff} config={systemConfig} />;
      default: return <Dashboard products={products} orders={orders} systemName={systemConfig.name} config={systemConfig} />;
    }
  };

  if (!currentUser) {
    return <Login staffMembers={staff} onLogin={handleLogin} config={systemConfig} />;
  }

  return (
    <div className="flex min-h-screen bg-gray-50 relative overflow-hidden">
      {systemConfig.appBgUrl && (
        <div className="absolute inset-0 z-0 opacity-5 pointer-events-none">
          <img src={systemConfig.appBgUrl} className="w-full h-full object-cover" alt="" />
        </div>
      )}

      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        userRole={currentUser.role} 
        currentUser={currentUser} 
        config={systemConfig} 
        onLanguageChange={(lang) => setSystemConfig(prev => ({ ...prev, language: lang }))}
      />

      <main className="flex-1 overflow-y-auto relative z-10 no-scrollbar">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 py-4 flex items-center justify-between no-print">
          <h2 className="text-lg font-bold text-gray-700 uppercase tracking-widest text-xs">
            {t[currentView.toLowerCase()] || currentView.replace('_', ' ')}
          </h2>
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2 px-3 py-1 bg-green-50 rounded-full border border-green-100">
               <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
               <span className="text-[9px] font-black text-green-600 uppercase tracking-widest">Database Ready</span>
            </div>

            <button onClick={handleLogout} className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2">
              <i className="fas fa-sign-out-alt"></i> {t.logout}
            </button>
            <div className="h-8 w-[1px] bg-gray-200"></div>
            <div className="flex items-center gap-2">
               <div className="text-right hidden sm:block">
                  <p className="text-sm font-bold text-gray-800">{currentUser.name}</p>
                  <p className="text-[10px] text-brand-secondary uppercase font-bold tracking-widest">{currentUser.role}</p>
               </div>
               <div className="w-10 h-10 bg-brand-primary rounded-xl flex items-center justify-center text-white shadow-lg border border-white/20">
                  <i className="fas fa-user-check"></i>
               </div>
            </div>
          </div>
        </header>
        <div className="animate-fadeIn">
          {renderView()}
        </div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        :root {
          --brand-primary: ${systemConfig.primaryColor};
          --brand-secondary: ${systemConfig.secondaryColor};
        }
        .bg-brand-primary { background-color: var(--brand-primary); }
        .bg-brand-secondary { background-color: var(--brand-secondary); }
        .text-brand-primary { color: var(--brand-primary); }
        .text-brand-secondary { color: var(--brand-secondary); }
        .border-brand-primary { border-color: var(--brand-primary); }
        .border-brand-secondary { border-color: var(--brand-secondary); }
        .ring-brand-secondary:focus { --tw-ring-color: var(--brand-secondary); }

        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scaleIn { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
      `}} />
    </div>
  );
};

export default App;
